}

function getObjectIdFromInput(input: any): string | null {
  if (!input) return null
  if (typeof input === 'string') return input
  if (input.UnresolvedObject?.objectId) {
    return input.UnresolvedObject.objectId
  }
  if (input.Object?.ImmOrOwnedObject?.objectId) {
    return input.Object.ImmOrOwnedObject.objectId
  }
  if (input.Object?.SharedObject?.objectId) {
    return input.Object.SharedObject.objectId
  }
  return null
}

function normalizeAddress(addr: string): string {
  let clean = addr.toLowerCase()
  if (clean.startsWith('0x')) clean = clean.slice(2)
  return '0x' + clean.padStart(64, '0')
}

const PASS_MINT_FNS = new Set(['mint_pass', 'mint_pass_with_extra_credentials'])

type PassTicketFields = {
  source: number
  nullifiers: number[][]
  commitment: number[]
  expiresAt: bigint
  bffSig: number[]
}

function parsePassTicketFromArgs(
  getPureBytes: (arg: any) => Uint8Array | null,
  args: any[],
  ticketBase: number
): PassTicketFields | null {
  const sourceBytes = getPureBytes(args[ticketBase])
  const nullifierBytes = getPureBytes(args[ticketBase + 1])
  const commitmentBytes = getPureBytes(args[ticketBase + 2])
  const expiresAtBytes = getPureBytes(args[ticketBase + 3])
  const bffSigBytes = getPureBytes(args[ticketBase + 4])
  if (!sourceBytes || !nullifierBytes || !commitmentBytes || !expiresAtBytes || !bffSigBytes) {
    return null
  }
  return {
    source: bcs.u8().parse(sourceBytes),
    nullifiers: bcs.vector(bcs.vector(bcs.u8())).parse(nullifierBytes).map((n: number[]) => Array.from(n)),
    commitment: Array.from(bcs.vector(bcs.u8()).parse(commitmentBytes)),
    expiresAt: BigInt(bcs.u64().parse(expiresAtBytes)),
    bffSig: Array.from(bcs.vector(bcs.u8()).parse(bffSigBytes)),
  }
}

function extractPassTicketsFromMoveCall(
  getPureBytes: (arg: any) => Uint8Array | null,
  fn: string,
  args: any[]
): PassTicketFields[] | null {
  if (fn === 'update_pass_credential') {
    const ticket = parsePassTicketFromArgs(getPureBytes, args, 3)
    return ticket ? [ticket] : null
  }
  if (fn === 'mint_pass') {
    const ticket = parsePassTicketFromArgs(getPureBytes, args, 4)
    return ticket ? [ticket] : null
  }
  if (fn === 'mint_pass_with_extra_credentials') {
    const primary = parsePassTicketFromArgs(getPureBytes, args, 4)
    if (!primary) return null

    const extraSourcesBytes = getPureBytes(args[9])
    const extraNullifiersBytes = getPureBytes(args[10])
    const extraCommitmentsBytes = getPureBytes(args[11])
    const extraExpiresAtBytes = getPureBytes(args[12])
    const extraBffSigsBytes = getPureBytes(args[13])
    if (
      !extraSourcesBytes ||
      !extraNullifiersBytes ||
      !extraCommitmentsBytes ||
      !extraExpiresAtBytes ||
      !extraBffSigsBytes
    ) {
      return null
    }

    const extraSources = bcs.vector(bcs.u8()).parse(extraSourcesBytes)
    const extraNullifiers = bcs.vector(bcs.vector(bcs.vector(bcs.u8()))).parse(extraNullifiersBytes)
    const extraCommitments = bcs.vector(bcs.vector(bcs.u8())).parse(extraCommitmentsBytes)
    const extraExpiresAt = bcs.vector(bcs.u64()).parse(extraExpiresAtBytes)
    const extraBffSigs = bcs.vector(bcs.vector(bcs.u8())).parse(extraBffSigsBytes)

    const len = extraSources.length
    if (
      len !== extraNullifiers.length ||
      len !== extraCommitments.length ||
      len !== extraExpiresAt.length ||
      len !== extraBffSigs.length
    ) {
      return null
    }

    const tickets: PassTicketFields[] = [primary]
    for (let i = 0; i < len; i++) {
      tickets.push({
        source: extraSources[i],
        nullifiers: extraNullifiers[i].map((n: number[]) => Array.from(n)),
        commitment: Array.from(extraCommitments[i]),
        expiresAt: BigInt(extraExpiresAt[i]),
        bffSig: Array.from(extraBffSigs[i]),
      })
    }
    return tickets
  }
  return null
}

async function verifyPassTicketSignature(
  keypair: Ed25519Keypair,
  senderAddress: string,
  ticket: PassTicketFields
): Promise<{ ok: true } | { ok: false; status: number; error: string; message: string }> {
  const payloadBytes = TicketPayload.serialize({
    owner: senderAddress,
    source: ticket.source,
    nullifiers: ticket.nullifiers,
    commitment: ticket.commitment,
    expires_at: ticket.expiresAt,
  }).toBytes()

  const isValid = await keypair.getPublicKey().verify(payloadBytes, new Uint8Array(ticket.bffSig))
  if (!isValid) {
    return {
      ok: false,
      status: 400,
      error: 'invalid_ticket_signature',
      message: 'The ticket signature in the transaction is invalid or tampered',
    }
  }

  if (Date.now() > Number(ticket.expiresAt)) {
    return {
      ok: false,
      status: 400,
      error: 'ticket_expired',
      message: 'The ticket has expired',
    }
  }

  return { ok: true }
}

function parseOptionVectorU8(bytes: Uint8Array | null): { isSome: boolean; payload: Uint8Array | null } {
  if (!bytes || bytes.length === 0) return { isSome: false, payload: null }
  if (bytes[0] === 0) return { isSome: false, payload: null }
  if (bytes[0] === 1) {
    try {
      const parsed = bcs.vector(bcs.u8()).parse(bytes.subarray(1))
      return { isSome: true, payload: new Uint8Array(parsed) }
    } catch {
      return { isSome: true, payload: null }
    }
  }
  return { isSome: false, payload: null }
}

let cachedDynamicGas: bigint | null = null
let lastFetchedTime = 0
const CACHE_DURATION_MS = 60_000 // 1 minute

export function __resetDynamicGasCache(): void {
  cachedDynamicGas = null
  lastFetchedTime = 0
}

export async function calculateDynamicGasCompensation(
  suiClient: SuiClient,
  packageId: string,
  minAmount: bigint
): Promise<bigint> {
  const now = Date.now()
  if (cachedDynamicGas !== null && now - lastFetchedTime < CACHE_DURATION_MS) {
    return cachedDynamicGas > minAmount ? cachedDynamicGas : minAmount
  }

  try {
    const res = await suiClient.queryTransactionBlocks({
      filter: {
        MoveFunction: {
          package: packageId,
          module: 'survey_vault',
          function: 'claim',
        },
      },
      limit: 10,
      options: {
        showEffects: true,
      },
    })

    let maxGas = minAmount
    if (res?.data && res.data.length > 0) {
      for (const txBlock of res.data) {
        if (txBlock.effects?.status?.status === 'success' && txBlock.effects.gasUsed) {
          const computationCost = BigInt(txBlock.effects.gasUsed.computationCost || '0')
          const storageCost = BigInt(txBlock.effects.gasUsed.storageCost || '0')
          const storageRebate = BigInt(txBlock.effects.gasUsed.storageRebate || '0')
          const netGas = computationCost + storageCost - storageRebate
          if (netGas > maxGas) {
            maxGas = netGas
          }
        }
      }
    }
    cachedDynamicGas = maxGas
    lastFetchedTime = now
    return maxGas
  } catch (error) {
    console.error('[GasStation] Failed to query dynamic gas compensation on-chain:', error)
    return minAmount
  }
}

export function registerGasRoutes(
  app: FastifyInstance,
  deps: { suiClient: SuiClient; packageId: string; coinQueue?: SponsorCoinQueue }
): void {
  const coinQueue = deps.coinQueue ?? InMemoryCoinLockStore.fromGasConfig(getGasConfig())
  app.get('/api/gas/health', async (_req, reply): Promise<GasHealthResponse> => {
    try {
      const gasConfig = getGasConfig()
      const privKeyHex = process.env.SURVEY_PASS_ISSUER_PRIV
      if (!privKeyHex) {
        return { available: false, reason: 'no_key' }
      }
      const privKeyClean = privKeyHex.startsWith('0x') ? privKeyHex.slice(2) : privKeyHex
      const privateKeyBytes = new Uint8Array(Buffer.from(privKeyClean, 'hex'))
      const keypair = Ed25519Keypair.fromSecretKey(privateKeyBytes.slice(0, 32))
      const sponsorAddress = keypair.getPublicKey().toSuiAddress()

      const balance = await deps.suiClient.getBalance({
        owner: sponsorAddress,
        coinType: '0x2::sui::SUI',
      })

      const minAmount = gasConfig.minGasCompensationAmount
      const dynamicAmount = await calculateDynamicGasCompensation(
        deps.suiClient,
        deps.packageId,
        minAmount
      )

      const gasStationMode = getGasStationMode()
      const doHealth =
        gasStationMode === 'do' ? await fetchGasStationHealth() : null
      const unlockedCoinCount =
        typeof doHealth?.unlockedCoinCount === 'number'
          ? doHealth.unlockedCoinCount
          : undefined
      const lockedCoinCount =
        typeof doHealth?.lockedCoinCount === 'number' ? doHealth.lockedCoinCount : undefined
      const queueDepth =
        typeof doHealth?.queueDepth === 'number' ? doHealth.queueDepth : undefined

      if (BigInt(balance.totalBalance) < healthMinBalanceMist(gasConfig)) {
        return {
          available: false,
          reason: 'low_balance',
          sponsorAddress,
          gasCompensationAmount: dynamicAmount.toString(),
          gasStationMode,
          unlockedCoinCount,
          lockedCoinCount,
          queueDepth,
        }
      }
      return {
        available: doHealth?.available === false ? false : true,
        sponsorAddress,
        gasCompensationAmount: dynamicAmount.toString(),
        gasStationMode,
        unlockedCoinCount,
        lockedCoinCount,
        queueDepth,
        reason: doHealth?.available === false ? 'unknown' : undefined,
      }
    } catch (err: any) {
      reply.log.warn({ err: err?.message }, '[GasStation] health probe failed')
      return { available: false, reason: 'unknown' }
    }
  })

  app.get(
    '/api/gas/sponsor-count',
    async (req: FastifyRequest<{ Querystring: { address?: string } }>, reply: FastifyReply) => {
      const { address } = req.query
      if (!address) {
        return reply.status(400).send({ error: 'Missing address' })
      }

      try {
        const privKeyHex = process.env.SURVEY_PASS_ISSUER_PRIV
        if (!privKeyHex) {
          throw new Error('SURVEY_PASS_ISSUER_PRIV is not set')
        }

        const privKeyClean = privKeyHex.startsWith('0x') ? privKeyHex.slice(2) : privKeyHex
        const privateKeyBytes = new Uint8Array(Buffer.from(privKeyClean, 'hex'))
        const keypairBytes = privateKeyBytes.slice(0, 32)
        const keypair = Ed25519Keypair.fromSecretKey(keypairBytes)
        const sponsorAddress = keypair.getPublicKey().toSuiAddress()

        const scope = resolveCountScope()
        const count = await getSponsorCount({
          suiClient: deps.suiClient,
          senderAddress: address,
          sponsorAddress,
          packageId: scope.packageId,
          sinceMs: scope.sinceMs,
        })

        const maxLimit = scope.passMax
        return {
          count,
          maxLimit,
          remaining: Math.max(0, maxLimit - count),
        }
      } catch (err: any) {
        req.log.error(err)
        return reply.status(500).send({ error: 'failed_to_get_count', message: err.message })
      }
    }
  )

  const sponsorRateLimit = getGasConfig()
  app.post(
    '/api/gas/sponsor',
    {
      config: {
        rateLimit: {
          max: sponsorRateLimit.gasSponsorRateLimitMax,
          timeWindow: sponsorRateLimit.gasSponsorRateLimitWindowMs,
        },
      },
    },
    async (req: FastifyRequest<{ Body: GasSponsorRequestBody }>, reply: FastifyReply) => {
      const gasConfig = getGasConfig()
      const { txBytes, senderAddress } = req.body
      if (!txBytes || !senderAddress) {
        return reply.status(400).send({ error: 'Missing txBytes or senderAddress' })
      }

      const walletLimit = await getWalletSponsorRateLimitStore().checkAndIncrement(
        senderAddress,
        gasConfig.gasSponsorRateLimitMaxPerWallet,
        gasConfig.gasSponsorRateLimitWalletWindowMs
      )
      if (!walletLimit.allowed) {
        return reply.status(429).send({
          error: 'wallet_rate_limit_exceeded',
          message: `Wallet sponsor rate limit exceeded; retry in ${Math.ceil((walletLimit.retryAfterMs ?? 0) / 1000)} seconds`,
        })
      }

      try {
        const privKeyHex = process.env.SURVEY_PASS_ISSUER_PRIV
        if (!privKeyHex) {
          throw new Error('SURVEY_PASS_ISSUER_PRIV is not set')
        }

        const privKeyClean = privKeyHex.startsWith('0x') ? privKeyHex.slice(2) : privKeyHex
        const privateKeyBytes = new Uint8Array(Buffer.from(privKeyClean, 'hex'))
        const keypairBytes = privateKeyBytes.slice(0, 32)
        const keypair = Ed25519Keypair.fromSecretKey(keypairBytes)
        const sponsorAddress = keypair.getPublicKey().toSuiAddress()

        // 1. Reconstruct transaction from transaction kind
        const tx = Transaction.fromKind(Buffer.from(txBytes, 'base64'))

        // Audit PTB commands: only survey_vault::claim and survey_pass mint/update allowed
        const commands = tx.getData().commands
        if (!commands || commands.length === 0) {
          return reply.status(400).send({
            error: 'invalid_transaction_commands',
            message: 'No commands in transaction',
          })
        }

        // Helpers to extract pure inputs
        const getPureBytes = (arg: any): Uint8Array | null => {
          if (arg && arg.$kind === 'Input') {
            const input = tx.getData().inputs[arg.Input]
            if (input && input.$kind === 'Pure') {
              const pureVal = input.Pure
              if (pureVal) {
                if (pureVal.bytes) return new Uint8Array(Buffer.from(pureVal.bytes, 'base64'))
                if (typeof pureVal === 'string') return new Uint8Array(Buffer.from(pureVal, 'base64'))
                if (Array.isArray(pureVal)) return new Uint8Array(pureVal)
              }
            }
          }
          return null
        }

        let isPassSponsor = false
        let isPlatformSponsor = false
        let vaultId: string | null = null
        let passId: string | null = null
        let claimGasCompensationAmount: bigint | null = null
        let claimStorageCompensationAmount: bigint | null = null
        let claimHasBlob = false

        for (const command of commands) {
          if (command.$kind !== 'MoveCall') {
            return reply.status(400).send({
              error: 'invalid_transaction_commands',
              message: 'Only MoveCall commands are allowed',
            })
          }
          const call = command.MoveCall
          if (!call) {
            return reply.status(400).send({
              error: 'invalid_transaction_commands',
              message: 'Missing MoveCall data',
            })
          }

          const expectedPackage = process.env.SUI_PACKAGE_ID
          if (expectedPackage) {
            if (normalizeAddress(call.package) !== normalizeAddress(expectedPackage)) {
              return reply.status(400).send({
                error: 'invalid_transaction_commands',
                message: 'Invalid package ID',
              })
            }
          }

          if (call.module === 'survey_pass') {
            if (
              call.function !== 'mint_pass' &&
              call.function !== 'mint_pass_with_extra_credentials' &&
              call.function !== 'update_pass_credential'
            ) {
              return reply.status(400).send({
                error: 'invalid_transaction_commands',
                message:
                  'Only mint_pass, mint_pass_with_extra_credentials, or update_pass_credential allowed in survey_pass module',
              })
            }
            isPassSponsor = true
          } else if (call.module === 'survey_vault') {
            if (
              call.function !== 'claim' &&
              call.function !== 'claim_with_ticket' &&
              call.function !== 'claim_with_nft_marking'
            ) {
              return reply.status(400).send({
                error: 'invalid_transaction_commands',
                message: 'Only claim, claim_with_ticket, or claim_with_nft_marking allowed in survey_vault module',
              })
            }
          } else {
            return reply.status(400).send({
              error: 'invalid_transaction_commands',
              message: `Unauthorized module: ${call.module}`,
            })
          }
        }

        if (isPassSponsor) {
          for (const command of commands) {
            const call = command.MoveCall!
            if (call.module !== 'survey_pass') continue

            if (PASS_MINT_FNS.has(call.function)) {
              const depositPayerBytes = getPureBytes(call.arguments[3])
              if (!depositPayerBytes) {
                return reply.status(400).send({
                  error: 'invalid_transaction_arguments',
                  message: 'Failed to extract deposit_payer from mint call',
                })
              }
              const depositPayer = normalizeAddress('0x' + Buffer.from(depositPayerBytes).toString('hex'))
              if (depositPayer !== normalizeAddress(sponsorAddress)) {
                return reply.status(400).send({
                  error: 'invalid_deposit_payer',
                  message: 'Sponsored mint must set deposit_payer to the sponsor address',
                })
              }
            }

            const tickets = extractPassTicketsFromMoveCall(getPureBytes, call.function, call.arguments)
            if (!tickets || tickets.length === 0) {
              return reply.status(400).send({
                error: 'invalid_transaction_arguments',
                message: 'Failed to extract ticket parameters from transaction inputs',
              })
            }

            for (const ticket of tickets) {
              const verifyRes = await verifyPassTicketSignature(keypair, senderAddress, ticket)
              if (!verifyRes.ok) {
                return reply.status(verifyRes.status).send({
                  error: verifyRes.error,
                  message: verifyRes.message,
                })
              }
            }
          }

          const scope = resolveCountScope()
          const checkRes = await checkSponsorLimit({
            suiClient: deps.suiClient,
            senderAddress,
            sponsorAddress,
            maxLimit: scope.passMax,
            packageId: scope.packageId,
            sinceMs: scope.sinceMs,
          })

          if (!checkRes.allowed) {
            return reply.status(403).send({
              error: 'PLATFORM_SPONSOR_LIMIT_REACHED',
              message: 'SurveyPass lifetime sponsor limit reached for this wallet address',
            })
          }
        } else {
          // Extract Vault and Pass object IDs from claim call
          const call = commands[0].MoveCall!

          let answersArg: any = null
          let blobIdArg: any = null

          if (call.function === 'claim') {
            answersArg = call.arguments[3]
            blobIdArg = call.arguments[4]

            const firstArg = call.arguments[0]
            if (firstArg && firstArg.$kind === 'Input') {
              vaultId = getObjectIdFromInput(tx.getData().inputs[firstArg.Input])
            }

            const thirdArg = call.arguments[2]
            if (thirdArg && thirdArg.$kind === 'Input') {
              passId = getObjectIdFromInput(tx.getData().inputs[thirdArg.Input])
            }
          } else if (call.function === 'claim_with_ticket') {
            answersArg = call.arguments[5]
            blobIdArg = call.arguments[6]

            const firstArg = call.arguments[0]
            if (firstArg && firstArg.$kind === 'Input') {
              vaultId = getObjectIdFromInput(tx.getData().inputs[firstArg.Input])
            }
          } else if (call.function === 'claim_with_nft_marking') {
            answersArg = call.arguments[2]
            blobIdArg = call.arguments[3]

            const firstArg = call.arguments[0]
            if (firstArg && firstArg.$kind === 'Input') {
              vaultId = getObjectIdFromInput(tx.getData().inputs[firstArg.Input])
            }
          }

          const answersParsed = parseOptionVectorU8(
            answersArg ? getPureBytes(answersArg) : null
          )
          const blobParsed = parseOptionVectorU8(blobIdArg ? getPureBytes(blobIdArg) : null)

          if (answersParsed.isSome && blobParsed.isSome) {
            return reply.status(400).send({
              error: 'ambiguous_answer_payload',
              message: 'Cannot set both inline encrypted_answers and answer_blob_id',
            })
          }

          if (!vaultId) {
            return reply.status(400).send({
              error: 'invalid_transaction_commands',
              message: 'Failed to extract SurveyVault ID',
            })
          }

          // Fetch SurveyVault fields to verify gas
          const vaultObj = await deps.suiClient.getObject({
            id: vaultId,
            options: { showContent: true },
          })

          if (!vaultObj.data || !vaultObj.data.content) {
            return reply.status(404).send({
              error: 'vault_not_found',
              message: `SurveyVault ${vaultId} not found`,
            })
          }

          const fields = (vaultObj.data.content as any).fields
          if (!fields) {
            return reply.status(500).send({
              error: 'invalid_vault_object',
              message: 'Failed to read vault fields',
            })
          }

          const vaultMaxInline = BigInt(fields.max_inline_answer_bytes ?? '6144')
          const inlineLimit = effectiveInlineLimit(vaultMaxInline)

          if (answersParsed.isSome && answersParsed.payload) {
            if (answersParsed.payload.length > inlineLimit) {
              return reply.status(400).send({
                error: 'inline_answer_too_large',
                message: `Encrypted answers payload exceeds inline limit (${inlineLimit} bytes); use Walrus storage`,
              })
            }
          }

          if (blobParsed.isSome && blobParsed.payload && blobParsed.payload.length > 1000) {
            return reply.status(400).send({
              error: 'blob_id_too_large',
              message: 'Answer blob_id size exceeds limit',
            })
          }

          claimHasBlob = blobParsed.isSome
          claimGasCompensationAmount = BigInt(fields.gas_compensation_amount || '0')
          claimStorageCompensationAmount = BigInt(fields.storage_compensation_amount || '0')

          const gasBalance = BigInt(fields.gas_balance || '0')
          const gasCompensationAmount = claimGasCompensationAmount

          if (gasBalance < gasCompensationAmount) {
            isPlatformSponsor = true
          }

          if (isPlatformSponsor) {
            const todayStr = todayUtcDate()
            const dailyCount = await getPlatformSponsorCount(senderAddress, todayStr)
            const dailyLimit = platformSponsorDailyLimit()

            if (dailyCount >= dailyLimit) {
              return reply.status(403).send({
                error: 'PLATFORM_SPONSOR_LIMIT_REACHED',
                message: 'Daily platform sponsorship limit reached for this wallet address',
              })
            }

            const tierCheck = await assertPlatformSponsorTierEligible(
              deps.suiClient,
              deps.packageId,
              senderAddress,
              gasConfig.minPlatformSponsorTier,
              passId
            )
            if (!tierCheck.ok) {
              return reply.status(403).send({
                error: tierCheck.error,
                message: tierCheck.message,
              })
            }
          }
        }

        const pipelineContext = {
          isPassSponsor,
          isPlatformSponsor,
          claimGasCompensationAmount: claimGasCompensationAmount?.toString() ?? null,
          claimStorageCompensationAmount: claimStorageCompensationAmount?.toString() ?? null,
          claimHasBlob,
        }
        const requestId =
          typeof req.headers['x-request-id'] === 'string' ? req.headers['x-request-id'] : undefined

        if (getGasStationMode() === 'do') {
          const forwarded = await forwardSponsorToGasStation({
            txBytes,
            senderAddress,
            sponsorAddress,
            requestId,
            pipelineContext,
          })
          if (!forwarded.ok) {
            return reply.status(forwarded.status).send({
              error: forwarded.error,
              message: forwarded.message,
            })
          }
          if (isPlatformSponsor) {
            await incrementPlatformSponsorCount(senderAddress, todayUtcDate())
          }
          if (isPassSponsor) {
            reserveSponsor(senderAddress)
          }
          return forwarded.data
        }

        const outcome = await runSponsorPipeline({
          txBytes,
          senderAddress,
          suiClient: deps.suiClient,
          keypair,
          sponsorAddress,
          coinStore: coinQueue,
          gasConfig,
          context: pipelineContext,
          requestId,
          onPlatformSponsorSigned: isPlatformSponsor
            ? async () => {
                await incrementPlatformSponsorCount(senderAddress, todayUtcDate())
              }
            : undefined,
          onPassSponsorSigned: isPassSponsor ? () => reserveSponsor(senderAddress) : undefined,
        })

        req.log.info(
          {
            requestId,
            sender: senderAddress,
            outcome: outcome.metrics.outcome,
            queueWaitMs: outcome.metrics.queueWaitMs,
            dryRunMs: outcome.metrics.dryRunMs,
            coinObjectId: outcome.metrics.coinObjectId,
          },
          '[GasStation] sponsor pipeline'
        )

        if (!outcome.ok) {
          if (outcome.error === 'dry_run_failed') {
            req.log.warn(`[GasStation] Dry run rejected: ${outcome.message}`)
          }
          return reply.status(outcome.status).send({
            error: outcome.error,
            message: outcome.message,
          })
        }

        return outcome.result
      } catch (err: any) {
        req.log.error(err)
        return reply.status(500).send({ error: 'sponsor_failed', message: err.message })
      }
    }
  )
}

import type { SuiClient } from '@mysten/sui/client'

// ─────────────────────────────────────────────────────────────────────────────
// Source of truth = on-chain history. We do NOT keep a persistent local ledger
// any more: it used to be incremented eagerly (before dry-run / signing / on-chain
// submission), which inflated the count whenever a sponsorship request was made
// but no transaction ever landed on chain (e.g. Email re-fill that pre-flight
// dry-run rejects, or a user who abandons the wallet prompt).
//
// Instead:
//   • `countOnChainSponsoredTx` is the authority — it counts transactions that
//     actually hit the chain (and thus consumed sponsor gas), INCLUDING ones that
//     failed during Move execution. Transactions rejected only by pre-flight
//     dry-run never land on chain and are therefore never counted.
//   • A short-TTL in-memory cache avoids re-querying the chain on every request.
//   • In-flight reservations (also in-memory, with a short TTL) prevent rapid
//     double-spend within the chain-indexing window, then self-expire so an
//     abandoned request leaves no permanent phantom count.
// ─────────────────────────────────────────────────────────────────────────────

// On-chain count cache TTL: how long a fetched on-chain count is trusted before re-query.
const ONCHAIN_CACHE_TTL_MS = 45_000
// In-flight reservation TTL: covers the window between signing and the tx being indexed.
const RESERVATION_TTL_MS = 120_000

interface OnChainCacheEntry {
  count: number
  fetchedAt: number
}

// normalizedAddr -> cached on-chain count
const onChainCountCache = new Map<string, OnChainCacheEntry>()
// normalizedAddr -> list of reservation creation timestamps (ms epoch). Each entry
// bridges the window between signing a sponsored tx and that tx being indexed on
// chain. It is released either when a fresh on-chain read reflects it (see
// getCachedOnChainCount) or, as a safety net for abandoned requests, once it
// exceeds RESERVATION_TTL_MS.
const pendingReservations = new Map<string, number[]>()

function normalizeAddress(addr: string): string {
  let clean = addr.toLowerCase()
  if (clean.startsWith('0x')) clean = clean.slice(2)
  return '0x' + clean.padStart(64, '0')
}

/** Return live (non-expired) reservations for an address, pruning expired ones (push-ordered: index 0 = oldest). */
function liveReservations(normalizedAddr: string): number[] {
  const now = Date.now()
  const list = pendingReservations.get(normalizedAddr)
  if (!list || list.length === 0) return []
  const live = list.filter((createdAt) => now - createdAt < RESERVATION_TTL_MS)
  if (live.length === 0) {
    pendingReservations.delete(normalizedAddr)
  } else if (live.length !== list.length) {
    pendingReservations.set(normalizedAddr, live)
  }
  return live
}

/** Count live (non-expired) in-flight reservations for an address. */
function pendingCount(normalizedAddr: string): number {
  return liveReservations(normalizedAddr).length
}

/**
 * Release the `n` oldest live reservations for an address. Called when a fresh
 * on-chain read shows that `n` more sponsored txs have landed: those txs are now
 * part of the on-chain count, so the reservations that bridged them must be
 * dropped. Otherwise the same sponsorship would be counted twice (reservation +
 * on-chain) for up to the full RESERVATION_TTL_MS window — which made the
 * displayed quota spike then "recover" as the phantom reservation expired.
 */
function releaseReservations(normalizedAddr: string, n: number): void {
  if (n <= 0) return
  const live = liveReservations(normalizedAddr)
  if (live.length === 0) return
  const remaining = live.slice(n) // index 0 is oldest → drop the n oldest
  if (remaining.length === 0) pendingReservations.delete(normalizedAddr)
  else pendingReservations.set(normalizedAddr, remaining)
}

/**
 * Double-check on-chain RPC history for sponsored transactions to this user.
 * This is the source of truth for how many lifetime sponsorships an address has
 * consumed.
 *
 * NOTE on semantics: we count any transaction that was submitted on chain with
 * our sponsor as gas payer and contains a survey_pass mint/update call —
 * regardless of whether it succeeded or failed (Move abort). A Move-aborted tx is
 * still committed on chain and consumed sponsor gas, so it counts. A tx that only
 * failed pre-flight dry-run never lands on chain and therefore never appears here.
 */
export async function countOnChainSponsoredTx(params: {
  suiClient: SuiClient
  senderAddress: string
  sponsorAddress: string
  packageId?: string | null
  sinceMs?: number
}): Promise<number> {
  const { suiClient, senderAddress, sponsorAddress, packageId, sinceMs } = params
  const normalizedSender = normalizeAddress(senderAddress)
  const normalizedSponsor = normalizeAddress(sponsorAddress)
  const normalizedPackage = packageId ? normalizeAddress(packageId) : null
  const minTimestamp = sinceMs && sinceMs > 0 ? sinceMs : 0

  let count = 0
  let hasNextPage = true
  let cursor: any = null
  let pagesPolled = 0

  console.log(`[SponsorLedger] Querying chain for sender: ${normalizedSender}, sponsor: ${normalizedSponsor}`)

  try {
    while (hasNextPage && pagesPolled < 5) {
      const res = await suiClient.queryTransactionBlocks({
        filter: {
          FromAddress: normalizedSender,
        },
        cursor,
        limit: 50,
        // `showInput` is what populates `transaction.data` (the PTB + gasData).
        // There is NO `showTransaction` option in Sui RPC — passing it (hidden by
        // the old `as any`) was silently ignored, so transaction.data stayed empty,
        // commands resolved to [] and the on-chain count was always 0.
        options: {
          showInput: true,
          showEffects: true,
        },
      })

      for (const txBlock of res.data) {
        // Time-window filter: skip txs older than the configured threshold.
        // `timestampMs` is a top-level field on the RPC response; when it's
        // missing we conservatively count the tx (and warn) rather than risk
        // under-counting the lifetime quota.
        if (minTimestamp > 0) {
          const tsRaw = (txBlock as any).timestampMs
          if (tsRaw == null) {
            console.warn('[SponsorLedger] tx missing timestampMs; counting conservatively')
          } else if (Number(tsRaw) < minTimestamp) {
            continue
          }
        }

        // Check if gas payer was our sponsor address
        const payer = txBlock.transaction?.data?.gasData?.owner
        if (payer && normalizeAddress(payer) === normalizedSponsor) {
          // Verify if it is indeed a survey_pass related call (mint_pass / update_pass_credential).
          // We intentionally do NOT inspect effects.status here: a failed (Move-aborted)
          // sponsored tx still consumed gas on chain and must count.
          // Sui RPC returns programmable-transaction commands under `.transactions`
          // (NOT `.commands`, which is the local SDK builder's field name).
          const commands = (txBlock.transaction?.data?.transaction as any)?.transactions || []
          const hasPassCall = commands.some((cmd: any) => {
            if (cmd.MoveCall) {
              const call = cmd.MoveCall
              const isPassMod = call.module === 'survey_pass'
              const isTargetFn =
                call.function === 'mint_pass' ||
                call.function === 'mint_pass_with_extra_credentials' ||
                call.function === 'update_pass_credential'
              // Package filter: when scoped to a specific package, only count
              // calls into that package so a redeploy (reset-registry) starts the
              // lifetime quota fresh. null = count across all packages (legacy).
              const isTargetPkg =
                normalizedPackage == null ||
                (typeof call.package === 'string' &&
                  normalizeAddress(call.package) === normalizedPackage)
              return isPassMod && isTargetFn && isTargetPkg
            }
            return false
          })

          if (hasPassCall) {
            count++
          }
        }
      }

      hasNextPage = res.hasNextPage
      cursor = res.nextCursor
      pagesPolled++
    }
  } catch (error) {
    console.error('[SponsorLedger] Failed to query on-chain transaction history', error)
  }

  console.log(`[SponsorLedger] On-chain check completed. Found ${count} sponsored transactions.`)
  return count
}

/** Fetch the on-chain count for an address, using a short-TTL cache. */
async function getCachedOnChainCount(params: {
  suiClient: SuiClient
  senderAddress: string
  sponsorAddress: string
  packageId?: string | null
  sinceMs?: number
}): Promise<number> {
  const { suiClient, senderAddress, sponsorAddress, packageId, sinceMs } = params
  const normalizedUser = normalizeAddress(senderAddress)
  // Cache key must include the filter conditions, otherwise scopes (current
  // package vs all, different sinceMs) would collide on the same address.
  const cacheKey = `${normalizedUser}|${packageId ?? 'all'}|${sinceMs ?? 0}`

  const cached = onChainCountCache.get(cacheKey)
  if (cached && Date.now() - cached.fetchedAt < ONCHAIN_CACHE_TTL_MS) {
    return cached.count
  }

  const count = await countOnChainSponsoredTx({
    suiClient,
    senderAddress: normalizedUser,
    sponsorAddress,
    packageId,
    sinceMs,
  })
  // A fresh read that shows more sponsored txs than the previous snapshot means
  // those txs have now been indexed on chain; release an equal number of in-flight
  // reservations so they are not double-counted on top of the on-chain total.
  // (First read has no baseline → nothing to release.)
  if (cached && count > cached.count) {
    releaseReservations(normalizedUser, count - cached.count)
  }
  onChainCountCache.set(cacheKey, { count, fetchedAt: Date.now() })
  return count
}

/**
 * Read-only check of whether the address has remaining sponsor quota.
 * The effective count = on-chain truth + in-flight reservations. Does NOT mutate
 * any persistent state — call `reserveSponsor` only after the sponsor signature
 * has been produced.
 */
export async function checkSponsorLimit(params: {
  suiClient: SuiClient
  senderAddress: string
  sponsorAddress: string
  maxLimit: number
  packageId?: string | null
  sinceMs?: number
}): Promise<{ allowed: boolean; count: number }> {
  const { suiClient, senderAddress, sponsorAddress, maxLimit, packageId, sinceMs } = params
  const normalizedUser = normalizeAddress(senderAddress)

  const onChain = await getCachedOnChainCount({
    suiClient,
    senderAddress,
    sponsorAddress,
    packageId,
    sinceMs,
  })
  const effective = onChain + pendingCount(normalizedUser)

  return { allowed: effective < maxLimit, count: effective }
}

/**
 * Record an in-flight reservation for an address. Call this only after the
 * sponsor signature has been produced (i.e. we are optimistic the user will
 * broadcast). The reservation auto-expires after RESERVATION_TTL_MS, by which
 * time a genuinely broadcast tx will be reflected in the on-chain count.
 */
export function reserveSponsor(senderAddress: string): void {
  const normalizedUser = normalizeAddress(senderAddress)
  const list = pendingReservations.get(normalizedUser) ?? []
  list.push(Date.now()) // store creation time; expiry derived via RESERVATION_TTL_MS
  pendingReservations.set(normalizedUser, list)
}

/**
 * Gets the current sponsor count for an address: on-chain truth plus any
 * in-flight reservations, so the displayed quota reflects both settled and
 * in-progress sponsorships.
 */
export async function getSponsorCount(params: {
  suiClient: SuiClient
  senderAddress: string
  sponsorAddress: string
  packageId?: string | null
  sinceMs?: number
}): Promise<number> {
  const { suiClient, senderAddress, sponsorAddress, packageId, sinceMs } = params
  const normalizedUser = normalizeAddress(senderAddress)

  const onChain = await getCachedOnChainCount({
    suiClient,
    senderAddress,
    sponsorAddress,
    packageId,
    sinceMs,
  })
  return onChain + pendingCount(normalizedUser)
}

/** Test-only: clear all in-memory sponsor state (on-chain cache + reservations). */
export function __resetSponsorState(): void {
  onChainCountCache.clear()
  pendingReservations.clear()
}

import { describe, it, expect, beforeAll, beforeEach, vi } from 'vitest'
import { Ed25519Keypair } from '@mysten/sui/keypairs/ed25519'
import { buildApp } from '../app.js'
import { buildDeleteAuthMessage } from './handler.js'
import { createStatsCache } from '../stats/cache.js'

const PKG = '0x' + 'ab'.repeat(32)
const REGISTRY = '0x' + '11'.repeat(32)
const CONFIG = '0x' + '22'.repeat(32)
const PASS_ID = '0x' + '33'.repeat(32)
// 32-byte 私鑰（sponsor / admin）
const SPONSOR_PRIV = '0102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f20'

function sponsorAddress(): string {
  const kp = Ed25519Keypair.fromSecretKey(new Uint8Array(Buffer.from(SPONSOR_PRIV, 'hex')))
  return kp.getPublicKey().toSuiAddress()
}

function makeSuiClientMock(passFields: { owner: string; deposit_payer: string }) {
  return {
    getObject: vi.fn(async () => ({
      data: {
        type: `${PKG}::survey_pass::SurveyPass`,
        content: { fields: passFields },
      },
    })),
    signAndExecuteTransaction: vi.fn(async () => ({
      digest: '0xDIGEST',
      effects: { status: { status: 'success' } },
    })),
  } as any
}

async function makeApp(suiClient: any) {
  return buildApp({ suiClient, cache: createStatsCache(), packageId: PKG, logger: false })
}

async function signDelete(ownerKp: Ed25519Keypair, passId: string, ts: number) {
  const msg = new TextEncoder().encode(buildDeleteAuthMessage(passId, ts))
  const { signature } = await ownerKp.signPersonalMessage(msg)
  return signature
}

describe('/api/pass/delete — 後端代執行刪除（代付 Pass）', () => {
  beforeAll(() => {
    process.env.SUI_PACKAGE_ID = PKG
    process.env.PASS_REGISTRY_ID = REGISTRY
    process.env.ISSUER_CONFIG_ID = CONFIG
    process.env.SURVEY_PASS_ISSUER_PRIV = SPONSOR_PRIV
  })

  let ownerKp: Ed25519Keypair
  beforeEach(() => {
    ownerKp = new Ed25519Keypair()
  })

  it('缺參數 → 400', async () => {
    const app = await makeApp(makeSuiClientMock({ owner: '0x0', deposit_payer: sponsorAddress() }))
    const res = await app.inject({ method: 'POST', url: '/api/pass/delete', payload: { passId: PASS_ID } })
    expect(res.statusCode).toBe(400)
  })

  it('owner 合法簽名 + deposit_payer==sponsor → 200 並回傳 digest，且以 admin 簽署執行', async () => {
    const owner = ownerKp.getPublicKey().toSuiAddress()
    const sui = makeSuiClientMock({ owner, deposit_payer: sponsorAddress() })
    const app = await makeApp(sui)
    const ts = Date.now()
    const signature = await signDelete(ownerKp, PASS_ID, ts)

    const res = await app.inject({
      method: 'POST',
      url: '/api/pass/delete',
      payload: { passId: PASS_ID, signedTimestamp: ts, signature },
    })

    expect(res.statusCode).toBe(200)
    expect(res.json()).toEqual({ digest: '0xDIGEST' })
    expect(sui.signAndExecuteTransaction).toHaveBeenCalledOnce()
  })

  it('非代付 Pass（deposit_payer != sponsor）→ 400 not_sponsor_funded', async () => {
    const owner = ownerKp.getPublicKey().toSuiAddress()
    const sui = makeSuiClientMock({ owner, deposit_payer: '0x' + '99'.repeat(32) })
    const app = await makeApp(sui)
    const ts = Date.now()
    const signature = await signDelete(ownerKp, PASS_ID, ts)

    const res = await app.inject({
      method: 'POST',
      url: '/api/pass/delete',
      payload: { passId: PASS_ID, signedTimestamp: ts, signature },
    })

    expect(res.statusCode).toBe(400)
    expect(res.json().error).toBe('not_sponsor_funded')
    expect(sui.signAndExecuteTransaction).not.toHaveBeenCalled()
  })

  it('簽名非 owner 所簽 → 401 invalid_signature', async () => {
    const owner = ownerKp.getPublicKey().toSuiAddress()
    const sui = makeSuiClientMock({ owner, deposit_payer: sponsorAddress() })
    const app = await makeApp(sui)
    const ts = Date.now()
    // 用另一把金鑰簽（冒充者）
    const attacker = new Ed25519Keypair()
    const signature = await signDelete(attacker, PASS_ID, ts)

    const res = await app.inject({
      method: 'POST',
      url: '/api/pass/delete',
      payload: { passId: PASS_ID, signedTimestamp: ts, signature },
    })

    expect(res.statusCode).toBe(401)
    expect(sui.signAndExecuteTransaction).not.toHaveBeenCalled()
  })

  it('授權過期（時間戳過舊）→ 400 authorization_expired', async () => {
    const owner = ownerKp.getPublicKey().toSuiAddress()
    const sui = makeSuiClientMock({ owner, deposit_payer: sponsorAddress() })
    const app = await makeApp(sui)
    const ts = Date.now() - 10 * 60_000 // 10 分鐘前
    const signature = await signDelete(ownerKp, PASS_ID, ts)

    const res = await app.inject({
      method: 'POST',
      url: '/api/pass/delete',
      payload: { passId: PASS_ID, signedTimestamp: ts, signature },
    })

    expect(res.statusCode).toBe(400)
    expect(res.json().error).toBe('authorization_expired')
  })
})

import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify'
import { Transaction } from '@mysten/sui/transactions'
import { Ed25519Keypair } from '@mysten/sui/keypairs/ed25519'
import { verifyPersonalMessageSignature } from '@mysten/sui/verify'
import type { SuiClient } from '@mysten/sui/client'

interface PassDeleteRequestBody {
  passId: string
  // 使用者用錢包對 personal-message 簽名（免 gas）授權刪除；message 由下方格式重建
  signedTimestamp: number
  signature: string
}

// 授權訊息有效期：限制簽名重放窗口
const SIGNATURE_TTL_MS = 5 * 60_000

function normalizeAddress(addr: string): string {
  let clean = addr.toLowerCase()
  if (clean.startsWith('0x')) clean = clean.slice(2)
  return '0x' + clean.padStart(64, '0')
}

function loadSponsorKeypair(): { keypair: Ed25519Keypair; sponsorAddress: string } | null {
  const privKeyHex = process.env.SURVEY_PASS_ISSUER_PRIV
  if (!privKeyHex) return null
  const privKeyClean = privKeyHex.startsWith('0x') ? privKeyHex.slice(2) : privKeyHex
  const privateKeyBytes = new Uint8Array(Buffer.from(privKeyClean, 'hex'))
  const keypair = Ed25519Keypair.fromSecretKey(privateKeyBytes.slice(0, 32))
  return { keypair, sponsorAddress: keypair.getPublicKey().toSuiAddress() }
}

// 與前端一致的授權訊息格式（綁定 passId + 時間戳，防止跨 Pass / 過期重放）。
// 直接使用呼叫端傳入的 passId 字串（不正規化），確保前端簽署與後端驗證的 bytes 完全一致。
export function buildDeleteAuthMessage(passId: string, signedTimestamp: number): string {
  return `surveysui:delete-pass:${passId}:${signedTimestamp}`
}

export function registerPassRoutes(app: FastifyInstance, deps: { suiClient: SuiClient }): void {
  // 後端代為執行「項目方代付」Pass 的刪除：admin 為 gas owner，使儲存返還回到項目方。
  // 使用者僅需做一次免 gas 的 personal-message 簽名授權；運算費由項目方負擔（但淨收返還）。
  app.post(
    '/api/pass/delete',
    async (req: FastifyRequest<{ Body: PassDeleteRequestBody }>, reply: FastifyReply) => {
      const { passId, signedTimestamp, signature } = req.body ?? ({} as PassDeleteRequestBody)
      if (!passId || !signedTimestamp || !signature) {
        return reply.status(400).send({ error: 'missing_params', message: 'passId, signedTimestamp and signature are required' })
      }

      const packageId = process.env.SUI_PACKAGE_ID
      const registryId = process.env.PASS_REGISTRY_ID
      const configId = process.env.ISSUER_CONFIG_ID
      if (!packageId || !registryId || !configId) {
        return reply.status(500).send({ error: 'server_misconfigured', message: 'Missing package/registry/config IDs' })
      }

      const sponsor = loadSponsorKeypair()
      if (!sponsor) {
        return reply.status(503).send({ error: 'sponsor_unavailable', message: 'Sponsor key not configured' })
      }
      const { keypair, sponsorAddress } = sponsor

      try {
        // 1. 時間戳新鮮度（限制重放窗口）
        if (Math.abs(Date.now() - Number(signedTimestamp)) > SIGNATURE_TTL_MS) {
          return reply.status(400).send({ error: 'authorization_expired', message: 'Delete authorization expired; please retry' })
        }

        // 2. 查 Pass 物件，取 owner / deposit_payer / 型別
        const passObj = await deps.suiClient.getObject({ id: passId, options: { showContent: true, showType: true } })
        if (!passObj.data || !passObj.data.content) {
          return reply.status(404).send({ error: 'pass_not_found', message: `SurveyPass ${passId} not found` })
        }
        const expectedType = `${normalizeAddress(packageId)}::survey_pass::SurveyPass`
        const actualType = (passObj.data.type ?? '').replace(/^0x0*/, '0x')
        if (normalizeAddress(actualType.split('::')[0]) !== normalizeAddress(packageId) || !actualType.endsWith('::survey_pass::SurveyPass')) {
          return reply.status(400).send({ error: 'invalid_object_type', message: `Object is not a SurveyPass (${expectedType})` })
        }
        const fields = (passObj.data.content as any).fields
        const owner = normalizeAddress(String(fields.owner))
        const depositPayer = normalizeAddress(String(fields.deposit_payer))

        // 3. 僅代執行「項目方代付」的 Pass；自付 Pass 由使用者自行刪除
        if (depositPayer !== normalizeAddress(sponsorAddress)) {
          return reply.status(400).send({
            error: 'not_sponsor_funded',
            message: 'This pass was not sponsor-funded; delete it yourself via delete_pass',
          })
        }

        // 4. 驗證 owner 對授權訊息的簽名（personal message，免 gas）
        const message = buildDeleteAuthMessage(passId, Number(signedTimestamp))
        const messageBytes = new TextEncoder().encode(message)
        try {
          await verifyPersonalMessageSignature(messageBytes, signature, { address: owner })
        } catch {
          return reply.status(401).send({ error: 'invalid_signature', message: 'Delete authorization signature is invalid or not signed by the pass owner' })
        }

        // 5. 由 admin（= sponsor）建構並執行 delete_pass：admin 為 sender + gas owner → 儲存返還回項目方
        const tx = new Transaction()
        tx.moveCall({
          target: `${packageId}::survey_pass::delete_pass`,
          arguments: [tx.object(registryId), tx.object(passId)],
        })
        tx.setSender(sponsorAddress)

        const result = await deps.suiClient.signAndExecuteTransaction({
          signer: keypair,
          transaction: tx,
          options: { showEffects: true },
        })

        if (result.effects?.status.status === 'failure') {
          return reply.status(422).send({ error: 'delete_failed', message: result.effects.status.error })
        }

        return { digest: result.digest }
      } catch (err: any) {
        req.log.error(err)
        return reply.status(500).send({ error: 'pass_delete_failed', message: err.message })
      }
    }
  )
}

import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify'
import type { SuiClient } from '@mysten/sui/client'
import { verifyPersonalMessageSignature } from '@mysten/sui/verify'
import { randomBytes } from 'node:crypto'
import { issueRealTimeTicket } from '../auth/ticket_issue.js'

interface TicketIssueRequestBody {
  vaultId: string
  walletA: string
  signedTimestamp: number
  signature: string
}

// 授權時間窗口 5 分鐘
const SIGNATURE_TTL_MS = 5 * 60_000
// 臨時去重記錄 Map: `${walletA.toLowerCase()}:${vaultId.toLowerCase()}` -> timestamp
const issuedTicketsRegistry = new Map<string, number>()

function normalizeAddress(addr: string): string {
  let clean = addr.toLowerCase()
  if (clean.startsWith('0x')) clean = clean.slice(2)
  return '0x' + clean.padStart(64, '0')
}

// 生成授權驗證訊息
export function buildTicketAuthMessage(vaultId: string, signedTimestamp: number): string {
  return `surveysui:issue-ticket:${vaultId}:${signedTimestamp}`
}

export function registerTicketRoutes(app: FastifyInstance, deps: { suiClient: SuiClient }): void {
  app.post(
    '/api/ticket/issue',
    async (req: FastifyRequest<{ Body: TicketIssueRequestBody }>, reply: FastifyReply) => {
      const { vaultId, walletA, signedTimestamp, signature } = req.body ?? ({} as TicketIssueRequestBody)

      if (!vaultId || !walletA || !signedTimestamp || !signature) {
        return reply.status(400).send({
          error: 'missing_params',
          message: 'vaultId, walletA, signedTimestamp and signature are required',
        })
      }

      const packageId = process.env.SUI_PACKAGE_ID
      if (!packageId) {
        return reply.status(500).send({
          error: 'server_misconfigured',
          message: 'Missing SUI_PACKAGE_ID env variable',
        })
      }

      try {
        // 1. 時間戳新鮮度（防範重放）
        if (Math.abs(Date.now() - Number(signedTimestamp)) > SIGNATURE_TTL_MS) {
          return reply.status(400).send({
            error: 'authorization_expired',
            message: 'Signature expired; please retry',
          })
        }

        // 2. 驗證錢包 A 的所有權簽名
        const message = buildTicketAuthMessage(vaultId, Number(signedTimestamp))
        const messageBytes = new TextEncoder().encode(message)
        try {
          await verifyPersonalMessageSignature(messageBytes, signature, { address: walletA })
        } catch {
          return reply.status(401).send({
            error: 'invalid_signature',
            message: 'Authorization signature is invalid or not signed by walletA',
          })
        }

        // 3. 防重複申請 Ticket 檢查
        const registryKey = `${normalizeAddress(walletA)}:${normalizeAddress(vaultId)}`
        if (issuedTicketsRegistry.has(registryKey)) {
          return reply.status(400).send({
            error: 'ticket_already_issued',
            message: 'A ticket has already been issued for this wallet and survey',
          })
        }

        // 4. 讀取鏈上 Vault 設定
        const vaultObj = await deps.suiClient.getObject({
          id: vaultId,
          options: { showContent: true },
        })

        if (!vaultObj.data || !vaultObj.data.content) {
          return reply.status(404).send({
            error: 'vault_not_found',
            message: `SurveyVault ${vaultId} not found`,
          })
        }

        const fields = (vaultObj.data.content as any).fields
        const allowedNftTypeOpt = fields.allowed_nft_type
        const ticketFee = BigInt(fields.ticket_fee ?? '0')
        const gasCompensation = BigInt(fields.gas_compensation_amount ?? '0')
        const storageCompensation = BigInt(fields.storage_compensation_amount ?? '0')
        const gasBalance = BigInt(fields.gas_balance ?? '0')

        // 5. 餘額預檢 (Sponsorship Pool)
        const requiredMinSui = gasCompensation + storageCompensation + ticketFee
        if (gasBalance < requiredMinSui) {
          return reply.status(422).send({
            error: 'insufficient_sponsor_balance',
            message: 'Sponsorship pool has insufficient balance to sponsor gas & ticket fee',
          })
        }

        // 6. 驗證資產持有資格 (若有限制 NFT)
        let allowedNftTypeBytes: number[] | null = null
        if (allowedNftTypeOpt) {
          // 支援兩種新舊 RPC Option 格式
          if (Array.isArray(allowedNftTypeOpt)) {
            allowedNftTypeBytes = allowedNftTypeOpt.length > 0 ? allowedNftTypeOpt[0] : null
          } else if (allowedNftTypeOpt.fields?.vec) {
            allowedNftTypeBytes = allowedNftTypeOpt.fields.vec
          }
        }

        if (allowedNftTypeBytes && allowedNftTypeBytes.length > 0) {
          const allowedNftTypeStr = String.fromCharCode(...allowedNftTypeBytes)
          req.log.info(`Checking NFT ownership for ${walletA} on type: ${allowedNftTypeStr}`)

          // 呼叫 Sui RPC 查詢擁有的特定類型 NFT
          const ownedNfts = await deps.suiClient.getOwnedObjects({
            owner: walletA,
            filter: { StructType: allowedNftTypeStr },
            limit: 1,
          })

          if (!ownedNfts.data || ownedNfts.data.length === 0) {
            return reply.status(403).send({
              error: 'ineligible_assets',
              message: `You do not own the required NFT collection: ${allowedNftTypeStr}`,
            })
          }
        }

        // 7. 簽發 Ticket
        const ephemeralNullifier = new Uint8Array(randomBytes(32))
        // Ticket 5 分鐘有效
        const expiresAtMs = Date.now() + SIGNATURE_TTL_MS

        const ticket = await issueRealTimeTicket(vaultId, ephemeralNullifier, expiresAtMs)

        // 8. 寫入去重快取，並回傳
        issuedTicketsRegistry.set(registryKey, Date.now())

        return ticket
      } catch (err: any) {
        req.log.error(err)
        return reply.status(500).send({
          error: 'ticket_issuance_failed',
          message: err.message || 'Failed to issue ticket',
        })
      }
    }
  )
}

import type { SuiClient } from '@mysten/sui/client'
import { Ed25519Keypair } from '@mysten/sui/keypairs/ed25519'
import {
  buildAndDryRunPurgeWithRebateRefund,
  readVaultCreator,
} from './rebateRefund.js'

/**
 * Background task that permanently destroys surveys whose grace period has
 * elapsed. This is the "automatic" trigger for the data-purge lifecycle: Sui has
 * no on-chain scheduler, so an external transaction must call `survey_vault::purge`
 * once the gate opens. The on-chain function re-checks the gate, so a premature
 * call simply aborts — this scan is only an optimisation to avoid doomed txs.
 *
 * Storage rebate from deleted objects is forwarded to vault.creator in the same
 * PTB (after dry-run gas estimation) when PURGE_REBATE_REFUND_ENABLED is true.
 */

const STATUS_CLOSED = 1

export interface PurgeTaskConfig {
  suiClient: SuiClient
  sponsorKeypair: Ed25519Keypair
  packageId: string
  registryId: string
  /** Max surveys to purge per cycle (bounds run time / gas). */
  maxPerCycle?: number
}

interface VaultState {
  status: number
  closedAtMs: bigint
  deadlineMs: bigint
  purgeGraceMs: bigint
  creator: string | null
}

/** Read the lifecycle fields of a vault, or null if it no longer exists. */
async function readVaultState(suiClient: SuiClient, vaultId: string): Promise<VaultState | null> {
  try {
    const res = await suiClient.getObject({ id: vaultId, options: { showContent: true } })
    const content = res.data?.content as any
    if (!content || content.dataType !== 'moveObject') return null
    const f = content.fields
    return {
      status: Number(f.status),
      closedAtMs: BigInt(f.closed_at_ms ?? 0),
      deadlineMs: BigInt(f.deadline_ms ?? 0),
      purgeGraceMs: BigInt(f.purge_grace_ms ?? 0),
      creator: f.creator ? String(f.creator) : null,
    }
  } catch {
    return null
  }
}

/** Terminal anchor + grace gate, mirroring `survey_vault::purge`. */
function isPurgeable(v: VaultState, nowMs: bigint): boolean {
  let anchor: bigint
  if (v.status === STATUS_CLOSED) {
    anchor = v.closedAtMs
  } else if (nowMs > v.deadlineMs) {
    anchor = v.deadlineMs
  } else {
    return false
  }
  return nowMs >= anchor + v.purgeGraceMs
}

/** One scan: find purge-eligible surveys and destroy them. Returns the count purged. */
export async function checkAndPurge(config: PurgeTaskConfig): Promise<number> {
  const { suiClient, sponsorKeypair, packageId, registryId, maxPerCycle = 10 } = config

  const nowMs = BigInt(Date.now())

  const surveys: Array<{ surveyId: string; vaultId: string }> = []
  let cursor: any = null
  let pageCount = 0
  const maxPages = 50
  try {
    do {
      const page = await suiClient.queryEvents({
        query: { MoveEventType: `${packageId}::survey_registry::SurveyRegistered` },
        cursor,
        limit: 50,
      })
      for (const ev of page.data) {
        const p = ev.parsedJson as any
        if (p?.survey_id && p?.vault_id) {
          surveys.push({ surveyId: p.survey_id, vaultId: p.vault_id })
        }
      }
      cursor = page.hasNextPage ? (page.nextCursor ?? null) : null
      pageCount++
    } while (cursor !== null && pageCount < maxPages)
  } catch (err) {
    console.error('[PurgeTask] Failed to enumerate surveys:', err)
    return 0
  }

  let purged = 0
  for (const { surveyId, vaultId } of surveys) {
    if (purged >= maxPerCycle) break
    const state = await readVaultState(suiClient, vaultId)
    if (!state || !isPurgeable(state, nowMs)) continue

    try {
      const creator =
        state.creator ?? (await readVaultCreator(suiClient, vaultId))

      const { tx, gasBudget, transferAmount, platformFee, creator: refundCreator } =
        await buildAndDryRunPurgeWithRebateRefund(
          suiClient,
          sponsorKeypair,
          { packageId, registryId, surveyId, vaultId },
          creator
        )

      tx.setGasBudget(Number(gasBudget))
      await suiClient.signAndExecuteTransaction({ transaction: tx, signer: sponsorKeypair })

      purged++
      if (transferAmount > 0n) {
        console.log(
          `[PurgeTask] Purged vault ${vaultId}, rebate ${transferAmount} MIST → creator ${refundCreator} (platform fee ${platformFee} MIST)`
        )
      } else {
        console.log(`[PurgeTask] Purged survey ${surveyId} (vault ${vaultId})`)
      }
    } catch (err) {
      console.warn(`[PurgeTask] purge failed for ${vaultId}:`, err)
    }
  }

  if (purged > 0) console.log(`[PurgeTask] Cycle complete — purged ${purged} survey(s).`)
  return purged
}

let purgeInterval: NodeJS.Timeout | null = null

/**
 * Start the periodic purge scan. No-op unless `PURGE_TASK_ENABLED=true` and a
 * `SURVEY_REGISTRY_ID` is configured. Returns a stop function.
 */
export function startPurgeTask(
  suiClient: SuiClient,
  keypair: Ed25519Keypair,
  packageId: string
): () => void {
  if (process.env.PURGE_TASK_ENABLED !== 'true') {
    console.log('[PurgeTask] Disabled (set PURGE_TASK_ENABLED=true to enable).')
    return () => {}
  }
  const registryId = process.env.SURVEY_REGISTRY_ID
  if (!registryId) {
    console.warn('[PurgeTask] SURVEY_REGISTRY_ID not set — purge task not started.')
    return () => {}
  }

  const intervalMs = process.env.PURGE_SCAN_INTERVAL_MS
    ? parseInt(process.env.PURGE_SCAN_INTERVAL_MS, 10)
    : 43200000
  const maxPerCycle = process.env.PURGE_MAX_PER_CYCLE
    ? parseInt(process.env.PURGE_MAX_PER_CYCLE, 10)
    : 10

  if (purgeInterval) clearInterval(purgeInterval)

  const run = () => {
    checkAndPurge({ suiClient, sponsorKeypair: keypair, packageId, registryId, maxPerCycle }).catch(
      (err) => console.error('[PurgeTask] Error in background task:', err)
    )
  }

  const startupTimeout = setTimeout(run, 10_000)
  purgeInterval = setInterval(run, intervalMs)
  console.log(`[PurgeTask] Started — scanning every ${intervalMs}ms.`)

  return () => {
    clearTimeout(startupTimeout)
    if (purgeInterval) {
      clearInterval(purgeInterval)
      purgeInterval = null
    }
  }
}

import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify'
import sharp from 'sharp'

interface ImageProxyQuery {
  url?: string
}

export function registerImageProxyRoutes(app: FastifyInstance): void {
  app.get(
    '/api/proxy/image',
    async (req: FastifyRequest<{ Querystring: ImageProxyQuery }>, reply: FastifyReply) => {
      const { url } = req.query
      if (!url) {
        return reply.status(400).send({ error: 'missing_url', message: 'Query parameter "url" is required' })
      }

      let parsedUrl: URL
      try {
        parsedUrl = new URL(url)
      } catch {
        return reply.status(400).send({ error: 'invalid_url', message: 'URL is invalid' })
      }

      if (parsedUrl.protocol !== 'http:' && parsedUrl.protocol !== 'https:') {
        return reply.status(400).send({ error: 'unsupported_protocol', message: 'Only http and https protocols are supported' })
      }

      try {
        // 1. Fetch external image with timeout (5 seconds) and size limit (2MB)
        const controller = new AbortController()
        const timeoutId = setTimeout(() => controller.abort(), 5000)

        const res = await fetch(parsedUrl.toString(), {
          signal: controller.signal,
          headers: {
            'User-Agent': 'SurveySui-ImageProxy/1.0',
          },
        })
        clearTimeout(timeoutId)

        if (!res.ok) {
          return reply.status(502).send({ error: 'fetch_failed', message: `Failed to fetch image: ${res.status}` })
        }

        // Check content-length header early
        const contentLength = res.headers.get('content-length')
        if (contentLength && parseInt(contentLength, 10) > 2 * 1024 * 1024) {
          return reply.status(413).send({ error: 'image_too_large', message: 'Image exceeds 2MB limit' })
        }

        // Read chunks while checking size limit to prevent content-length bypass
        const reader = res.body?.getReader()
        if (!reader) {
          return reply.status(500).send({ error: 'no_response_body', message: 'Response body is empty' })
        }

        const chunks: Uint8Array[] = []
        let totalBytes = 0

        while (true) {
          const { done, value } = await reader.read()
          if (done) break
          if (value) {
            totalBytes += value.length
            if (totalBytes > 2 * 1024 * 1024) {
              await reader.cancel()
              return reply.status(413).send({ error: 'image_too_large', message: 'Image exceeds 2MB limit' })
            }
            chunks.push(value)
          }
        }

        const imageBuffer = Buffer.concat(chunks)

        // 2. Load into sharp and check dimensions (Pixel flood mitigation)
        const image = sharp(imageBuffer)
        const metadata = await image.metadata()

        if (
          (metadata.width && metadata.width > 5000) ||
          (metadata.height && metadata.height > 5000)
        ) {
          return reply.status(400).send({ error: 'pixel_flood_prevented', message: 'Image resolution is too large (max 5000x5000)' })
        }

        // 3. Resize (to within 400x400 aspect-ratio inside) and convert to clean WebP
        const cleanWebpBuffer = await image
          .resize({
            width: 400,
            height: 400,
            fit: 'inside',
            withoutEnlargement: true,
          })
          .webp({ quality: 80 })
          .toBuffer()

        // 4. Return clean image with security headers and caching
        return reply
          .header('Content-Type', 'image/webp')
          .header('X-Content-Type-Options', 'nosniff')
          .header('Cache-Control', 'public, max-age=86400')
          .send(cleanWebpBuffer)
      } catch (err: any) {
        req.log.error(err)
        if (err.name === 'AbortError') {
          return reply.status(504).send({ error: 'gateway_timeout', message: 'Fetching external image timed out' })
        }
        return reply.status(500).send({ error: 'image_processing_failed', message: err.message || 'Failed to process image' })
      }
    }
  )
}

import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify'
import { insertRevokedNullifier, deleteRevokedNullifier } from './db.js'

interface RevokeRequestBody {
  nullifier: string
  source: number
  passId?: string
  reason?: string
}

interface UnrevokeRequestBody {
  nullifier: string
  source: number
}

function verifyAdminSecret(req: FastifyRequest, reply: FastifyReply): boolean {
  const adminSecret = process.env.ADMIN_SECRET
  if (!adminSecret) {
    reply.status(500).send({ error: 'server_misconfigured', message: 'ADMIN_SECRET not set on server' })
    return false
  }

  const authHeader = req.headers.authorization
  if (!authHeader || authHeader !== `Bearer ${adminSecret}`) {
    reply.status(401).send({ error: 'unauthorized', message: 'Invalid or missing admin credentials' })
    return false
  }
  return true
}

export function registerAdminRevocationRoutes(app: FastifyInstance): void {
  app.post(
    '/api/admin/revocation/revoke',
    async (req: FastifyRequest<{ Body: RevokeRequestBody }>, reply: FastifyReply) => {
      if (!verifyAdminSecret(req, reply)) return

      const { nullifier, source, passId, reason } = req.body ?? {}
      if (!nullifier || source === undefined) {
        return reply.status(400).send({ error: 'missing_params', message: 'nullifier and source are required' })
      }

      try {
        await insertRevokedNullifier(nullifier, source, passId, reason)
        return { success: true, message: `Nullifier ${nullifier} has been revoked successfully` }
      } catch (err: any) {
        req.log.error(err)
        return reply.status(500).send({ error: 'revocation_failed', message: err.message })
      }
    }
  )

  app.post(
    '/api/admin/revocation/unrevoke',
    async (req: FastifyRequest<{ Body: UnrevokeRequestBody }>, reply: FastifyReply) => {
      if (!verifyAdminSecret(req, reply)) return

      const { nullifier, source } = req.body ?? {}
      if (!nullifier || source === undefined) {
        return reply.status(400).send({ error: 'missing_params', message: 'nullifier and source are required' })
      }

      try {
        await deleteRevokedNullifier(nullifier, source)
        return { success: true, message: `Nullifier ${nullifier} has been unrevoked successfully` }
      } catch (err: any) {
        req.log.error(err)
        return reply.status(500).send({ error: 'unrevocation_failed', message: err.message })
      }
    }
  )
}

import type { FastifyInstance } from 'fastify'
import type { SuiClient } from '@mysten/sui/client'
import type { LRUCache } from 'lru-cache'
import type { StatsResponse } from '../types.js'
import { fetchClaimedEvents } from './fetcher.js'
import { aggregateEvents } from './aggregator.js'
import { cacheAnswerContent } from '../storage/cacheManager.js'

export interface StatsHandlerDeps {
  suiClient: SuiClient
  cache: LRUCache<string, StatsResponse>
  packageId: string
}

function parseOptionVector(opt: any): number[] | null {
  if (!opt) return null
  if (Array.isArray(opt)) {
    if (opt.length > 0 && typeof opt[0] === 'number') {
      return opt
    }
    if (opt.length > 0 && Array.isArray(opt[0])) {
      return opt[0]
    }
    return null
  }
  if (opt.vec && Array.isArray(opt.vec)) {
    if (opt.vec.length === 0) return null
    return opt.vec[0]
  }
  if (opt.fields && opt.fields.vec && Array.isArray(opt.fields.vec)) {
    if (opt.fields.vec.length === 0) return null
    return opt.fields.vec[0]
  }
  return null
}

export function registerStatsRoutes(app: FastifyInstance, deps: StatsHandlerDeps): void {
  app.get<{ Params: { vaultId: string } }>('/stats/:vaultId', async (req, reply) => {
    const { vaultId } = req.params
    if (!vaultId) return reply.code(400).send({ error: 'invalid_vault_id' })

    const cached = deps.cache.get(vaultId)
    if (cached) return reply.code(200).send(cached)

    try {
      const events = await fetchClaimedEvents(deps.suiClient, vaultId, deps.packageId)

      const processedEvents = await Promise.all(
        events.map(async (ev) => {
          let encryptedAnswers = parseOptionVector(ev.encrypted_answers)
          const answerBlobIdBytes = parseOptionVector(ev.answer_blob_id)

          if (!encryptedAnswers && answerBlobIdBytes && answerBlobIdBytes.length > 0) {
            try {
              const blobIdStr = Buffer.from(answerBlobIdBytes).toString('utf8')
              const cachedBuf = await cacheAnswerContent(blobIdStr)
              encryptedAnswers = Array.from(cachedBuf)
            } catch (err: any) {
              req.log.error(`[Stats] Failed to cache/download answer blob: ${err.message}`)
            }
          }

          return {
            ...ev,
            encrypted_answers: encryptedAnswers,
            answer_blob_id: answerBlobIdBytes,
          } as any
        })
      )

      const response = aggregateEvents(vaultId, processedEvents)
      deps.cache.set(vaultId, response)
      return reply.code(200).send(response)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'unknown'
      return reply.code(502).send({ error: 'rpc_error', message })
    }
  })
}

import fs from 'fs'
import path from 'path'
import crypto from 'crypto'
import type { SuiClient } from '@mysten/sui/client'
import { getFromIpfsMock, downloadFromWalrus } from './ipfsProxy.js'

const SURVEY_CACHE_DIR = path.join(process.cwd(), 'data', 'survey_cache')
const ANSWER_CACHE_DIR = path.join(process.cwd(), 'data', 'answer_cache')

// Ensure directories exist
if (!fs.existsSync(SURVEY_CACHE_DIR)) {
  fs.mkdirSync(SURVEY_CACHE_DIR, { recursive: true })
}
if (!fs.existsSync(ANSWER_CACHE_DIR)) {
  fs.mkdirSync(ANSWER_CACHE_DIR, { recursive: true })
}

function getOptionValue<T>(opt: any): T | null {
  if (!opt || !opt.fields || !Array.isArray(opt.fields.vec)) return null
  if (opt.fields.vec.length === 0) return null
  return opt.fields.vec[0] as T
}

/**
 * Cache and validate survey content under zero trust.
 * 1. Fetch Survey Object from SUI chain.
 * 2. Verify on-chain survey_blob_id matches the requested blobId.
 * 3. Fetch from IPFS mock or Walrus.
 * 4. Compute sha256 of downloaded content and assert it matches the on-chain content_hash.
 * 5. If verified, cache the content.
 */
export async function cacheSurveyContent(
  suiClient: SuiClient,
  surveyId: string,
  blobId: string
): Promise<boolean> {
  if (!fs.existsSync(SURVEY_CACHE_DIR)) {
    fs.mkdirSync(SURVEY_CACHE_DIR, { recursive: true })
  }
  const cachePath = path.join(SURVEY_CACHE_DIR, surveyId)
  if (fs.existsSync(cachePath)) {
    return true // Already cached
  }

  // 1. Fetch Survey Object
  const surveyObj = await suiClient.getObject({
    id: surveyId,
    options: { showContent: true }
  })

  if (!surveyObj.data || !surveyObj.data.content) {
    throw new Error(`Survey object not found: ${surveyId}`)
  }

  const fields = (surveyObj.data.content as any).fields
  if (!fields) {
    throw new Error('Survey object fields not found')
  }

  // 2. Extract on-chain survey_blob_id
  const onChainBlobIdBytes = getOptionValue<number[]>(fields.survey_blob_id)
  if (!onChainBlobIdBytes) {
    throw new Error(`Survey ${surveyId} is not in decentralized storage mode (no survey_blob_id)`)
  }

  const onChainBlobId = Buffer.from(onChainBlobIdBytes).toString('utf8')
  if (onChainBlobId !== blobId) {
    throw new Error(`Blob ID mismatch: requested ${blobId}, on-chain is ${onChainBlobId}`)
  }

  // 3. Download the content
  let content: Buffer
  const isIpfs = blobId.startsWith('Qm') || blobId.startsWith('bafy')
  if (isIpfs) {
    content = await getFromIpfsMock(blobId)
  } else {
    content = await downloadFromWalrus(blobId)
  }

  // Check file size threshold (e.g., 10MB safety limit)
  if (content.length > 10 * 1024 * 1024) {
    throw new Error('Survey file size exceeds safe limit of 10MB')
  }

  // 4. Compute sha256 hash and compare to on-chain content_hash
  const computedHashBytes = crypto.createHash('sha256').update(content).digest()
  const onChainHashBytes = fields.content_hash as number[]
  if (!onChainHashBytes) {
    throw new Error('Survey object missing content_hash field')
  }

  const computedHashHex = computedHashBytes.toString('hex')
  const onChainHashHex = Buffer.from(onChainHashBytes).toString('hex')

  if (computedHashHex !== onChainHashHex) {
    throw new Error(`Integrity check failed: hash mismatch. Computed: ${computedHashHex}, expected ${onChainHashHex}`)
  }

  // 5. Cache the content
  await fs.promises.writeFile(cachePath, content)
  console.log(`[CacheManager] Successfully cached survey ${surveyId}`)
  return true
}

/**
 * Cache and validate answer content.
 * Downloads the answer content, audits the file size, and caches it locally.
 */
export async function cacheAnswerContent(
  answerBlobId: string
): Promise<Buffer> {
  if (!fs.existsSync(ANSWER_CACHE_DIR)) {
    fs.mkdirSync(ANSWER_CACHE_DIR, { recursive: true })
  }
  const cachePath = path.join(ANSWER_CACHE_DIR, answerBlobId)
  if (fs.existsSync(cachePath)) {
    return fs.promises.readFile(cachePath)
  }

  let content: Buffer
  const isIpfs = answerBlobId.startsWith('Qm') || answerBlobId.startsWith('bafy')
  if (isIpfs) {
    content = await getFromIpfsMock(answerBlobId)
  } else {
    content = await downloadFromWalrus(answerBlobId)
  }

  // Check answer file size safety limit (e.g. 50KB)
  if (content.length > 50 * 1024) {
    throw new Error(`Answer file size ${content.length} exceeds safety threshold of 50KB`)
  }

  await fs.promises.writeFile(cachePath, content)
  console.log(`[CacheManager] Successfully cached answer ${answerBlobId}`)
  return content
}

/**
 * Helper to retrieve survey cached content
 */
export async function getCachedSurveyContent(surveyId: string): Promise<Buffer | null> {
  const cachePath = path.join(SURVEY_CACHE_DIR, surveyId)
  if (fs.existsSync(cachePath)) {
    return fs.promises.readFile(cachePath)
  }
  return null
}

/**
 * Helper to retrieve answer cached content
 */
export async function getCachedAnswerContent(answerBlobId: string): Promise<Buffer | null> {
  const cachePath = path.join(ANSWER_CACHE_DIR, answerBlobId)
  if (fs.existsSync(cachePath)) {
    return fs.promises.readFile(cachePath)
  }
  return null
}

import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify'
import type { SuiClient } from '@mysten/sui/client'
import { saveToIpfsMock, getFromIpfsMock, downloadFromWalrus } from './ipfsProxy.js'
import { cacheSurveyContent } from './cacheManager.js'

interface CacheSurveyRequestBody {
  surveyId: string
  blobId: string
}

export function registerStorageRoutes(app: FastifyInstance, deps: { suiClient: SuiClient }): void {
  // Support parsing binary data uploaded by the client
  if (!app.hasContentTypeParser('application/octet-stream')) {
    app.addContentTypeParser('application/octet-stream', (request, payload, done) => {
      const chunks: Buffer[] = []
      payload.on('data', (chunk) => chunks.push(chunk))
      payload.on('end', () => {
        done(null, Buffer.concat(chunks))
      })
      payload.on('error', (err) => {
        done(err)
      })
    })
  }

  // IPFS Mock Upload
  app.post('/api/storage/ipfs/upload', async (req: FastifyRequest, reply: FastifyReply) => {
    const body = req.body as Buffer
    if (!body || body.length === 0) {
      return reply.status(400).send({ error: 'empty_body', message: 'Binary data is required' })
    }

    try {
      const cid = await saveToIpfsMock(body)
      return reply.status(200).send({ cid })
    } catch (err: any) {
      req.log.error(err)
      return reply.status(500).send({ error: 'ipfs_upload_failed', message: err.message })
    }
  })

  // IPFS Mock Download
  app.get<{ Params: { cid: string } }>('/api/storage/ipfs/download/:cid', async (req, reply) => {
    const { cid } = req.params
    if (!cid) {
      return reply.status(400).send({ error: 'invalid_cid', message: 'CID is required' })
    }

    try {
      const data = await getFromIpfsMock(cid)
      return reply
        .header('Content-Type', 'application/octet-stream')
        .status(200)
        .send(data)
    } catch (err: any) {
      req.log.error(err)
      return reply.status(404).send({ error: 'ipfs_download_failed', message: err.message })
    }
  })

  // Walrus Proxy Download
  app.get<{ Params: { blobId: string } }>('/api/storage/walrus/download/:blobId', async (req, reply) => {
    const { blobId } = req.params
    if (!blobId) {
      return reply.status(400).send({ error: 'invalid_blob_id', message: 'Blob ID is required' })
    }

    try {
      const data = await downloadFromWalrus(blobId)
      return reply
        .header('Content-Type', 'application/octet-stream')
        .status(200)
        .send(data)
    } catch (err: any) {
      req.log.error(err)
      return reply.status(502).send({ error: 'walrus_download_failed', message: err.message })
    }
  })

  // Cache survey endpoint (zero-trust verified)
  app.post('/api/cache/survey', async (req: FastifyRequest<{ Body: CacheSurveyRequestBody }>, reply: FastifyReply) => {
    const { surveyId, blobId } = req.body ?? {}
    if (!surveyId || !blobId) {
      return reply.status(400).send({ error: 'missing_params', message: 'surveyId and blobId are required' })
    }

    try {
      await cacheSurveyContent(deps.suiClient, surveyId, blobId)
      return reply.status(200).send({ success: true })
    } catch (err: any) {
      req.log.error(`[BFF] Survey cache error: ${err.message}`)
      return reply.status(400).send({ error: 'cache_failed', message: err.message })
    }
  })
}

