    })

    it('should support underscores and commas in env values', async () => {
      process.env.MIN_GAS_COMPENSATION_AMOUNT = '8_500_000'
      process.env.GAS_BUDGET_CAP_MIST = '8_500_000'
      __resetGasConfigCache()
      mockSuiClient.queryTransactionBlocks = vi.fn().mockResolvedValue({ data: [] })

      const response = await server.inject({
        method: 'GET',
        url: '/api/gas/health',
      })
      expect(response.statusCode).toBe(200)
      const resData = JSON.parse(response.payload)
      expect(resData.gasCompensationAmount).toBe('8500000')
    })

    it('should calculate dynamic compensation based on successful recent transactions', async () => {
      process.env.MIN_GAS_COMPENSATION_AMOUNT = '3000000'
      process.env.GAS_BUDGET_CAP_MIST = '3000000'
      __resetGasConfigCache()
      // Mock successful claim transactions with varying gas costs
      // Transaction 1: net gas = 4000000 + 1000000 - 500000 = 4500000 MIST
      // Transaction 2: net gas = 5000000 + 2000000 - 1000000 = 6000000 MIST (max)
      // Transaction 3 (failed): net gas = 9000000 (should be ignored)
      mockSuiClient.queryTransactionBlocks = vi.fn().mockResolvedValue({
        data: [
          {
            effects: {
              status: { status: 'success' },
              gasUsed: {
                computationCost: '4000000',
                storageCost: '1000000',
                storageRebate: '500000',
              },
            },
          },
          {
            effects: {
              status: { status: 'success' },
              gasUsed: {
                computationCost: '5000000',
                storageCost: '2000000',
                storageRebate: '1000000',
              },
            },
          },
          {
            effects: {
              status: { status: 'failure' },
              gasUsed: {
                computationCost: '8000000',
                storageCost: '2000000',
                storageRebate: '1000000',
              },
            },
          },
        ],
      })

      const response = await server.inject({
        method: 'GET',
        url: '/api/gas/health',
      })
      expect(response.statusCode).toBe(200)
      const resData = JSON.parse(response.payload)
      expect(resData.gasCompensationAmount).toBe('6000000')
    })

    it('should cache calculated dynamic gas and not call RPC repeatedly within cache window', async () => {
      process.env.MIN_GAS_COMPENSATION_AMOUNT = '3000000'
      process.env.GAS_BUDGET_CAP_MIST = '3000000'
      __resetGasConfigCache()
      mockSuiClient.queryTransactionBlocks = vi.fn().mockResolvedValue({
        data: [
          {
            effects: {
              status: { status: 'success' },
              gasUsed: {
                computationCost: '6000000',
                storageCost: '0',
                storageRebate: '0',
              },
            },
          },
        ],
      })

      // First call
      const response1 = await server.inject({
        method: 'GET',
        url: '/api/gas/health',
      })
      expect(JSON.parse(response1.payload).gasCompensationAmount).toBe('6000000')
      expect(mockSuiClient.queryTransactionBlocks).toHaveBeenCalledTimes(1)

      // Second call should hit cache and not invoke queryTransactionBlocks again
      const response2 = await server.inject({
        method: 'GET',
        url: '/api/gas/health',
      })
      expect(JSON.parse(response2.payload).gasCompensationAmount).toBe('6000000')
      expect(mockSuiClient.queryTransactionBlocks).toHaveBeenCalledTimes(1)
    })
  })
})

import { describe, it, expect, beforeEach, afterEach } from 'vitest'
import {
  loadGasConfig,
  assertGasConfig,
  healthMinBalanceMist,
  __resetGasConfigCache,
} from '../src/gas/gasConfig.js'

describe('gasConfig', () => {
  const envBackup: Record<string, string | undefined> = {}

  beforeEach(() => {
    __resetGasConfigCache()
    for (const key of [
      'GAS_BUDGET_CAP_MIST',
      'GAS_BUDGET_BUFFER_MIST',
      'MIN_GAS_COMPENSATION_AMOUNT',
      'MAX_PLATFORM_CLAIM_GAS_MIST',
      'COIN_MERGE_THRESHOLD_SUI',
      'COIN_MERGE_TRIGGER_COUNT',
    ]) {
      envBackup[key] = process.env[key]
      delete process.env[key]
    }
  })

  afterEach(() => {
    __resetGasConfigCache()
    for (const [key, val] of Object.entries(envBackup)) {
      if (val === undefined) delete process.env[key]
      else process.env[key] = val
    }
  })

  it('loads defaults aligned with production plan', () => {
    const cfg = loadGasConfig()
    expect(cfg.gasBudgetCapMist).toBe(100_000_000n)
    expect(cfg.gasBudgetBufferMist).toBe(2_000_000n)
    expect(cfg.minGasCompensationAmount).toBe(100_000_000n)
    expect(healthMinBalanceMist(cfg)).toBe(500_000_000n)
  })

  it('parses underscored env values', () => {
    process.env.GAS_BUDGET_CAP_MIST = '50_000_000'
    process.env.MIN_GAS_COMPENSATION_AMOUNT = '50_000_000'
    process.env.COIN_MERGE_THRESHOLD_SUI = '0.03'
    __resetGasConfigCache()
    const cfg = loadGasConfig()
    expect(cfg.gasBudgetCapMist).toBe(50_000_000n)
    assertGasConfig(cfg)
  })

  it('fails when platform cap exceeds budget cap', () => {
    process.env.GAS_BUDGET_CAP_MIST = '10_000_000'
    process.env.MIN_GAS_COMPENSATION_AMOUNT = '10_000_000'
    process.env.MAX_PLATFORM_CLAIM_GAS_MIST = '20_000_000'
    __resetGasConfigCache()
    expect(() => assertGasConfig(loadGasConfig())).toThrow(/MAX_PLATFORM_CLAIM_GAS_MIST/)
  })

  it('fails when budget cap exceeds min compensation', () => {
    process.env.GAS_BUDGET_CAP_MIST = '200_000_000'
    process.env.MIN_GAS_COMPENSATION_AMOUNT = '100_000_000'
    __resetGasConfigCache()
    expect(() => assertGasConfig(loadGasConfig())).toThrow(/GAS_BUDGET_CAP_MIST/)
  })
})

