  )

  const activeSigner = useActiveSigner()
  // 有效地址：連接的 Sui 錢包
  const activeAddress = account?.address

  const packageId = import.meta.env.VITE_PACKAGE_ID ?? ''
  const registryId =
    import.meta.env.VITE_NULLIFIER_REGISTRY_ID ?? import.meta.env.VITE_PASS_REGISTRY_ID ?? ''
