    title: string
    question_count: number
    registered_at_ms: number
    status: number
    claimed_count: number
    max_responses: number
  }

  const [surveyDetails, setSurveyDetails] = useState<CreatorSurveyDetail[]>([])
  const [loadingDetails, setLoadingDetails] = useState(false)

function getAnswerText(q: any, val: any, separator: string = ', '): string {
  if (val === undefined || val === null) return ''
  if (q.type === 'single_choice' && q.options_json) {
    const idx = Number(val)
    if (!isNaN(idx) && idx >= 0 && idx < q.options_json.length) {
      return q.options_json[idx]
    }
  }
  if (q.type === 'multi_choice' && q.options_json && Array.isArray(val)) {
    return val
      .map((item) => {
        const idx = Number(item)
        return idx >= 0 && idx < q.options_json!.length ? q.options_json![idx] : ''
      })
      .filter((t: string) => t !== '')
      .join(separator)
  }
  return String(val)
}

  const sortedSurveyDetails = useMemo(() => {
    return [...surveyDetails].sort((a, b) => {
      const aActive = a.status === 0 ? 0 : 1
      const bActive = b.status === 0 ? 0 : 1
      if (aActive !== bActive) return aActive - bActive
      return b.registered_at_ms - a.registered_at_ms
    })
  }, [surveyDetails])

  useEffect(() => {
    if (!vaultId) return
    let cancelled = false
    setSurveyResolveFailed(false)
    setDetailSurveyTitle(null)
    async function resolveSurvey() {
      if (
        !suiClient ||
        typeof suiClient.queryEvents !== 'function' ||
        typeof suiClient.getObject !== 'function'
      )
        return
      try {
        console.log('[DashboardPage] Querying on-chain registry events to resolve survey_id...')
        let cursor: any = null
        let hit: any = null
        let pageCount = 0
        do {
          const res = await suiClient.queryEvents({
            query: {
              MoveEventType: `${getPackageId()}::survey_registry::SurveyRegistered`,
            },
            cursor,
            limit: 50,
            order: 'descending',
          })
          hit = res.data.find(
            (e: any) =>
              e.parsedJson &&
              normalizeSuiId(e.parsedJson.vault_id) === normalizeSuiId(vaultId ?? '')
          )
          if (hit) break
          cursor = res.hasNextPage ? res.nextCursor : null
          pageCount++
        } while (cursor && pageCount < 10)

        if (hit && !cancelled) {
          const sId = hit.parsedJson.survey_id
          setSurveyId((prev) => (prev === sId ? prev : sId))
          const obj = await suiClient.getObject({
            id: sId,
            options: { showContent: true },
          })
          if (obj.data && !cancelled) {
            setSurveyData((prev: any) =>
              JSON.stringify(prev) === JSON.stringify(obj.data) ? prev : obj.data
            )
          }
        } else if (!cancelled) {
          setSurveyResolveFailed(true)
        }
      } catch (err) {
        console.error('[DashboardPage] Failed to resolve survey:', err)
        if (!cancelled) setSurveyResolveFailed(true)
      }
    }
    void resolveSurvey()
    return () => {
      cancelled = true
    }
  }, [vaultId, suiClient])

  useEffect(() => {
    if (!account?.address || !getPackageId()) return
    if (!suiClient || typeof (suiClient as unknown as SuiClient).queryEvents !== 'function') return
    let cancelled = false
    async function loadCreatorSurveys() {
      try {
        let cursor: any = null
        let mine: Array<{
          vault_id: string
          survey_id: string
          question_count: number
          registered_at_ms: number
        }> = []
        let pageCount = 0
        do {
          const res = await (suiClient as unknown as SuiClient).queryEvents({
            query: {
              MoveEventType: `${getPackageId()}::survey_registry::SurveyRegistered`,
            },
            cursor,
            limit: 50,
            order: 'descending',
          })
          const pageMine = (res.data as any[])
            .filter(
              (e: any) =>
                normalizeSuiId(e.parsedJson?.creator || '') ===
                normalizeSuiId(account?.address || '')
            )
            .map((e: any) => ({
              vault_id: e.parsedJson.vault_id as string,
              survey_id: e.parsedJson.survey_id as string,
              question_count: e.parsedJson.question_count ? Number(e.parsedJson.question_count) : 0,
              registered_at_ms: e.parsedJson.registered_at_ms
                ? Number(e.parsedJson.registered_at_ms)
                : 0,
            }))
          mine = [...mine, ...pageMine]
          cursor = res.hasNextPage ? res.nextCursor : null
          pageCount++
        } while (cursor && pageCount < 10)

        // Deduplicate surveys by vault_id to prevent redundant requests and displays
        const seen = new Set<string>()
        const uniqueMine: typeof mine = []
        for (const item of mine) {
          const normId = normalizeSuiId(item.vault_id)
          if (!seen.has(normId)) {
            seen.add(normId)
            uniqueMine.push(item)
          }
        }
        mine = uniqueMine

        if (!cancelled) {
          setCreatorSurveys((prev) => {
            const isIdentical =
              prev.length === mine.length &&
              prev.every((s, idx) => {
                const m = mine[idx]
                return (
                  s.vault_id === m.vault_id &&
                  s.survey_id === m.survey_id &&
                  s.question_count === m.question_count &&
                  s.registered_at_ms === m.registered_at_ms
                )
              })
            return isIdentical ? prev : mine
          })
        }
      } catch (err) {
        console.error('[DashboardPage] Failed to load creator surveys:', err)
      }
    }
    void loadCreatorSurveys()
    return () => {
      cancelled = true
    }
  }, [account?.address, suiClient])

  useEffect(() => {
    if (creatorSurveys.length === 0 || !suiClient) {
      setSurveyDetails([])
      return
    }
    let cancelled = false
    setLoadingDetails(true)

    async function fetchDetails() {
      try {
        const surveyIds = creatorSurveys.map((s) => s.survey_id)
        const vaultIds = creatorSurveys.map((s) => s.vault_id)

        const surveyObjs = await suiClient.multiGetObjects({
          ids: surveyIds,
          options: { showContent: true },
        })

        const vaultObjs = await suiClient.multiGetObjects({
          ids: vaultIds,
          options: { showContent: true },
        })

        const details = await Promise.all(
          creatorSurveys.map(async (s, i) => {
            const surveyObj = surveyObjs[i]
            const vaultObj = vaultObjs[i]

            let title = `${t.surveyTitlePrefix}${s.survey_id.slice(0, 6)}`
            let status = 0
            let claimed_count = 0
            let max_responses = 0

            const isSurveyDeleted = !surveyObj || !surveyObj.data || !!surveyObj.error
            const isVaultDeleted = !vaultObj || !vaultObj.data || !!vaultObj.error

            if (isSurveyDeleted && isVaultDeleted) {
              status = 2 // 已銷毀
            } else {
              const sFields = (surveyObj?.data?.content as any)?.fields
              if (sFields) {
                status = sFields.status !== undefined ? Number(sFields.status) : 0

                const surveyBlobIdBytes = getOptionVec(sFields.survey_blob_id)
                let rawContent: Uint8Array | null = null

                if (surveyBlobIdBytes) {
                  try {
                    const blobId = new TextDecoder().decode(surveyBlobIdBytes)
                    rawContent = await downloadFromDecentralizedStorage(blobId)
                  } catch (e) {
                    console.warn('Failed to download decentralized storage title for list item:', s.survey_id, e)
                  }
                } else {
                  rawContent = sFields.encrypted_content
                    ? normalizeBytes(sFields.encrypted_content)
                    : null
                }

                if (rawContent) {
                  try {
                    const parsedBlob = parseContentBlob(rawContent)
                    if (parsedBlob.version === 0x00) {
                      const parsed = parseFullSurveyMarkdown(parsedBlob.markdown || '')
                      if (parsed.ok && parsed.data.title) {
                        title = parsed.data.title
                      }
                    } else {
                      const savedKey = getSavedContentKey(s.vault_id)
                      if (savedKey) {
                        const keyBytes = base64urlToBytes(savedKey.slice(1))
                        const dec = await decryptSurveyContent(rawContent, keyBytes)
                        const parsed = parseFullSurveyMarkdown(dec.markdown)
                        if (parsed.ok && parsed.data.title) {
                          title = parsed.data.title
                        }
                      } else if (parsedBlob.version === -1 && rawContent.length >= 32) {
                        const md = new TextDecoder().decode(rawContent.slice(32))
                        const parsed = parseFullSurveyMarkdown(md)
                        if (parsed.ok && parsed.data.title) {
                          title = parsed.data.title
                        }
                      }
                    }
                  } catch (e) {
                    console.warn('Failed to decrypt title for list item:', s.survey_id, e)
                  }
                }
              }

              const vFields = (vaultObj?.data?.content as any)?.fields
              if (vFields) {
                claimed_count = vFields.claimed_count !== undefined ? Number(vFields.claimed_count) : 0
                max_responses = vFields.max_responses !== undefined ? Number(vFields.max_responses) : 0
                if (vFields.status !== undefined) {
                  status = Number(vFields.status)
                }
              }
            }

            return {
              vault_id: s.vault_id,
              survey_id: s.survey_id,
              title,
              question_count: s.question_count,
              registered_at_ms: s.registered_at_ms,
              status,
              claimed_count,
              max_responses,
            }
          })
        )

        if (!cancelled) {
          setSurveyDetails((prev) => {
            const isIdentical =
              prev.length === details.length &&
              prev.every((s, idx) => {
                const d = details[idx]
                return (
                  s.vault_id === d.vault_id &&
                  s.survey_id === d.survey_id &&
                  s.title === d.title &&
                  s.question_count === d.question_count &&
                  s.registered_at_ms === d.registered_at_ms &&
                  s.status === d.status &&
                  s.claimed_count === d.claimed_count &&
                  s.max_responses === d.max_responses
                )
              })
            return isIdentical ? prev : details
          })
          setLoadingDetails(false)
        }
      } catch (err) {
        console.error('[DashboardPage] Failed to fetch survey details:', err)
        if (!cancelled) {
          setLoadingDetails(false)
        }
      }
    }

    void fetchDetails()
    return () => {
      cancelled = true
    }
  }, [creatorSurveys, suiClient])

  useEffect(() => {
    if (!surveyData) return
    const fields = surveyData.content?.fields as any
    if (!fields) return

    let hashBytes = fields.schema_hash ? normalizeBytes(fields.schema_hash) : new Uint8Array(0)
    const newHash = bytesToHex(hashBytes)
    setSchemaHashStr((prev) => (prev === newHash ? prev : newHash))

    // Determine contentKey (already computed via useMemo at the top)

    function applyMeta(data: FullSurveyData) {
      const next = {
        allowedSources: data.allowedSources,
        allowedNftType: data.allowedNftType || null,
        repeatReward: data.repeatReward,
        repeatMaxTimes: data.repeatMaxTimes,
        perResponse: data.perResponse,
        deadlineMs: data.deadlineMs,
        encryptAnswers: data.encryptAnswers,
      }
      setSurveyMeta((prev) =>
        prev &&
          JSON.stringify(prev.allowedSources) === JSON.stringify(next.allowedSources) &&
          prev.allowedNftType === next.allowedNftType &&
          prev.repeatReward === next.repeatReward &&
          prev.repeatMaxTimes === next.repeatMaxTimes &&
          prev.perResponse === next.perResponse &&
          prev.deadlineMs === next.deadlineMs &&
          prev.encryptAnswers === next.encryptAnswers
          ? prev
          : next
      )
    }

    async function loadQuestions() {
      try {
        const surveyBlobIdBytes = getOptionVec(fields.survey_blob_id)
        let rawContent: Uint8Array

        if (surveyBlobIdBytes) {
          const blobId = new TextDecoder().decode(surveyBlobIdBytes)
          rawContent = await downloadFromDecentralizedStorage(blobId)
        } else {
          const encryptedContentBytes = getOptionVec(fields.encrypted_content)
          if (!encryptedContentBytes) {
            throw new Error('Survey content data corrupted')
          }
          rawContent = encryptedContentBytes
        }

        const parsedBlob = parseContentBlob(rawContent)
        if (parsedBlob.version === 0x00) {
          const parsed = parseFullSurveyMarkdown(parsedBlob.markdown || '')
          if (parsed.ok) {
            setQuestions((prev) => {
              const sanitized = sanitizeQuestionIds(parsed.data.questions)
              return JSON.stringify(prev) === JSON.stringify(sanitized)
                ? prev
                : sanitized
            })
            applyMeta(parsed.data)
            if (parsed.data.title) {
              setDetailSurveyTitle(parsed.data.title)
            }
          }
        } else if (parsedBlob.version === 0x01 || (parsedBlob.version === -1 && contentKeyB64)) {
          if (contentKeyB64) {
            const keyBytes = base64urlToBytes(contentKeyB64)
            const dec = await decryptSurveyContent(rawContent, keyBytes)
            const parsed = parseFullSurveyMarkdown(dec.markdown)
            if (parsed.ok) {
              setQuestions((prev) => {
                const sanitized = sanitizeQuestionIds(parsed.data.questions)
                return JSON.stringify(prev) === JSON.stringify(sanitized)
                  ? prev
                  : sanitized
              })
              applyMeta(parsed.data)
              if (parsed.data.title) {
                setDetailSurveyTitle(parsed.data.title)
              }
            }
          }
        } else if (parsedBlob.version === -1 && rawContent.length >= 32) {
          const md = new TextDecoder().decode(rawContent.slice(32))
          const parsed = parseFullSurveyMarkdown(md)
          if (parsed.ok) {
            setQuestions((prev) => {
              const sanitized = sanitizeQuestionIds(parsed.data.questions)
              return JSON.stringify(prev) === JSON.stringify(sanitized)
                ? prev
                : sanitized
            })
            applyMeta(parsed.data)
            if (parsed.data.title) {
              setDetailSurveyTitle(parsed.data.title)
            }
          }
        }
      } catch (err) {
        console.error('[DashboardPage] Failed to decrypt/parse survey questions:', err)
      }
    }

    void loadQuestions()
  }, [surveyData, vaultId, location.hash])

  // ── 公開問卷自動解析 ──────────────────────────────────────────────────────
  useEffect(() => {
    if (surveyMeta?.encryptAnswers === false && questions && events && schemaHashStr) {
      try {
        const { responses } = decodeAllPlainResponses(
          events,
          questions,
          schemaHashStr
        )
        const s = aggregateStats(responses, events.length)
        setStats(s)
        setDecryptedResponses(responses)
        setDecryptStatus('done')
      } catch (err) {
        console.error('[DashboardPage] Failed to decode plain responses:', err)
        setDecryptError(err instanceof Error ? err.message : 'Failed to decode responses')
        setDecryptStatus('error')
      }
    }
  }, [surveyMeta?.encryptAnswers, questions, events, schemaHashStr])

  // ── 解密 ──────────────────────────────────────────────────────────────────
  const [stats, setStats] = useState<DashboardStats | null>(null)
  const [decryptedResponses, setDecryptedResponses] = useState<DecryptedResponse[] | null>(null)
  /** 'all' = 顯示所有提交（含同地址多筆）；'latest' = 同地址僅顯示最新一次。CSV 永遠匯出全部。 */
  const [responseViewMode, setResponseViewMode] = useState<'all' | 'latest'>('all')
  const [decryptStatus, setDecryptStatus] = useState<
    'idle' | 'signing' | 'decrypting' | 'done' | 'error'
  >('idle')
  const [decryptError, setDecryptError] = useState<string | null>(null)

  const isCreator =
    !!account && !!vault && normalizeSuiId(account.address) === normalizeSuiId(vault.creator)
  const isActive = vault?.status === 0

  const isAccessDenied = useMemo(() => {
    if (!vaultId || isWalletResolving || !vault) return false
    return !isCreator
  }, [vaultId, isWalletResolving, vault, isCreator])

  useEffect(() => {
    if (!isAccessDenied) return
    if (surveyId) {
      const hash = contentKeyB64 ? `#${contentKeyB64}` : ''
      navigate(`/s/${surveyId}${hash}`, { replace: true })
      return
    }
    if (surveyResolveFailed) {
      navigate('/', { replace: true })
    }
  }, [isAccessDenied, surveyId, surveyResolveFailed, contentKeyB64, navigate])

  async function handleDecrypt() {
    if (!isCreator || decryptStatus === 'signing' || decryptStatus === 'decrypting') return
    setDecryptError(null)
    setDecryptStatus('signing')
    try {
      const message = new TextEncoder().encode(KEY_DERIVE_MSG)
      const { signature } = await signPersonalMessageAsync({ message })
      const sigBytes = base64ToBytes(signature)
      
      const fields = surveyData?.content?.fields
      let salt: Uint8Array | null = null
      if (fields?.creator_pub_key) {
        const creatorPubKeyBytes = normalizeBytes(fields.creator_pub_key)
        try {
          const parsed = parseCreatorPubKey(creatorPubKeyBytes)
          salt = parsed.salt
        } catch (e) {
          console.warn('[DashboardPage] Failed to parse creator_pub_key for salt:', e)
        }
      }

      const kp = await deriveCreatorKeyPair(sigBytes, salt)
      setDecryptStatus('decrypting')
      const { responses } = await decryptAllResponses(
        events,
        kp,
        questions || [],
        schemaHashStr || ''
      )
      const s = aggregateStats(responses, events.length)
      setStats(s)
      setDecryptedResponses(responses)
      setDecryptStatus('done')
    } catch (err) {
      setDecryptError(err instanceof Error ? err.message : t.errDecryptFailed)
      setDecryptStatus('error')
    }
  }

  function handleDownloadCsv() {
    if (!decryptedResponses || !questions) return

    // Prepare headers
    const headers = [
      'Respondent',
      'Submitted Time',
      ...questions.map((q) => (q.prompt ? `${q.id}: ${q.prompt}` : q.id)),
    ]

    // Prepare rows
    const rows = decryptedResponses.map((resp) => {
      const timeStr = new Date(resp.claimed_at_ms).toLocaleString('zh-TW')
      const rowAnswers = questions.map((q) => {
        const val = resp.answers[q.id]
        return getAnswerText(q, val, '; ')
      })
      return [resp.respondent, timeStr, ...rowAnswers]
    })

    // Convert to CSV string, handling quotes and escaping
    const escapeCsv = (str: string) => {
      const escaped = str.replace(/"/g, '""')
      if (
        escaped.includes(',') ||
        escaped.includes('"') ||
        escaped.includes('\n') ||
        escaped.includes('\r')
      ) {
        return `"${escaped}"`
      }
      return escaped
    }

    const csvContent = [
      headers.map(escapeCsv).join(','),
      ...rows.map((row) => row.map(escapeCsv).join(',')),
    ].join('\r\n')

    // Download file with UTF-8 BOM
    const blob = new Blob([new Uint8Array([0xef, 0xbb, 0xbf]), csvContent], {
      type: 'text/csv;charset=utf-8;',
    })
    const url = URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.href = url
    link.setAttribute('download', `survey_responses_${vaultId || 'export'}.csv`)
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
  }

  function handleDownloadQr() {
    if (!qrCanvasRef.current) return
    const url = qrCanvasRef.current.toDataURL('image/png')
    const link = document.createElement('a')
    link.href = url
    link.download = `survey_qrcode_${vaultId || 'export'}.png`
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
  }

  // contentKey hash 是給受訪者用的；creator 自己用簽名衍生金鑰
  // 但保留 base64urlToBytes import 以利 v2 收件人模式擴充
  void contentKeyB64
  void base64urlToBytes

  // ── 結束活動 ──────────────────────────────────────────────────────────────
  const [closeStatus, setCloseStatus] = useState<'idle' | 'signing' | 'success' | 'error'>('idle')
  const [closeError, setCloseError] = useState<string | null>(null)
  const [purgeStatus, setPurgeStatus] = useState<'idle' | 'confirm' | 'signing' | 'success' | 'error'>('idle')
  const [purgeError, setPurgeError] = useState<string | null>(null)
  const [extendStatus, setExtendStatus] = useState<'idle' | 'signing' | 'success' | 'error'>('idle')
  const [extendError, setExtendError] = useState<string | null>(null)

  const walrusBlobObjectId = useMemo(() => {
    const fields = surveyData?.content?.fields as Record<string, unknown> | undefined
    if (!fields) return null
    return getOptionId(fields.survey_blob_object_id)
  }, [surveyData])

  const isWalrusSurvey = useMemo(() => {
    const fields = surveyData?.content?.fields as Record<string, unknown> | undefined
    if (!fields) return false
    return !!getOptionVec(fields.survey_blob_id)
  }, [surveyData])

  const walrusCoverageTargetMs = useMemo(() => {
    if (!surveyMeta) return 0
    const closedAt = vault?.closed_at_ms ? Number(vault.closed_at_ms) : 0
    if (closedAt > 0) {
      const grace = vault?.purge_grace_ms ? Number(vault.purge_grace_ms) : Number(PURGE_GRACE_MS)
      return closedAt + grace
    }
    return surveyMeta.deadlineMs + Number(PURGE_GRACE_MS)
  }, [surveyMeta, vault])

  const canClose = isActive && closeStatus !== 'signing' && closeStatus !== 'success'

  function handleClose() {
    if (!vaultId || !canClose) return
    setCloseError(null)
    setCloseStatus('signing')
    let tx
    try {
      tx = buildClosePtb({ packageId: getPackageId(), vaultId })
    } catch (err) {
      setCloseError(err instanceof Error ? err.message : t.errPtbBuildFailed)
      setCloseStatus('error')
      return
    }
    signAndExecute(
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      { transaction: tx as any },
      {
        onSuccess: () => {
          setCloseStatus('success')
          void refetchVault()
        },
        onError: (err) => {
          setCloseError(err.message)
          setCloseStatus('error')
        },
      }
    )
  }

  // Creator-initiated immediate purge of a closed survey (bypasses the grace
  // window — the contract permits this only for the creator on a closed vault).
  async function handleExtendWalrus() {
    if (!walrusBlobObjectId || !account?.address || extendStatus === 'signing') return
    setExtendError(null)
    setExtendStatus('signing')
    try {
      const tx = await buildExtendWalrusBlobTx(suiClient as unknown as SuiClient, {
        blobObjectId: walrusBlobObjectId,
        coverageTargetMs: walrusCoverageTargetMs,
        sender: account.address,
      })
      signAndExecute(
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        { transaction: tx as any },
        {
          onSuccess: () => {
            setExtendStatus('success')
          },
          onError: (err) => {
            setExtendError(err.message)
            setExtendStatus('error')
          },
        }
      )
    } catch (err) {
      const msg = err instanceof Error ? err.message : t.errPtbBuildFailed
      if (msg === 'walrus_extend_no_wal') {
        setExtendError(t.walrusExtendNoWal)
      } else if (msg === 'walrus_extend_insufficient_wal') {
        setExtendError(t.walrusExtendInsufficientWal)
      } else if (msg === 'walrus_extend_not_needed') {
        setExtendError(t.walrusExtendNotNeeded)
      } else {
        setExtendError(msg)
      }
      setExtendStatus('error')
    }
  }

  function handlePurge() {
    if (!vaultId || !surveyId || isActive) return
    const registryId = import.meta.env.VITE_SURVEY_REGISTRY_ID as string | undefined
    if (!registryId) {
      setPurgeError(t.errNoRegistry)
      setPurgeStatus('error')
      return
    }
    setPurgeError(null)
    setPurgeStatus('signing')
    let tx
    try {
      tx = buildPurgePtb({ packageId: getPackageId(), registryId, surveyId, vaultId })
    } catch (err) {
      setPurgeError(err instanceof Error ? err.message : t.errPtbBuildFailed)
      setPurgeStatus('error')
      return
    }
    signAndExecute(
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      { transaction: tx as any },
      {
        onSuccess: () => {
          setPurgeStatus('success')
          setTimeout(() => navigate('/dashboard'), 1200)
        },
        onError: (err) => {
          setPurgeError(err.message)
          setPurgeStatus('error')
        },
      }
    )
  }

  // ── 顯示 ──────────────────────────────────────────────────────────────────
  const displayBalanceSsr = vault ? formatCompactCoin(vault.balance) : null
  const displayGasBalance = vault ? formatCompactCoin(vault.gas_balance) : null

  // QR Code 用的 fullUrl 與繪製 effect 必須宣告在任何 early return 之前，
  // 否則 isAccessDenied 在同一 mount 內由 false 翻 true 時會違反 Rules of Hooks。
  const fullUrl = surveyId
    ? `${window.location.origin}/s/${surveyId}${contentKeyB64 ? `#${contentKeyB64}` : ''}`
    : ''

  useEffect(() => {
    if (showQrModal && qrCanvasRef.current && fullUrl) {
      QRCode.toCanvas(
        qrCanvasRef.current,
        fullUrl,
        {
          width: 240,
          margin: 2,
          color: {
            dark: '#30305f',
            light: '#ffffff',
          },
        },
        (error) => {
          if (error) console.error('[DashboardPage] Failed to generate QR Code:', error)
        }
      )
    }
  }, [showQrModal, fullUrl])

  if (vaultId && isAccessDenied) {
    return (
      <main className="min-h-screen p-4 sm:p-8 max-w-2xl mx-auto flex items-center justify-center">
        <div className="bg-white dark:bg-neutral-900 rounded-3xl border border-slate-100 dark:border-neutral-800 shadow-xl p-8 text-center space-y-4 animate-fadeIn w-full">
          <div className="inline-block animate-spin rounded-full h-8 w-8 border-4 border-blue-500 border-t-transparent"></div>
          <p aria-live="polite" className="text-sm text-slate-500 dark:text-neutral-400 font-medium">
            {t.redirectingToSurvey}
          </p>
        </div>
      </main>
    )
  }

  if (!vaultId) {
    return (
      <main className="min-h-screen p-4 sm:p-8 max-w-4xl mx-auto text-slate-800 dark:text-neutral-300">
        <div className="flex flex-col sm:flex-row sm:items-center gap-3 mb-6">
          <div className="flex-1">
            <h1 className="text-h1">
              {t.dashboardTitle}
            </h1>
            <p className="text-muted mt-1">
              {t.dashboardDescPrefix}<strong>{t.dashboardDescStrong}</strong>{t.dashboardDescSuffix}
            </p>
            <p className="text-muted mt-2">{t.listPurgeReminder(PURGE_GRACE_DAYS)}</p>
          </div>
          {account && !loadingDetails && surveyDetails.length > 0 && (
            <div className="flex gap-3 self-start sm:self-auto items-center">
              <Link
                to="/create"
                className="whitespace-nowrap btn-primary"
              >
                {t.btnCreateSurvey}
              </Link>
            </div>
          )}
        </div>

        {!account ? (
          <div className="bg-white dark:bg-neutral-900 border border-neutral-200 dark:border-neutral-800 rounded-3xl p-8 text-center shadow-sm max-w-md mx-auto my-12 transition-colors">
            <h2 className="text-h2 mb-2">
              {t.walletRequired}
            </h2>
            <p className="text-muted mb-6 leading-relaxed">
              {t.walletRequiredDesc}
            </p>
            <div className="flex justify-center">
              <ConnectButton />
            </div>
          </div>
        ) : loadingDetails ? (
          <div className="text-center py-12">
            <div className="inline-block animate-spin rounded-full h-8 w-8 border-4 border-blue-700 border-t-transparent mb-4"></div>
            <p className="text-muted">
              {t.loadingSurveys}
            </p>
          </div>
        ) : surveyDetails.length === 0 ? (
          <div className="bg-white dark:bg-neutral-900 border border-neutral-100 dark:border-neutral-800 rounded-3xl p-10 text-center shadow-sm max-w-lg mx-auto my-8 transition-colors">
            <h3 className="text-h3 mb-2">
              {t.noSurveys}
            </h3>
            <p className="text-muted mb-6 leading-relaxed">
              {t.noSurveysDesc}
            </p>
            <div className="flex gap-3 justify-center items-center">
              <Link
                to="/create"
                className="btn-primary inline-flex items-center gap-1"
              >
                {t.createFirstSurvey}
              </Link>
            </div>
          </div>
        ) : (
          <div className="flex flex-col gap-[3px]">
            {/* 標頭卡片 */}
            <div
              className="hidden sm:grid grid-cols-12 gap-4 px-6 py-3.5 bg-neutral-100 dark:bg-neutral-800 rounded-xs 
            text-sm font-normal text-neutral-700 dark:text-neutral-300 uppercase tracking-wider transition-colors"
            >
              <div className="col-span-5">{t.colTitle}</div>
              <div className="col-span-3">{t.colCreatedAt}</div>
              <div className="col-span-2">{t.colProgress}</div>
              <div className="col-span-2 text-right">{t.colStatus}</div>
            </div>

            {/* 問卷卡片列表 */}
            {sortedSurveyDetails.map((s) => (
              <div
                key={s.vault_id}
                onClick={() =>
                  navigate(`/dashboard/${s.vault_id}${getSavedContentKey(s.vault_id)}`)
                }
                className="cursor-pointer bg-white dark:bg-neutral-900 rounded-sm px-6 py-4 flex flex-col 
                gap-3 sm:grid sm:grid-cols-12 sm:gap-4 sm:items-center 
                hover:bg-neutral-100/90 dark:hover:bg-neutral-800/60 transition-colors duration-150"
              >
                {/* 欄位 1: 問卷標題 */}
                <div className="sm:col-span-5 min-w-0" title={s.title}>
                  <span className="font-mono text-slate-900 dark:text-neutral-100 block truncate">
                    {s.title}
                  </span>
                  <div className="font-mono text-xxs text-slate-500 dark:text-neutral-500 mt-1 truncate" title={s.vault_id}>
                    Vault: {formatVaultId(s.vault_id)}
                  </div>
                </div>

                {/* 欄位 2: 建立日期 */}
                <div className="sm:col-span-3 text-sm text-slate-600 dark:text-neutral-400 flex items-center justify-between sm:block">
                  <span className="sm:hidden text-xs font-normal text-slate-600 dark:text-neutral-400 uppercase">
                    {t.mobileCreatedAt}
                  </span>
                  <span>{s.registered_at_ms ? formatDateTime(s.registered_at_ms) : '—'}</span>
                </div>

                {/* 欄位 3: 填答進度 */}
                <div className="sm:col-span-2 flex items-center justify-between sm:justify-start gap-2">
                  <span className="sm:hidden text-xs font-normal text-slate-600 dark:text-neutral-400 uppercase">
                    {t.mobileProgress}
                  </span>
                  <div className="flex items-center gap-2">
                    <span className="font-mono text-sm text-slate-800 dark:text-neutral-300 whitespace-nowrap">
                      {s.claimed_count} / {s.max_responses}
                    </span>
                    <div className="w-16 bg-slate-100 dark:bg-neutral-800 rounded-full h-1.5 overflow-hidden flex-shrink-0">
                      <div
                        className="bg-blue-600 h-1.5 rounded-full"
                        style={{
                          width: `${Math.min(100, (s.claimed_count / (s.max_responses || 1)) * 100)}%`,
                        }}
                      />
                    </div>
                  </div>
                </div>

                {/* 欄位 4: 狀態 */}
                <div className="sm:col-span-2 sm:text-right flex items-center justify-between sm:justify-end gap-2">
                  <span className="sm:hidden text-xs font-normal text-slate-600 dark:text-neutral-400 uppercase">
                    {t.mobileStatus}
                  </span>
                  {(() => {
                    const state = deriveSurveyState(s.status, s.claimed_count, s.max_responses)
                    const styles =
                      state === 'active'
                        ? 'bg-emerald-50 text-emerald-700 dark:bg-emerald-950/30 dark:text-emerald-400 border-emerald-200/50 dark:border-emerald-800/30'
                        : state === 'full'
                          ? 'bg-amber-50 text-amber-700 dark:bg-amber-950/30 dark:text-amber-400 border-amber-200/50 dark:border-amber-800/30'
                          : state === 'purged'
                            ? 'bg-neutral-100 text-neutral-600 dark:bg-neutral-800 dark:text-neutral-400 border-neutral-200/50 dark:border-neutral-700/30'
                            : 'bg-red-50 text-red-700 dark:bg-red-950/30 dark:text-red-400 border-red-200/50 dark:border-red-800/30'
                    const label =
                      state === 'active'
                        ? t.statusActive
                        : state === 'full'
                          ? t.statusFull
                          : state === 'purged'
                            ? t.statusPurged
                            : t.statusClosed
                    return (
                      <span
                        className={`inline-flex items-center shrink-0 whitespace-nowrap px-2.5 py-0.5 rounded-full text-xs font-normal border ${styles}`}
                      >
                        {label}
                      </span>
                    )
                  })()}
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
    )
  }

  const currentSurvey = surveyDetails.find((s) => s.vault_id === vaultId)
  const surveyTitle = detailSurveyTitle || (currentSurvey ? currentSurvey.title : loadingDetails ? t.loadingShort : t.surveyDefault)

  return (
    <main className="min-h-screen p-4 sm:p-8 max-w-4xl mx-auto text-slate-800 dark:text-neutral-300">
      <div className="mb-4">
        <Link
          to="/dashboard"
          className="inline-flex items-center gap-1.5 text-sm text-blue-700 hover:text-blue-800 dark:text-blue-400 dark:hover:text-blue-300 hover:underline font-normal"
        >
          {t.backToList}
        </Link>
      </div>

      <h1 className="text-h1 mb-1 overflow-x-auto whitespace-nowrap pb-1.5">{surveyTitle}</h1>
      <h2 className="text-h3 text-muted mb-6">
        {t.subtitle}
      </h2>

      {surveyId && vault && (
        <section className="mb-6 bg-blue-100 dark:bg-blue-900/20 border border-transparent dark:border-blue-900/30 rounded-xl p-4 flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-3">
            <a
              href={`/s/${surveyId}${contentKeyB64 ? `#${contentKeyB64}` : ''}`}
              target="_blank"
              rel="noopener noreferrer"
              className="text-sm text-blue-700 hover:text-blue-800 dark:text-blue-400 dark:hover:text-blue-300 hover:underline font-normal cursor-pointer"
              aria-label={t.claimLinkAria}
            >
              {t.claimLink}
            </a>
            <button
              type="button"
              onClick={() => {
                void navigator.clipboard.writeText(fullUrl)
                setCopied(true)
                setTimeout(() => setCopied(false), 2000)
              }}
              className={`px-3 py-1.5 text-sm rounded-xl font-normal transition-all ${copied ? 'bg-emerald-700 text-white' : 'bg-blue-700 hover:bg-blue-800 text-white dark:bg-blue-800 dark:hover:bg-blue-600'
                }`}
            >
              {copied ? t.copied : t.copy}
            </button>
            <button
              type="button"
              onClick={() => setShowQrModal(true)}
              className="btn-secondary px-3 py-1.5 text-sm"
              aria-label={t.qrCodeAria}
            >
              QR Code
            </button>
          </div>
          {surveyMeta?.encryptAnswers === false && (
            <div className="flex items-center gap-3 border-t sm:border-t-0 sm:border-l pt-3 sm:pt-0 sm:pl-3 border-slate-200 dark:border-neutral-800 sm:ml-auto">
              <Link
                to={`/results/${vaultId}`}
                target="_blank"
                rel="noopener noreferrer"
                className="px-3 py-1.5 text-sm rounded-xl font-normal transition-all bg-emerald-700 hover:bg-emerald-800 text-white dark:bg-emerald-800 dark:hover:bg-emerald-700 cursor-pointer"
              >
                {t.publicResultsLink}
              </Link>
            </div>
          )}
        </section>
      )}

      {eventsState.kind === 'error' && (
        <div role="alert" className="alert-error mb-4">
          <span>{eventsState.error}</span>
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
        <div className="bg-slate-100 dark:bg-neutral-900 rounded p-4 transition-colors">
          <p className="text-sm text-slate-600 dark:text-neutral-400">{t.statResponseCount}</p>
          <p className="text-2xl font-mono font-normal text-slate-900 dark:text-neutral-100 text-right mt-1 truncate" aria-label="response-count" title={String(responseCount)}>
            {formatCompactInt(responseCount)}
          </p>
        </div>
        <div className="bg-slate-100 dark:bg-neutral-900 rounded p-4 transition-colors">
          <p className="text-sm text-slate-600 dark:text-neutral-400">{t.statResponseProgress}</p>
          <p className="text-2xl font-mono font-normal text-slate-900 dark:text-neutral-100 text-right mt-1 truncate" aria-label="received-over-max" title={vault ? `${responseCount} / ${vault.max_responses}` : undefined}>
            {formatCompactInt(responseCount)} / {vault ? formatCompactInt(vault.max_responses) : '—'}
          </p>
        </div>
        <div className="bg-slate-100 dark:bg-neutral-900 rounded p-4 transition-colors">
          <p className="text-sm text-slate-600 dark:text-neutral-400">{t.statVaultBalance}</p>
          <p className="text-2xl font-mono font-normal text-slate-900 dark:text-neutral-100 text-right mt-1 truncate" aria-label="vault-balance" title={vault ? `${formatFullPrecision(vault.balance)} SSR` : undefined}>
            {displayBalanceSsr !== null ? displayBalanceSsr : isPendingVault ? t.checkingShort : '—'}
          </p>
        </div>
        <div className="bg-slate-100 dark:bg-neutral-900 rounded p-4 transition-colors">
          <p className="text-sm text-slate-600 dark:text-neutral-400">{t.statGasBalance}</p>
          <p className="text-2xl font-mono font-normal text-slate-900 dark:text-neutral-100 text-right mt-1 truncate" aria-label="gas-balance" title={vault ? `${formatFullPrecision(vault.gas_balance)} SUI` : undefined}>
            {displayGasBalance !== null ? displayGasBalance : isPendingVault ? t.checkingShort : '—'}
          </p>
        </div>
      </div>

      {/* ── 問卷資訊整合區塊 ────────────────────────────────────────────── */}
      <section className="mb-6 bg-slate-100 border border-slate-300 dark:bg-neutral-950 dark:border-neutral-800 rounded-xl p-4">
        <dl className="grid grid-cols-1 md:grid-cols-[180px_1fr] gap-y-3 md:gap-y-2 gap-x-4 text-sm">
          <dt className="text-sm font-normal text-slate-600 dark:text-neutral-300 md:self-center break-words">{t.vaultLabel}</dt>
          <dd className="font-mono break-all text-body">{vaultId}</dd>

          <dt className="text-sm font-normal text-slate-600 dark:text-neutral-300 md:self-center break-words">{t.statusLabel.replace(':', '')}</dt>
          <dd className="text-body">
            {isPendingVault ? (
              t.checking
            ) : !vault ? (
              <span className="text-slate-600 dark:text-neutral-400">{t.statusPurged}</span>
            ) : (() => {
              const state = deriveSurveyState(
                vault.status,
                Number(vault.claimed_count),
                Number(vault.max_responses)
              )
              if (state === 'active') {
                return <span className="text-emerald-700 dark:text-emerald-400">{t.statusActive}</span>
              }
              if (state === 'full') {
                return <span className="text-amber-700 dark:text-amber-400">{t.statusFull}</span>
              }
              if (state === 'purged') {
                return <span className="text-slate-600 dark:text-neutral-400">{t.statusPurged}</span>
              }
              return (
                <span className="text-red-700 dark:text-red-400">
                  {t.statusClosedAt(
                    vault.closed_at_ms && Number(vault.closed_at_ms) > 0
                      ? formatDateTime(Number(vault.closed_at_ms))
                      : '—'
                  )}
                </span>
              )
            })()}
          </dd>

          {vault?.closed_at_ms && Number(vault.closed_at_ms) > 0 && (
            <>
              <dt className="text-sm font-normal text-slate-600 dark:text-neutral-300 md:self-center break-words">{t.purgeLabel}</dt>
              <dd className="text-muted">
                {t.purgeNoticeAt(
                  formatDateTime(
                    Number(vault.closed_at_ms) +
                      (vault.purge_grace_ms ? Number(vault.purge_grace_ms) : Number(PURGE_GRACE_MS))
                  )
                )}
              </dd>
            </>
          )}

          <dt className="text-sm font-normal text-slate-600 dark:text-neutral-300 md:self-center break-words">{t.storageLocationLabel}</dt>
          <dd className="text-body flex items-center gap-1.5">
            {surveyData ? (
              (() => {
                const fields = surveyData.content?.fields as any
                const surveyBlobIdBytes = getOptionVec(fields?.survey_blob_id)
                return surveyBlobIdBytes ? (
                  <span className="badge-decentralized shrink-0 inline-flex items-center gap-1">
                    {t.storageDecentralized}
                  </span>
                ) : (
                  <span className="badge-direct shrink-0 inline-flex items-center gap-1">
                    {t.storageDirect}
                  </span>
                )
              })()
            ) : isPendingVault ? (
              t.checkingShort
            ) : (
              '—'
            )}
          </dd>

          <dt className="text-sm font-normal text-slate-600 dark:text-neutral-300 md:self-center break-words">{t.deadlineLabel}</dt>
          <dd className="text-body">{surveyMeta ? formatDateTime(surveyMeta.deadlineMs) : '—'}</dd>

          <dt className="text-sm font-normal text-slate-600 dark:text-neutral-300 md:self-center break-words">{t.identityThresholdLabel}</dt>
          <dd className="text-body flex flex-col gap-1.5 py-1">
            {surveyMeta ? (
              <>
                {surveyMeta.allowedSources && surveyMeta.allowedSources.length > 0 && (
                  <div>
                    <span className="font-semibold text-slate-500 dark:text-neutral-450 mr-1">憑證：</span>
                    <span>
                      {surveyMeta.allowedSources.map((s: number) => {
                        switch (s) {
                          case 1: return t.sourceSelfReport || '自我宣告'
                          case 2: return t.sourceEmail || 'Email 驗證'
                          case 3: return t.sourceSocial || '社群驗證'
                          case 4: return t.sourceSelfProtocol || '自我協定'
                          case 5: return t.sourceWorldId || 'World ID'
                          case 6: return t.sourceGoogle || 'Google'
                          case 7: return t.sourceGithub || 'GitHub'
                          default: return `Source ${s}`
                        }
                      }).join(', ')}
                    </span>
                  </div>
                )}
                {surveyMeta.allowedNftType && (
                  <div className="flex items-start gap-1 flex-wrap">
                    <span className="font-semibold text-slate-500 dark:text-neutral-450 shrink-0">NFT：</span>
                    <span className="font-mono text-xs bg-slate-100 dark:bg-neutral-800 px-1.5 py-0.5 rounded text-blue-600 dark:text-blue-400 break-all select-all max-w-full">
                      {surveyMeta.allowedNftType}
                    </span>
                  </div>
                )}
                {!surveyMeta.allowedSources?.length && !surveyMeta.allowedNftType && '—'}
              </>
            ) : '—'}
          </dd>

          <dt className="text-sm font-normal text-slate-600 dark:text-neutral-300 md:self-center break-words">{t.perResponseLabel}</dt>
          <dd className="text-body">{surveyMeta ? `${surveyMeta.perResponse} SSR` : '—'}</dd>

          <dt className="text-sm font-normal text-slate-600 dark:text-neutral-300 md:self-center break-words">{t.repeatLabel}</dt>
          <dd className="text-body">
            {surveyMeta
              ? surveyMeta.repeatReward === 0
                ? t.repeatDisabled
                : t.repeatEnabled(surveyMeta.repeatReward, surveyMeta.repeatMaxTimes)
              : '—'}
          </dd>

          <dt className="text-sm font-normal text-slate-600 dark:text-neutral-300 md:self-center break-words">{t.gasCompensationLabel}</dt>
          <dd className="text-body">
            {vault ? `${formatSui(vault.gas_compensation_amount)} SUI` : '—'}
          </dd>

          <dt className="text-sm font-normal text-slate-600 dark:text-neutral-300 md:self-center break-words">{t.sponsorAddressLabel}</dt>
          <dd className="font-mono break-all text-body">
            {vault ? vault.sponsor_address : '—'}
          </dd>
        </dl>
        {!surveyMeta && (
          <p className="text-muted mt-3">{t.metaUnavailable}</p>
        )}

        {isWalrusSurvey && walrusBlobObjectId && vault?.status !== 2 && (
          <div className="alert-info mt-4 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
            <p className="text-sm font-normal">{t.walrusExtendHint}</p>
            <button
              type="button"
              className="btn-outline shrink-0 disabled:opacity-50"
              disabled={extendStatus === 'signing' || extendStatus === 'success'}
              onClick={() => void handleExtendWalrus()}
            >
              {extendStatus === 'signing'
                ? t.walrusExtending
                : extendStatus === 'success'
                  ? t.walrusExtendSuccess
                  : t.walrusExtendBtn}
            </button>
          </div>
        )}
        {extendError && (
          <p className="text-sm font-normal text-rose-700 dark:text-rose-400 mt-2">{extendError}</p>
        )}
      </section>

      {/* ── 解密 + 統計圖表 ──────────────────────────────────────────────── */}
      {responseCount === 0 ? (
        <div className="bg-slate-100 dark:bg-neutral-900 rounded p-6 text-center text-slate-600 dark:text-neutral-400 mb-6 transition-colors">
          {t.noResponses}
        </div>
      ) : (
        <section className="mb-6">
          {decryptStatus === 'idle' && isCreator && (
            <button
              type="button"
              onClick={() => void handleDecrypt()}
              className="btn-primary"
            >
              {t.decryptBtn}
            </button>
          )}
          {(decryptStatus === 'signing' || decryptStatus === 'decrypting') && (
            <p className="text-sm text-slate-600 dark:text-neutral-400">
              {decryptStatus === 'signing' ? t.signingMsg : t.decryptingMsg}
            </p>
          )}
          {decryptStatus === 'error' && decryptError && (
            <div role="alert" className="alert-error">
              <span>{decryptError}</span>
            </div>
          )}

          {decryptedResponses &&
            questions &&
            (() => {
              const isPublicSurvey = surveyMeta?.encryptAnswers === false

              // viewMode 切換：'latest' 同地址僅保留 max(claimed_at_ms) 那筆。
              const displayedResponses = (() => {
                if (responseViewMode === 'all') return decryptedResponses
                const latestByRespondent = new Map<string, DecryptedResponse>()
                for (const resp of decryptedResponses) {
                  const prev = latestByRespondent.get(resp.respondent)
                  if (!prev || resp.claimed_at_ms > prev.claimed_at_ms) {
                    latestByRespondent.set(resp.respondent, resp)
                  }
                }
                return [...latestByRespondent.values()].sort(
                  (a, b) => a.claimed_at_ms - b.claimed_at_ms
                )
              })()
              const hasRepeats =
                decryptedResponses.length !== displayedResponses.length ||
                decryptedResponses.length >
                new Set(decryptedResponses.map((r) => r.respondent)).size

              return (
                <div className="mt-6">
                  <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-4">
                    <div className="flex items-center gap-3 flex-wrap">
                      <h3 className="text-h3">
                        {isPublicSurvey ? t.responsesTitlePublic : t.responsesTitle}
                      </h3>
                      <span className="text-xs text-slate-600 dark:text-neutral-400">
                        {isPublicSurvey
                          ? t.displayCount(decryptedResponses.length)
                          : responseViewMode === 'all'
                            ? t.displayCount(displayedResponses.length)
                            : t.displayUniqueCount(displayedResponses.length, decryptedResponses.length)}
                      </span>
                    </div>
                    <div className="flex items-center gap-3 flex-wrap">
                      {!isPublicSurvey && (
                        <div
                          role="radiogroup"
                          aria-label={t.viewModeLabel}
                          className="inline-flex items-center bg-slate-100 dark:bg-neutral-800 rounded-lg p-0.5 text-xs transition-colors"
                        >
                          <label
                            className={`px-3 py-1.5 rounded-md cursor-pointer font-normal ${responseViewMode === 'all' ? 'bg-white shadow-sm text-slate-800 dark:bg-neutral-700 dark:text-neutral-100' : 'text-slate-600 dark:text-neutral-400'}`}
                          >
                            <input
                              type="radio"
                              name="responseViewMode"
                              value="all"
                              checked={responseViewMode === 'all'}
                              onChange={() => setResponseViewMode('all')}
                              className="sr-only"
                            />
                            {t.allSubmissions}
                          </label>
                          <label
                            className={`px-3 py-1.5 rounded-md cursor-pointer font-normal ${responseViewMode === 'latest' ? 'bg-white shadow-sm text-slate-800 dark:bg-neutral-700 dark:text-neutral-100' : 'text-slate-600 dark:text-neutral-400'}`}
                          >
                            <input
                              type="radio"
                              name="responseViewMode"
                              value="latest"
                              checked={responseViewMode === 'latest'}
                              onChange={() => setResponseViewMode('latest')}
                              className="sr-only"
                            />
                            {t.latestPerPerson}
                          </label>
                        </div>
                      )}
                      <button
                        type="button"
                        onClick={handleDownloadCsv}
                        title={isPublicSurvey ? t.csvTooltipPublic : t.csvTooltip}
                 className="bg-emerald-700 hover:bg-emerald-800 text-neutral-100 font-normal px-5 py-2 rounded-xl transition-all text-base flex items-center justify-center gap-1.5 shadow-sm dark:bg-emerald-800 dark:hover:bg-emerald-700"
                      >
                        <svg
                          className="w-4 h-4"
                          fill="none"
                          stroke="currentColor"
                          viewBox="0 0 24 24"
                          xmlns="http://www.w3.org/2000/svg"
                        >
                          <path
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            strokeWidth="2"
                            d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"
                          ></path>
                        </svg>
                        {isPublicSurvey ? t.downloadCsvPublic : t.downloadCsv}
                      </button>
                    </div>
                  </div>
                  {hasRepeats && responseViewMode === 'all' && !isPublicSurvey && (
                    <p className="text-xs text-slate-600 dark:text-neutral-400 mb-3">
                      {t.hasRepeatsInfo}
                    </p>
                  )}

                  {isPublicSurvey ? (
                    <div className="space-y-6">
                      {questions.map((q) => {
                        const questionStats = stats?.questions?.[q.id]
                        const totalAnswers = stats?.decrypted_count || 0

                        if (q.type === 'text') {
                          return (
                            <div
                              key={q.id}
                              className="bg-white dark:bg-neutral-900 border border-neutral-200 dark:border-neutral-800 rounded-2xl p-6 transition-colors shadow-xs"
                            >
                              <div className="flex items-center gap-2 mb-3">
                                <span className="px-2.5 py-0.5 rounded-full text-xs font-medium bg-neutral-100 text-neutral-600 dark:bg-neutral-800 dark:text-neutral-400">
                                  {t.questionTypeText}
                                </span>
                                <h4 className="text-base font-semibold text-slate-900 dark:text-neutral-100">
                                  {q.prompt}
                                </h4>
                              </div>
                              <div className="p-4 bg-slate-50 dark:bg-neutral-950/50 rounded-xl border border-dashed border-neutral-200 dark:border-neutral-800 text-sm text-slate-500 dark:text-neutral-400 flex items-start gap-2.5">
                                <svg
                                  className="w-5 h-5 text-amber-500 flex-shrink-0 mt-0.5"
                                  fill="none"
                                  stroke="currentColor"
                                  viewBox="0 0 24 24"
                                  xmlns="http://www.w3.org/2000/svg"
                                >
                                  <path
                                    strokeLinecap="round"
                                    strokeLinejoin="round"
                                    strokeWidth="2"
                                    d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"
                                  ></path>
                                </svg>
                                <span>{t.textAnswersHiddenInfo}</span>
                              </div>
                            </div>
                          )
                        }

                        const options = q.options_json || []
                        const counts = questionStats?.counts || {}

                        const displayOptions =
                          options.length > 0
                            ? options
                            : Object.keys(counts).sort((a, b) => (counts[b] || 0) - (counts[a] || 0))

                        const typeLabel =
                          q.type === 'single_choice'
                            ? t.questionTypeSingle
                            : q.type === 'multi_choice'
                              ? t.questionTypeMulti
                              : t.questionTypeScale

                        const badgeStyle =
                          q.type === 'single_choice'
                            ? 'bg-blue-50 text-blue-700 dark:bg-blue-950/30 dark:text-blue-400 border-blue-200/30'
                            : q.type === 'multi_choice'
                              ? 'bg-purple-50 text-purple-700 dark:bg-purple-950/30 dark:text-purple-400 border-purple-200/30'
                              : 'bg-indigo-50 text-indigo-700 dark:bg-indigo-950/30 dark:text-indigo-400 border-indigo-200/30'

                        return (
                          <div
                            key={q.id}
                            className="bg-white dark:bg-neutral-900 border border-neutral-200 dark:border-neutral-800 rounded-2xl p-6 transition-colors shadow-xs"
                          >
                            <div className="flex items-center gap-2 mb-4">
                              <span className={`px-2.5 py-0.5 rounded-full text-xs font-medium border ${badgeStyle}`}>
                                {typeLabel}
                              </span>
                              <h4 className="text-base font-semibold text-slate-900 dark:text-neutral-100">
                                {q.prompt}
                              </h4>
                            </div>

                            <div className="space-y-4">
                              {q.options_json?.map((opt, optIdx) => {
                                const count = counts[String(optIdx)] || counts[optIdx] || 0
                                const pct = totalAnswers > 0 ? (count / totalAnswers) * 100 : 0
                                const displayPct = pct.toFixed(1)

                                return (
                                  <div key={opt} className="space-y-1.5">
                                    <div className="flex items-center justify-between text-sm">
                                      <span className="text-slate-800 dark:text-neutral-200 font-medium break-all pr-4">
                                        {opt}
                                      </span>
                                      <span className="text-slate-500 dark:text-neutral-400 text-xs font-mono whitespace-nowrap">
                                        {count} 次 ({displayPct}%)
                                      </span>
                                    </div>
                                    <div className="w-full bg-slate-100 dark:bg-neutral-800/80 rounded-full h-3 overflow-hidden">
                                      <div
                                        className={`h-full rounded-full transition-all duration-500 ${q.type === 'single_choice'
                                          ? 'bg-blue-600 dark:bg-blue-500'
                                          : q.type === 'multi_choice'
                                            ? 'bg-purple-600 dark:bg-purple-500'
                                            : 'bg-indigo-600 dark:bg-indigo-500'
                                          }`}
                                        style={{ width: `${pct}%` }}
                                      />
                                    </div>
                                  </div>
                                )
                              })}

                              {displayOptions.length === 0 && (
                                <p className="text-sm text-slate-400 dark:text-neutral-500 italic">
                                  無填答數據
                                </p>
                              )}
                            </div>
                          </div>
                        )
                      })}
                    </div>
                  ) : (
                    <div className="overflow-x-auto rounded-xl bg-white dark:bg-neutral-900 shadow-sm max-w-full transition-colors">
                      <table className="min-w-full divide-y divide-gray-200 dark:divide-neutral-800 text-sm">
                        <thead className="bg-slate-100 dark:bg-neutral-800">
                          <tr>
                            <th
                              scope="col"
                              className="px-4 py-3 text-left text-xs font-normal text-slate-600 dark:text-neutral-400 uppercase tracking-wider whitespace-nowrap"
                            >
                              #
                            </th>
                            <th
                              scope="col"
                              className="px-4 py-3 text-left text-xs font-normal text-slate-600 dark:text-neutral-400 uppercase tracking-wider whitespace-nowrap"
                            >
                              {t.respondentHeader}
                            </th>
                            <th
                              scope="col"
                              className="px-4 py-3 text-left text-xs font-normal text-slate-600 dark:text-neutral-400 uppercase tracking-wider whitespace-nowrap"
                            >
                              {t.submittedTimeHeader}
                            </th>
                            {questions.map((q) => (
                              <th
                                key={q.id}
                                scope="col"
                                className="px-4 py-3 text-left text-xs font-normal text-slate-600 dark:text-neutral-400 uppercase tracking-wider whitespace-nowrap max-w-xs truncate"
                                title={q.prompt}
                              >
                                {q.id}: {q.prompt}
                              </th>
                            ))}
                          </tr>
                        </thead>
                        <tbody className="bg-white dark:bg-neutral-900 divide-y divide-gray-100 dark:divide-neutral-800">
                          {displayedResponses.map((resp, idx) => (
                            <tr
                              key={resp.respondent + idx}
                              className="hover:bg-slate-100/50 dark:hover:bg-neutral-800/40 transition-colors"
                            >
                              <td className="px-4 py-3 text-slate-500 dark:text-neutral-500 font-mono whitespace-nowrap">
                                {idx + 1}
                              </td>
                              <td
                                className="px-4 py-3 text-slate-700 dark:text-neutral-300 font-mono whitespace-nowrap"
                                title={resp.respondent}
                              >
                                {resp.respondent.slice(0, 8)}...{resp.respondent.slice(-8)}
                              </td>
                              <td className="px-4 py-3 text-slate-600 dark:text-neutral-400 whitespace-nowrap">
                                {new Date(resp.claimed_at_ms).toLocaleString('zh-TW')}
                              </td>
                              {questions.map((q) => {
                                const val = resp.answers[q.id]
                                const displayVal = getAnswerText(q, val) || '—'
                                return (
                                  <td
                                    key={q.id}
                                    className="px-4 py-3 text-slate-800 dark:text-neutral-300 whitespace-nowrap max-w-xs truncate"
                                    title={displayVal}
                                  >
                                    {displayVal}
                                  </td>
                                )
                              })}
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  )}
                </div>
              )
            })()}

          {stats && stats.failed_count > 0 && (
            <p className="text-xs text-amber-600">
              {t.decryptFailedCount(stats.failed_count)}
            </p>
          )}
        </section>
      )}

      {/* ── 結束活動 ─────────────────────────────────────────────────────── */}
      {(closeStatus !== 'idle' || isCreator) && (
        <div className="mt-6 border-t pt-6">
          {closeStatus === 'success' && (
            <div role="status" className="alert-success mb-3">
              <span>{t.closeSuccess}</span>
            </div>
          )}
          {closeStatus === 'error' && closeError && (
            <div role="alert" className="alert-error mb-3 break-all">
              <span>{closeError}</span>
            </div>
          )}

          {isCreator && (
            <div className="flex flex-wrap items-center gap-3">
              <button
                type="button"
                onClick={handleClose}
                disabled={!canClose}
                className={
                  isActive
                    ? 'btn-danger'
                    : 'btn-secondary text-neutral-400 dark:text-neutral-500 cursor-default shadow-none'
                }
              >
                {!isActive ? t.btnClosed : closeStatus === 'signing' ? t.btnClosing : t.btnClose}
              </button>

              {!isActive && (
                <>
                  {purgeStatus === 'success' && (
                    <div role="status" className="alert-success py-1.5 px-3 text-sm">
                      <span>{t.purgeSuccess}</span>
                    </div>
                  )}

                  {purgeStatus === 'confirm' && (
                    <>
                      <button
                        type="button"
                        onClick={() => setPurgeStatus('idle')}
                        className="btn-secondary w-24 sm:w-28 flex-shrink-0 text-center"
                      >
                        {t.purgeCancel}
                      </button>
                      <button type="button" onClick={handlePurge} className="btn-danger">
                        {t.purgeConfirmBtn}
                      </button>
                      <span className="text-muted flex-1 min-w-[250px]">
                        {t.purgeConfirm}
                      </span>
                    </>
                  )}

                  {purgeStatus !== 'success' && purgeStatus !== 'confirm' && (
                    <button
                      type="button"
                      onClick={() => setPurgeStatus('confirm')}
                      disabled={purgeStatus === 'signing'}
                      className="btn-danger w-24 sm:w-28"
                    >
                      {purgeStatus === 'signing' ? t.purging : t.btnPurge}
                    </button>
                  )}
                </>
              )}
            </div>
          )}

          {isCreator && (
            <p className="text-muted mt-2">{t.closeAndPurgeNotice(PURGE_GRACE_DAYS)}</p>
          )}

          {isCreator && !isActive && purgeStatus === 'error' && purgeError && (
            <div role="alert" className="alert-error mt-3 break-all">
              <span>{purgeError}</span>
            </div>
          )}
        </div>
      )}

      {/* ── 我的問卷列表 (Bottom Switcher) ────────────────────────────────── */}
      {creatorSurveys.length > 0 && (
        <section className="mt-8 border-t pt-6">
          <div className="mb-3">
            <h2 className="text-h2">
              {t.switchSurveys}
            </h2>
            <p className="text-xs text-neutral-500 dark:text-neutral-400 mt-1">
              <strong>{t.switchSurveysDescStrong}</strong>{t.switchSurveysDescSuffix}
            </p>
          </div>
          <div className="flex flex-col gap-[3px] text-sm">
            {sortedSurveyDetails.map((s) => (
              <div
                key={s.vault_id}
                role="row"
                onClick={() =>
                  s.vault_id !== vaultId &&
                  navigate(`/dashboard/${s.vault_id}${getSavedContentKey(s.vault_id)}`)
                }
                className={`flex items-center justify-between px-4 py-2 rounded-xs transition-colors duration-150 group ${s.vault_id === vaultId
                  ? 'bg-neutral-50/50 dark:bg-neutral-800/30 cursor-default'
                  : 'bg-white dark:bg-neutral-900 cursor-pointer hover:bg-neutral-100/80 dark:hover:bg-neutral-800/60'
                  }`}
              >
                <div className="text-slate-900 dark:text-white font-normal flex-1 min-w-0 truncate mr-4" title={s.title}>
                  {s.title}
                </div>
                <div className="flex items-center gap-4">
                  <div className="text-slate-600 dark:text-neutral-400 font-mono whitespace-nowrap">
                    {s.claimed_count} / {s.max_responses}
                  </div>
                  <div className="w-24 text-right">
                    {s.vault_id === vaultId ? (
                      <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-normal bg-blue-100 text-blue-800 dark:bg-blue-900/40 dark:text-blue-300">
                        {t.currentlySelected}
                      </span>
                    ) : (() => {
                      const state = deriveSurveyState(s.status, s.claimed_count, s.max_responses)
                      const styles =
                        state === 'active'
                          ? 'bg-emerald-50 text-emerald-700 dark:bg-emerald-950/30 dark:text-emerald-400 border-emerald-200/50 dark:border-emerald-800/30'
                          : state === 'full'
                            ? 'bg-amber-50 text-amber-700 dark:bg-amber-950/30 dark:text-amber-400 border-amber-200/50 dark:border-amber-800/30'
                            : state === 'purged'
                              ? 'bg-neutral-100 text-neutral-600 dark:bg-neutral-800 dark:text-neutral-400 border-neutral-200/50 dark:border-neutral-700/30'
                              : 'bg-red-50 text-red-700 dark:bg-red-950/30 dark:text-red-400 border-red-200/50 dark:border-red-800/30'
                      const label =
                        state === 'active'
                          ? t.statusActive
                          : state === 'full'
                            ? t.statusFull
                            : state === 'purged'
                              ? t.statusPurged
                              : t.statusClosed
                      return (
                        <span
                          className={`inline-flex items-center shrink-0 whitespace-nowrap px-2.5 py-0.5 rounded-full text-xs font-normal border ${styles}`}
                        >
                          {label}
                        </span>
                      )
                    })()}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {showQrModal && (
        <div
          className="fixed inset-0 bg-black/50 backdrop-blur-xs flex items-center justify-center z-50 transition-opacity duration-300"
          onClick={() => setShowQrModal(false)}
        >
          <div
            className="bg-white dark:bg-neutral-900 rounded-lg p-6 max-w-sm w-full mx-4 shadow-xl border border-neutral-200 dark:border-neutral-800 flex flex-col items-center gap-4"
            onClick={(e) => e.stopPropagation()}
          >
            <h3 className="text-lg font-bold text-neutral-900 dark:text-white">{t.qrModalTitle}</h3>

            <div className="bg-white p-2 rounded border border-neutral-100 dark:border-neutral-800">
              <canvas ref={qrCanvasRef} className="max-w-full h-auto" />
            </div>

            <p className="text-xs text-neutral-500 dark:text-neutral-400 text-center">
              {t.qrModalDesc}
            </p>

            <div className="flex gap-2 w-full mt-2">
              <button
                type="button"
                onClick={handleDownloadQr}
                className="flex-1 btn-primary text-sm flex items-center justify-center"
              >
                {t.downloadPng}
              </button>
              <button
                type="button"
                onClick={() => setShowQrModal(false)}
                className="flex-1 btn-secondary text-sm flex items-center justify-center"
              >
                {t.close}
              </button>
            </div>
          </div>
        </div>
      )}
    </main>
  )
}

import { useEffect, useMemo, useRef, useState } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import { AlertTriangle, Info } from 'lucide-react'
import {
  useCurrentAccount,
  useSignAndExecuteTransaction,
  useSignPersonalMessage,
  useSuiClient,
  useSuiClientQuery,
} from '@mysten/dapp-kit'
import { parseFrontmatter, parseFullSurveyMarkdown, serializeFullSurveyToMarkdown, type QuestionType } from '../lib/frontmatter'
import { renderMarkdown } from '../lib/markdown'
import {
  buildCreateSurveyPtb,
  estimateFundCostV2,
  extractSurveyIdFromEffects,
  extractVaultIdFromEffects,
} from '../lib/ptb'
import { getTicketFeeMist } from '../lib/ticketFee'
import { formatSsr, formatSui, formatFullPrecision } from '../lib/format'
import {
  KEY_DERIVE_MSG,
  buildCreatorPubKey,
  bytesToBase64url,
  deriveCreatorKeyPair,
  encryptSurveyContent,
  buildPublicContentBlob,
  type CreatorKeyPair,
} from '../lib/crypto'
import { translateMoveAbort } from '../lib/moveAbort'
import { useT } from '../i18n'
import { probeGasSponsorHealth, type GasHealth } from '../lib/sponsoredTx'
import { uploadToDecentralizedStorage } from '../lib/storage'

const PACKAGE_ID = import.meta.env.VITE_PACKAGE_ID ?? ''
const POOL_ID = import.meta.env.VITE_AMM_POOL_ID ?? ''
const SR_TREASURY_ID = import.meta.env.VITE_SR_TREASURY_ID ?? ''
const SSR_TREASURY_ID = import.meta.env.VITE_SSR_TREASURY_ID ?? ''
const SURVEY_REGISTRY_ID = import.meta.env.VITE_SURVEY_REGISTRY_ID ?? ''
const ADMIN_TREASURY = import.meta.env.VITE_ADMIN_ADDRESS ?? ''

const DRAFT_KEY_PREFIX = 'surveysui:draft:'
const SURVEY_KEY_PREFIX = 'surveysui:survey:'

/** Slippage buffer: invest 1% more SUI than the curve says, in case `total_sui_invested` shifts. */
const SLIPPAGE_NUMER = 101n
const SLIPPAGE_DENOM = 100n

function base64ToBytes(b64: string): Uint8Array {
  const binary = atob(b64)
  return Uint8Array.from(binary, (c) => c.charCodeAt(0))
}

interface DraftEntry {
  contentMd: string
  encrypt?: boolean
  savedAt: number
}

function readDraft(draftId: string | undefined): DraftEntry | null {
  if (!draftId) return null
  try {
    const raw = window.localStorage.getItem(`${DRAFT_KEY_PREFIX}${draftId}`)
    if (!raw) return null
    const parsed = JSON.parse(raw) as DraftEntry
    if (typeof parsed?.contentMd !== 'string') return null
    return parsed
  } catch {
    return null
  }
}

export default function FundPage() {
  const { id: draftId } = useParams<{ id: string }>()
  const navigate = useNavigate()

  const account = useCurrentAccount()
  const suiClient = useSuiClient()
  const { mutate: signAndExecute } = useSignAndExecuteTransaction()
  const { mutateAsync: signPersonalMessageAsync } = useSignPersonalMessage()
  const t = useT('fund')

  const typeLabel = (type: QuestionType): string => {
    switch (type) {
      case 'single_choice': return t.typeSingleChoice
      case 'multi_choice': return t.typeMultiChoice
      case 'text': return t.typeText
      case 'scale': return t.typeScale
      default: return type
    }
  }

  const [draft, setDraft] = useState<DraftEntry | null>(() => readDraft(draftId))

  useEffect(() => {
    setDraft(readDraft(draftId))
  }, [draftId])

  const frontmatter = useMemo(() => (draft ? parseFrontmatter(draft.contentMd) : null), [draft])

  const { data: poolData } = useSuiClientQuery(
    'getObject',
    { id: POOL_ID, options: { showContent: true } },
    { enabled: !!POOL_ID }
  )

  const { data: coinsData } = useSuiClientQuery(
    'getCoins',
    {
      owner: account?.address ?? '',
      coinType: `${PACKAGE_ID}::stacked_survey_reward::STACKED_SURVEY_REWARD`,
    },
    { enabled: !!account && !!PACKAGE_ID }
  )

  const ssrCoins = useMemo(() => {
    return coinsData?.data ?? []
  }, [coinsData])

  const creatorSsrBalance = useMemo(() => {
    return ssrCoins.reduce((sum, c) => sum + BigInt(c.balance), 0n)
  }, [ssrCoins])

  const totalSuiInvested = useMemo<bigint>(() => {
    if (poolData?.data?.content?.dataType !== 'moveObject') return 0n
    const fields = (poolData.data.content as { fields: Record<string, string> }).fields
    return BigInt(fields.total_sui_invested ?? '0')
  }, [poolData])

  const currentRate = useMemo(() => {
    const decay = 1_000_000_000_000n
    const initialSsrPerSui = 1000n
    const numer = Number(initialSsrPerSui * decay)
    const denom = Number(decay + totalSuiInvested)
    return numer / denom
  }, [totalSuiInvested])

  const feeConfig = useMemo(() => {
    if (poolData?.data?.content?.dataType !== 'moveObject') {
      return { totalFeeBps: 2000n, discountBps: 5000n }
    }
    const fields = (poolData.data.content as { fields: Record<string, any> }).fields
    const feeFields = fields?.fee_config?.fields
    if (!feeFields) {
      return { totalFeeBps: 2000n, discountBps: 5000n }
    }
    return {
      totalFeeBps: BigInt(feeFields.total_fee_bps ?? '2000'),
      discountBps: BigInt(feeFields.discount_bps ?? '5000'),
    }
  }, [poolData])

  const cost = useMemo(() => {
    if (!frontmatter?.ok) return null
    return estimateFundCostV2({
      perResponse: BigInt(frontmatter.data.perResponse),
      repeatReward: BigInt(frontmatter.data.repeatReward),
      repeatMaxTimes: frontmatter.data.repeatMaxTimes,
      maxResponses: frontmatter.data.maxResponses,
      totalSuiInvested,
      feeConfig,
      creatorSsrBalance,
    })
  }, [frontmatter, totalSuiInvested, feeConfig, creatorSsrBalance])

  const suiToSpend = cost ? (cost.suiToInvest * SLIPPAGE_NUMER) / SLIPPAGE_DENOM : null

  const [gasHealth, setGasHealth] = useState<GasHealth | null>(null)

  useEffect(() => {
    const backendUrl = import.meta.env.VITE_BFF_URL ?? ''
    void probeGasSponsorHealth({ backendUrl }).then((res) => {
      setGasHealth(res)
    })
  }, [])

  const gasCompensationAmount = useMemo(() => {
    if (!gasHealth?.available) return 0n
    return BigInt(gasHealth.gasCompensationAmount ?? '0')
  }, [gasHealth])

  const storageCompensationAmountMIST = useMemo(() => {
    if (!frontmatter?.ok) return 0n
    const amount = frontmatter.data.storageCompensationAmount ?? 0.01
    return BigInt(Math.round(amount * 1_000_000_000))
  }, [frontmatter])

  const ticketFeeMist = useMemo(() => getTicketFeeMist(), [])

  const requiredGas = useMemo(() => {
    if (!frontmatter?.ok) return 0n
    const params = frontmatter.data
    const perResponseSui = gasCompensationAmount + storageCompensationAmountMIST + ticketFeeMist
    if (perResponseSui === 0n) return 0n
    const repeatMaxTimes = BigInt(params.repeatMaxTimes ?? 1)
    if (params.repeatReward > 0) {
      return BigInt(params.maxResponses) * (1n + repeatMaxTimes) * perResponseSui
    } else {
      return BigInt(params.maxResponses) * perResponseSui
    }
  }, [frontmatter, gasCompensationAmount, storageCompensationAmountMIST, ticketFeeMist])

  const SURVEY_SIZE_THRESHOLD_KB = Number(import.meta.env.VITE_SURVEY_SIZE_THRESHOLD_KB || '10')

  const requiredStorageFund = 0n

  const totalSuiToSpend = suiToSpend != null ? suiToSpend + requiredGas : null

  const [keypair, setKeypair] = useState<CreatorKeyPair | null>(null)
  const [surveySalt] = useState(() => crypto.getRandomValues(new Uint8Array(32)))
  const [status, setStatus] = useState<
    'idle' | 'key-signing' | 'key-ready' | 'uploading' | 'tx-signing' | 'submitting' | 'success' | 'error'
  >('idle')
  const [errorMsg, setErrorMsg] = useState<string | null>(null)
  const [encrypt, setEncrypt] = useState(false)
  const [encryptAnswers, setEncryptAnswers] = useState(true)

  useEffect(() => {
    if (draft) {
      setEncrypt(!!draft.encrypt)
      const parsed = parseFullSurveyMarkdown(draft.contentMd)
      if (parsed.ok) {
        setEncryptAnswers(parsed.data.encryptAnswers !== false)
      }
    }
  }, [draft])

  const fullSurvey = useMemo(() => {
    if (!draft) return null
    const parsed = parseFullSurveyMarkdown(draft.contentMd)
    return parsed.ok ? parsed.data : null
  }, [draft])

  // 切換錢包時清除 keypair
  const prevAddressRef = useRef<string | undefined>(undefined)
  useEffect(() => {
    if (prevAddressRef.current && prevAddressRef.current !== account?.address) {
      setKeypair(null)
      setStatus('idle')
    }
    prevAddressRef.current = account?.address
  }, [account?.address])

  if (!draftId || !draft) {
    return (
      <main className="min-h-screen p-8 max-w-xl mx-auto">
        <h1 className="text-h1 mb-4">{t.pageTitle}</h1>
        <p className="text-red-600">
          {t.draftNotFound(draftId ?? '?')}
        </p>
      </main>
    )
  }

  if (!frontmatter?.ok) {
    return (
      <main className="min-h-screen p-8 max-w-xl mx-auto">
        <h1 className="text-h1 mb-4">{t.pageTitle}</h1>
        <p className="text-red-600">{t.frontmatterParseFailed(frontmatter?.error ?? t.unknownError)}</p>
      </main>
    )
  }

  const params = frontmatter.data
  const baseSsr = params.perResponse * params.maxResponses
  const repeatSsr = params.repeatReward * params.maxResponses * params.repeatMaxTimes
  const totalSsr = baseSsr + repeatSsr

  async function handleSetupKey() {
    if (!account) return
    setStatus('key-signing')
    setErrorMsg(null)
    try {
      const message = new TextEncoder().encode(KEY_DERIVE_MSG)
      const { signature } = await signPersonalMessageAsync({ message })
      const kp = await deriveCreatorKeyPair(base64ToBytes(signature), surveySalt)
      setKeypair(kp)
      setStatus('key-ready')
    } catch (err) {
      setErrorMsg(err instanceof Error ? err.message : t.errKeySetupFailed)
      setStatus('error')
    }
  }

  async function handleFund() {
    const actualEncryptAnswers = encrypt ? true : encryptAnswers
    const isKeyRequired = encrypt || actualEncryptAnswers

    if (!account || !cost || suiToSpend == null || !draft) return
    if (isKeyRequired && !keypair) return

    setStatus('tx-signing')
    setErrorMsg(null)

    // 32B X25519 pubkey embedded in the content blob header (identification only).
    const creatorPublicKeyBytes = isKeyRequired && keypair
      ? keypair.x25519PublicKeyBytes
      : new Uint8Array(32) // 32-byte dummy key for non-encrypted surveys
    // Hybrid (X25519 + ML-KEM-768) pubkey published on-chain for answer encryption.
    const creatorPubKeyForChain = isKeyRequired && keypair
      ? buildCreatorPubKey(keypair, surveySalt)
      : new Uint8Array(32) // dummy for non-encrypted surveys (answers never encrypted)
    let contentKey: Uint8Array
    let encryptedBlob: Uint8Array

    // 1. 解析 draft.contentMd，更新 encryptAnswers 並重新序列化
    let contentMdUpdated = draft.contentMd
    try {
      const parsed = parseFullSurveyMarkdown(draft.contentMd)
      if (!parsed.ok) {
        setErrorMsg(parsed.error)
        setStatus('error')
        return
      }
      parsed.data.encryptAnswers = actualEncryptAnswers
      contentMdUpdated = serializeFullSurveyToMarkdown(parsed.data, {
        draftStamp: new Date().toISOString()
      })
    } catch (err) {
      console.error('Failed to update draft markdown frontmatter:', err)
      setErrorMsg('更新問卷 frontmatter 失敗')
      setStatus('error')
      return
    }

    try {
      const shouldEncrypt = encrypt
      if (shouldEncrypt) {
        const enc = await encryptSurveyContent(contentMdUpdated, creatorPublicKeyBytes)
        encryptedBlob = enc.encryptedBlob
        contentKey = enc.contentKey
      } else {
        // 公開問卷：使用 buildPublicContentBlob 產生首 Byte 為 0x00 的明文 Blob
        encryptedBlob = buildPublicContentBlob(contentMdUpdated)
        contentKey = new Uint8Array(0)
      }
    } catch (err) {
      console.error('E2E Debug: handleFund encryption catch:', err)
      setErrorMsg(err instanceof Error ? err.message : t.errEncryptFailed)
      setStatus('error')
      return
    }

    const fullSurvey = parseFullSurveyMarkdown(contentMdUpdated)
    if (!fullSurvey.ok) {
      setErrorMsg(fullSurvey.error)
      setStatus('error')
      return
    }

    const sha256 = async (text: string): Promise<Uint8Array> => {
      const data = new TextEncoder().encode(text)
      const hashBuffer = await crypto.subtle.digest('SHA-256', data)
      return new Uint8Array(hashBuffer)
    }

    let contentHash: Uint8Array
    let schemaHash: Uint8Array
    try {
      contentHash = await sha256(contentMdUpdated) // Use updated markdown
      const schemaStr = JSON.stringify(fullSurvey.data.questions || [])
      schemaHash = await sha256(schemaStr)
    } catch (err) {
      console.error('E2E Debug: handleFund hash calculation catch:', err)
      setErrorMsg(t.errHashCalcFailed)
      setStatus('error')
      return
    }

    let surveyBlobId: Uint8Array | undefined = undefined
    let surveyBlobObjectId: string | undefined = undefined
    let surveyBlobIdStr = ''
    if (encryptedBlob.length > SURVEY_SIZE_THRESHOLD_KB * 1024) {
      setStatus('uploading')
      try {
        const uploadRes = await uploadToDecentralizedStorage(encryptedBlob)
        if (uploadRes.provider !== 'walrus' || !uploadRes.blobObjectId) {
          throw new Error('Walrus upload did not return a blob object ID')
        }
        surveyBlobIdStr = uploadRes.blobId
        surveyBlobObjectId = uploadRes.blobObjectId
        surveyBlobId = new TextEncoder().encode(uploadRes.blobId)
      } catch (err) {
        console.error('[FundPage] Decentralized upload failed:', err)
        setErrorMsg(t.errUploadFailed)
        setStatus('error')
        return
      }
    }

    setStatus('tx-signing')

    const buildTx = () => {
      return buildCreateSurveyPtb({
        packageId: PACKAGE_ID,
        poolId: POOL_ID,
        srTreasuryId: SR_TREASURY_ID,
        ssrTreasuryId: SSR_TREASURY_ID,
        registryId: SURVEY_REGISTRY_ID,
        adminTreasury: ADMIN_TREASURY,
        perResponse: BigInt(params.perResponse),
        repeatReward: BigInt(params.repeatReward),
        repeatMaxTimes: params.repeatMaxTimes,
        maxResponses: params.maxResponses,
        deadlineMs: BigInt(params.deadlineMs),
        encryptedContent: surveyBlobId ? new Uint8Array(0) : encryptedBlob,
        suiToSpend,
        contentHash,
        schemaHash,
        creatorPubKey: creatorPubKeyForChain,
        questions: fullSurvey.data.questions,
        allowedSources: fullSurvey.data.allowedSources,
        offsetIn: cost.offsetIn,
        creatorSsrCoins: ssrCoins,
        sponsorAddress: gasHealth?.sponsorAddress,
        gasCompensationAmount,
        surveyBlobId,
        surveyBlobObjectId,
        storageCompensationAmount: storageCompensationAmountMIST,
        requiredStorageFund,
        ticketFee: ticketFeeMist,
        allowedNftType: params.allowedNftType || undefined,
      })
    }

    // Dry-run pre-flight (best-effort)：抓到合約 abort 就攔在錢包簽名前；
    // 但 build / RPC 自己出錯時降級放行，讓後續 signAndExecute 的 onError 處理。
    try {
      const dryRunTx = buildTx()
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        ; (dryRunTx as any).setSender(account.address)
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const dryRunBytes = await (dryRunTx as any).build({ client: suiClient })
      const dryRunResult = await suiClient.dryRunTransactionBlock({
        transactionBlock: dryRunBytes,
      })
      if (dryRunResult.effects.status.status === 'failure') {
        const rawErr = dryRunResult.effects.status.error ?? t.unknownError
        const friendly = translateMoveAbort(rawErr)
        setErrorMsg(friendly ?? t.errDryRunFailed(rawErr))
        setStatus('error')
        return
      }
    } catch (err) {
      console.warn('[FundPage] dry-run pre-flight skipped:', err)
    }

    setStatus('submitting')
    const actualTx = buildTx()
    signAndExecute(
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      {
        transaction: actualTx as any,
      },
      {
        onSuccess: async (result) => {
          console.log('E2E Debug: signAndExecute onSuccess result:', JSON.stringify(result))
          try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            let txResult = (window as any).mockLastExecutedTransactionResult
            if (!txResult) {
              try {
                await suiClient.waitForTransaction({
                  digest: result.digest,
                  timeout: 30_000,
                  pollInterval: 1_000,
                })
              } catch (e) {
                console.warn(
                  '[FundPage] waitForTransaction timed out, falling back to getTransactionBlock',
                  e
                )
              }
              txResult = await suiClient.getTransactionBlock({
                digest: result.digest,
                options: {
                  showObjectChanges: true,
                  showEffects: true,
                  showEvents: true,
                },
              })
            }

            if (!txResult) {
              throw new Error(t.errCannotFetchTx)
            }

            if (
              txResult.effects &&
              txResult.effects.status &&
              txResult.effects.status.status === 'failure'
            ) {
              const rawErr = txResult.effects.status.error || t.errUnknownMoveError
              const friendly = translateMoveAbort(rawErr)
              throw new Error(friendly ?? t.errTxOnchainFailed(rawErr))
            }

            let vaultId = null
            let surveyId = null

            // 1. Try to extract from on-chain events (primary)
            if (txResult.events && txResult.events.length > 0) {
              const hit = txResult.events.find(
                (e: any) =>
                  e.type.endsWith('::survey_registry::SurveyRegistered') ||
                  e.type.includes('::survey_registry::SurveyRegistered')
              )
              if (hit && hit.parsedJson) {
                vaultId = (hit.parsedJson as any).vault_id
                surveyId = (hit.parsedJson as any).survey_id
                console.log(
                  '[FundPage] Successfully extracted vaultId and surveyId from events:',
                  vaultId,
                  surveyId
                )
              }
            }

            // 2. Fallback to objectChanges (secondary)
            if (!vaultId && txResult.objectChanges) {
              const changes = txResult.objectChanges
              console.log('E2E Debug: fetched changes fallback:', JSON.stringify(changes))
              vaultId = extractVaultIdFromEffects(changes)
              surveyId = extractSurveyIdFromEffects(changes)
            }

            if (!vaultId) {
              setErrorMsg(t.errCannotExtractVaultId)
              setStatus('error')
              return
            }

            if (surveyId) {
              window.localStorage.setItem(
                `${SURVEY_KEY_PREFIX}${surveyId}`,
                JSON.stringify({
                  vaultId,
                  contentKeyB64: contentKey.length > 0 ? bytesToBase64url(contentKey) : '',
                  createdAt: Date.now(),
                })
              )
              if (surveyBlobIdStr) {
                try {
                  const bffUrl = import.meta.env.VITE_BFF_URL || 'http://localhost:3100'
                  await fetch(`${bffUrl}/api/cache/survey`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ surveyId, blobId: surveyBlobIdStr })
                  })
                } catch (e) {
                  console.warn('Failed to notify BFF to cache survey:', e)
                }
              }
            }
            window.localStorage.removeItem(`${DRAFT_KEY_PREFIX}${draftId}`)

            const fragment = contentKey.length > 0 ? bytesToBase64url(contentKey) : ''
            setStatus('success')
            navigate(`/dashboard/${vaultId}${fragment ? `#${fragment}` : ''}`)
          } catch (err: any) {
            console.error('E2E Debug: onSuccess query error:', err)
            setErrorMsg(err.message || t.errQueryTxFailed)
            setStatus('error')
          }
        },
        onError: (err) => {
          console.error('E2E Debug: handleFund signAndExecute onError:', err)
          const friendly = translateMoveAbort(err.message)
          setErrorMsg(friendly ?? err.message)
          setStatus('error')
        },
      }
    )
  }

  const sui = (mist: bigint) => formatSui(mist)
  const ssr = (base: bigint) => formatSsr(base)

  return (
    <main className="min-h-screen p-4 sm:p-8 max-w-4xl mx-auto">
      <div className="bg-white dark:bg-neutral-900 rounded-3xl border border-slate-100 dark:border-neutral-800/80 shadow-xl overflow-hidden p-6 sm:p-8 space-y-6 animate-fadeIn transition-colors">
        {/* 頂部標題 */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 border-b pb-4 border-slate-100 dark:border-neutral-800">
          <div className="space-y-1">
            <h1 className="text-h1 flex items-center gap-2">
              {t.title}
            </h1>
            <p className="text-muted text-base">
              {t.desc}
            </p>
          </div>
        </div>

        {/* 1. 仿真填答者視角預覽 */}
        {fullSurvey && fullSurvey.questions && (
          <section className="border border-slate-100 dark:border-neutral-800 rounded-2xl p-5 bg-slate-50/50 dark:bg-neutral-900/20 shadow-sm space-y-4 animate-fadeIn">
            <div className="flex items-center justify-between border-b border-slate-200/60 dark:border-neutral-800 pb-2.5">
              <h2 className="text-h3 flex items-center gap-1.5">
                {t.previewTitle}
              </h2>
              <span className="text-sm font-normal px-2 py-0.5 bg-blue-50 dark:bg-blue-900/30 border border-blue-100 dark:border-blue-900/30 text-blue-700 dark:text-blue-400 rounded-full">
                {t.readOnly}
              </span>
            </div>

            <div className="space-y-5 max-h-[400px] overflow-y-auto pr-1">
              <div className="space-y-3 bg-white dark:bg-neutral-900 p-5 rounded-2xl border border-slate-100 dark:border-neutral-800/80 shadow-sm">
                <h3 className="text-h2 text-slate-800 dark:text-white">{fullSurvey.title}</h3>
                {fullSurvey.description && (
                  <div
                    className="prose max-w-none text-sm text-slate-600 dark:text-neutral-400 leading-relaxed border-t border-slate-100 dark:border-neutral-800/80 pt-3 mt-1 font-normal"
                    dangerouslySetInnerHTML={{ __html: renderMarkdown(fullSurvey.description) }}
                  />
                )}
              </div>

              {fullSurvey.questions.map((q: any, i: number) => (
                <div
                  key={q.id}
                  className="bg-white dark:bg-neutral-900 border border-slate-100 dark:border-neutral-800/80 rounded-2xl p-5 space-y-4 shadow-sm hover:bg-slate-50/30 dark:hover:bg-neutral-800/30 transition-colors"
                >
                  <div className="flex items-center justify-between border-b pb-2 border-slate-200/60 dark:border-neutral-800/80">
                    <div className="flex items-center gap-3">
                      <span className={`text-sm font-normal transition-colors ${q.required ? 'text-rose-800 dark:text-rose-400' : 'text-slate-700 dark:text-neutral-300'}`}>
                        {t.questionNum(i + 1)}
                      </span>
                      <span className={q.required ? 'chip-required' : 'chip-optional'}>
                        {q.required ? t.required : t.optional}
                      </span>
                    </div>
                    <span className="chip-optional shrink-0">
                      {typeLabel(q.type as QuestionType)}
                    </span>
                  </div>

                  <p className="text-base font-normal text-slate-800 dark:text-white">{q.prompt}</p>

                  {/* 題型渲染 */}
                  {q.type === 'single_choice' && q.options_json && (
                    <div className="space-y-2 pt-1">
                      {q.options_json.map((opt: string, oi: number) => (
                        <label
                          key={oi}
                          className="flex items-center gap-2.5 text-sm text-slate-600 dark:text-neutral-300 font-normal cursor-not-allowed bg-slate-50/50 dark:bg-neutral-950/20 border border-slate-100 dark:border-neutral-800 hover:bg-slate-50 dark:hover:bg-neutral-950/30 rounded-xl px-3.5 py-2 transition-colors w-full"
                        >
                          <input
                            type="radio"
                            name={`preview-single-${q.id}`}
                            disabled
                            className="radio-dark"
                          />
                          <span>{opt}</span>
                        </label>
                      ))}
                    </div>
                  )}

                  {q.type === 'multi_choice' && q.options_json && (
                    <div className="space-y-2 pt-1">
                      {q.options_json.map((opt: string, oi: number) => (
                        <label
                          key={oi}
                          className="flex items-center gap-2.5 text-sm text-slate-600 dark:text-neutral-300 font-normal cursor-not-allowed bg-slate-50/50 dark:bg-neutral-950/20 border border-slate-100 dark:border-neutral-800 hover:bg-slate-50 dark:hover:bg-neutral-950/30 rounded-xl px-3.5 py-2 transition-colors w-full"
                        >
                          <input
                            type="checkbox"
                            disabled
                            className="checkbox-dark checked:bg-blue-600 checked:border-blue-600"
                          />
                          <span>{opt}</span>
                        </label>
                      ))}
                    </div>
                  )}

                  {q.type === 'text' && (
                    <div className="space-y-1.5">
                      <textarea
                        disabled
                        rows={2}
                        className="form-input bg-slate-50/50 dark:bg-neutral-950/20 cursor-not-allowed font-mono"
                        placeholder={t.textPlaceholder}
                      />
                      {q.maxLen !== undefined && (
                        <div className="text-xs font-semibold text-slate-400 dark:text-neutral-500 px-1 select-none text-right">
                          {t.charLimit(q.maxLen)}
                        </div>
                      )}
                    </div>
                  )}

                  {q.type === 'scale' && (
                    <div className="flex flex-wrap gap-3 pt-1">
                      {[1, 2, 3, 4, 5].map((val) => (
                        <label
                          key={val}
                          className="flex flex-col items-center justify-center gap-1.5 cursor-not-allowed bg-slate-50/50 dark:bg-neutral-950/20 border border-slate-100 dark:border-neutral-800 hover:bg-slate-50 dark:hover:bg-neutral-950/30 rounded-xl p-3 w-12 h-14 transition-colors"
                        >
                          <span className="text-xs font-normal text-slate-400 dark:text-neutral-500">{val}</span>
                          <input
                            type="radio"
                            name={`preview-scale-${q.id}`}
                            disabled
                            className="radio-dark"
                          />
                        </label>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </section>
        )}

        {/* 2. 問卷規則參數資訊條 */}
        <div className="flex flex-wrap items-center gap-x-6 gap-y-2 text-sm text-slate-600 dark:text-neutral-400 bg-slate-50/60 dark:bg-neutral-950/20 rounded-2xl p-4 border border-slate-100 dark:border-neutral-800/80 transition-colors">
          <div className="flex items-center gap-1.5">
            <span className="font-medium text-slate-500 dark:text-neutral-500">{t.perResponseLabel}</span>
            <span className="font-semibold text-slate-800 dark:text-neutral-200">{params.perResponse} SSR</span>
          </div>
          <div className="h-4 w-px bg-slate-200 dark:bg-neutral-800 hidden sm:block" />
          <div className="flex items-center gap-1.5">
            <span className="font-medium text-slate-500 dark:text-neutral-500">{t.maxResponsesLabel}</span>
            <span className="font-semibold text-slate-800 dark:text-neutral-200">{params.maxResponses} {t.unitCopies}</span>
          </div>
          {params.repeatReward > 0 && (
            <>
              <div className="h-4 w-px bg-slate-200 dark:bg-neutral-800 hidden sm:block" />
              <div className="flex items-center gap-1.5">
                <span className="font-medium text-slate-500 dark:text-neutral-500">{t.repeatRewardLabel}</span>
                <span className="font-semibold text-slate-800 dark:text-neutral-200">{params.repeatReward} SSR ({params.repeatMaxTimes} {t.timesPerPerson})</span>
              </div>
            </>
          )}
        </div>

        {/* 3. 費用估計與資金明細 */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
          {/* 左：問卷規則與預算 */}
          <section className="bg-slate-50/50 dark:bg-neutral-950/30 border border-slate-100 dark:border-neutral-800 rounded-2xl p-5 space-y-4 shadow-sm transition-colors text-sm">
            <h2 className="text-h3 border-b pb-2 border-slate-100 dark:border-neutral-800">
              {t.rewardSettings}
            </h2>
            <div className="space-y-2.5 pt-1">
              <div className="flex justify-between text-base">
                <span className="text-slate-600 dark:text-neutral-400 font-normal">{t.totalRewardLabel}</span>
                <span className="font-semibold text-slate-800 dark:text-neutral-200 tabular-nums">
                  {totalSsr} <span className="text-sm font-normal text-slate-500 dark:text-neutral-400">SSR</span>
                </span>
              </div>
              <div className="flex justify-between text-base">
                <span className="text-slate-600 dark:text-neutral-400 font-normal">
                  {t.platformFeeLabel}
                  {cost && (
                    <span className="text-xs text-slate-400 dark:text-neutral-500 ml-1">
                      ({Number(cost.effectiveFeeBps) / 100}%)
                    </span>
                  )}
                </span>
                <span
                  className="font-semibold text-slate-800 dark:text-white tabular-nums"
                  aria-label="platform-fee"
                  title={cost ? `${formatFullPrecision(cost.feeBase)} SSR` : undefined}
                >
                  {cost ? (
                    <>
                      {ssr(cost.feeBase)} <span className="text-sm font-normal text-slate-500 dark:text-neutral-400">SSR</span>
                    </>
                  ) : (
                    t.calculating
                  )}
                </span>
              </div>

              <div className="flex justify-between border-t border-slate-200 dark:border-neutral-800 pt-2.5 font-medium text-base">
                <span className="text-slate-700 dark:text-neutral-200">{t.totalSsrRequiredLabel}</span>
                <span className="font-semibold text-slate-800 dark:text-neutral-200 tabular-nums" title={cost ? `${formatFullPrecision(cost.grossSsrBase)} SSR` : undefined}>
                  {cost ? `${ssr(cost.grossSsrBase)} SSR` : t.calculating}
                </span>
              </div>
              <div className="flex justify-between text-base">
                <span className="text-slate-600 dark:text-neutral-400 font-normal">{t.ssrOffsetLabel}</span>
                <span className="font-semibold text-slate-700 dark:text-neutral-300 tabular-nums" title={cost ? `${formatFullPrecision(cost.offsetIn)} SSR` : undefined}>
                  {cost ? `-${ssr(cost.offsetIn)} SSR` : t.calculating}
                </span>
              </div>
              <div className="flex justify-between border-t border-slate-200 dark:border-neutral-800 pt-2.5 font-medium text-base">
                <span className="text-slate-700 dark:text-neutral-200">{t.newMintSsrLabel}</span>
                <span className="font-bold text-blue-700 dark:text-blue-400 tabular-nums" title={cost ? `${formatFullPrecision(cost.minted)} SSR` : undefined}>
                  {cost ? `${ssr(cost.minted)} SSR` : t.calculating}
                </span>
              </div>
            </div>
          </section>

          {/* 右：支付與資金流向 */}
          <section className="bg-white dark:bg-neutral-950/20 border border-slate-100 dark:border-neutral-800 rounded-2xl p-5 space-y-4 shadow-sm text-sm transition-colors flex flex-col justify-between">
            <div className="space-y-4">
              <h2 className="text-h3 border-b pb-2 border-slate-100 dark:border-neutral-800">
                {t.fundFlow}
              </h2>

              {/* Part 2: SUI Payments */}
              <div className="space-y-2">
                <div className="flex justify-between text-slate-600 dark:text-neutral-400">
                  <div className="flex items-center gap-1">
                    <div className="flex flex-col">
                      <span>{t.mintSuiCostLabel}</span>
                      <span className="text-xs text-slate-400 dark:text-neutral-500">
                        ({t.withSlippage})
                      </span>
                    </div>
                    <div className="group relative inline-block self-start mt-1">
                      <Info size={13} className="text-slate-400 hover:text-slate-600 dark:text-neutral-500 dark:hover:text-neutral-300 cursor-pointer" />
                      <div className="absolute left-1/2 -translate-x-1/2 bottom-full mb-2 w-72 p-3 bg-slate-900 text-white dark:bg-neutral-800 dark:text-neutral-100 text-xs rounded-xl shadow-lg opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-50 pointer-events-none leading-relaxed font-normal">
                        <p className="font-semibold">{t.exchangeRateLabel} 1 SUI ≈ {currentRate.toFixed(2)} SSR</p>
                        <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-slate-900 dark:border-t-neutral-800" />
                      </div>
                    </div>
                  </div>
                  <span className="font-semibold text-slate-700 dark:text-neutral-300" title={suiToSpend !== null ? `${formatFullPrecision(suiToSpend)} SUI` : undefined}>
                    {suiToSpend !== null ? `${sui(suiToSpend)} SUI` : t.calculating}
                  </span>
                </div>

                {requiredGas > 0n && (
                  <div className="flex justify-between items-center text-slate-600 dark:text-neutral-400">
                    <div className="flex items-center gap-1">
                      <span>{t.prefundTotalLabel}</span>
                      <div className="group relative inline-block">
                        <Info size={13} className="text-slate-400 hover:text-slate-600 dark:text-neutral-500 dark:hover:text-neutral-300 cursor-pointer" />
                        <div className="absolute left-1/2 -translate-x-1/2 bottom-full mb-2 w-72 p-3 bg-slate-900 text-white dark:bg-neutral-800 dark:text-neutral-100 text-xs rounded-xl shadow-lg opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-50 pointer-events-none leading-relaxed font-normal">
                          {t.prefundTooltip}
                          <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-slate-900 dark:border-t-neutral-800" />
                        </div>
                      </div>
                    </div>
                    <span className="font-semibold text-slate-700 dark:text-neutral-300" title={`${formatFullPrecision(requiredGas)} SUI`}>
                      {sui(requiredGas)} SUI
                    </span>
                  </div>
                )}
              </div>
            </div>

            {/* Part 3: Total Card */}
            {(() => {
              const fullyOffset = cost != null && totalSuiToSpend != null && totalSuiToSpend === 0n
              const cardClass = fullyOffset
                ? 'bg-gradient-to-r from-emerald-700 to-emerald-600 dark:from-teal-950 dark:to-teal-900 text-white rounded-xl p-3.5 mt-4 flex justify-between items-center shadow-md'
                : 'bg-gradient-to-r from-blue-900 to-indigo-800 text-white rounded-xl p-3.5 mt-4 flex justify-between items-center shadow-md'
              const title = t.estimatedTotal
              const subtitle = fullyOffset ? t.coveredBySsrSubtitle : t.withSlippage
              let mainValue: string
              let fullValue: string | undefined = undefined
              if (totalSuiToSpend == null) {
                mainValue = t.calculating
              } else if (fullyOffset) {
                mainValue = `${ssr(cost!.offsetIn)} SSR`
                fullValue = `${formatFullPrecision(cost!.offsetIn)} SSR`
              } else {
                mainValue = `${sui(totalSuiToSpend)} SUI`
                fullValue = `${formatFullPrecision(totalSuiToSpend)} SUI`
              }
              return (
                <div className={cardClass}>
                  <div className="flex flex-col min-w-0">
                    <span className="text-base font-normal opacity-90">{title}</span>
                    <span className="text-sm opacity-70">{subtitle}</span>
                  </div>
                  <span
                    className="text-xl font-normal font-mono whitespace-nowrap text-right shrink-0 ml-3"
                    aria-label="estimated-sui-cost"
                    title={fullValue}
                  >
                    {mainValue}
                  </span>
                </div>
              )
            })()}
          </section>
        </div>

        {/* 3. 加密安全開關 */}
        <section className="bg-slate-50/50 dark:bg-neutral-950/30 border border-slate-100 dark:border-neutral-800 rounded-2xl p-5 animate-fadeIn transition-colors flex flex-col sm:flex-row gap-6">
          <label className="inline-flex items-start gap-3.5 cursor-pointer select-none flex-1">
            <input
              id="encrypt-survey"
              type="checkbox"
              checked={encrypt}
              onChange={(e) => setEncrypt(e.target.checked)}
              className="checkbox-dark checked:bg-blue-600 checked:border-blue-600 mt-0.5 shrink-0"
            />
            <div className="flex flex-col gap-0.5">
              <span className="text-base text-slate-800 dark:text-neutral-200 font-semibold">
                {t.encryptSurvey}
              </span>
              <span className="text-sm text-slate-400 dark:text-neutral-400 font-normal leading-normal">
                {t.encryptSurveyDesc}
              </span>

            </div>
          </label>

          <div className="hidden sm:block border-l border-slate-200 dark:border-neutral-800/80 self-stretch my-1" />
          <div className="sm:hidden border-t border-slate-200 dark:border-neutral-800/80 my-1" />

          <label className="inline-flex items-start gap-3.5 cursor-pointer select-none flex-1">
            <input
              id="encrypt-answers"
              type="checkbox"
              checked={encrypt ? true : encryptAnswers}
              disabled={encrypt}
              onChange={(e) => setEncryptAnswers(e.target.checked)}
              className="checkbox-dark checked:bg-blue-600 checked:border-blue-600 mt-0.5 shrink-0 disabled:opacity-50 disabled:cursor-not-allowed"
            />
            <div className="flex flex-col gap-0.5">
              <span className="text-base text-slate-800 dark:text-neutral-200 font-semibold">
                {t.encryptAnswers}
              </span>
              <span className="text-sm text-slate-400 dark:text-neutral-400 font-normal leading-normal">
                {t.encryptAnswersDesc}
              </span>
            </div>
          </label>
        </section>

        {/* 4. 發布操作 */}
        <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-neutral-800 animate-fadeIn">
          {errorMsg && (
            <div
              role="alert"
              className="alert-error break-all flex items-center gap-1.5"
            >
              <AlertTriangle size={14} className="shrink-0 text-rose-500" />
              <span>{errorMsg}</span>
            </div>
          )}

          {account ? (
            <div className="flex flex-col sm:flex-row gap-3">
              <button
                type="button"
                onClick={() => navigate(`/create/${draftId}`)}
                className="btn-outline w-full sm:w-1/3 flex items-center justify-center gap-2 py-3"
              >
                {t.btnBack}
              </button>
              <div className="w-full sm:w-2/3 flex flex-col gap-2.5">
                {(() => {
                  const isKeyRequired = encrypt || (encrypt ? true : encryptAnswers);
                  return (
                    <>
                      <button
                        type="button"
                        onClick={handleSetupKey}
                        disabled={!isKeyRequired || !!keypair || status === 'key-signing' || status === 'uploading'}
                        className={
                          !isKeyRequired
                            ? 'bg-slate-100 dark:bg-neutral-800 text-slate-400 dark:text-neutral-500 font-normal px-5 rounded-xl border border-slate-200/60 dark:border-neutral-700/60 w-full flex items-center justify-center gap-2 py-3 cursor-not-allowed'
                            : keypair
                              ? 'bg-emerald-700/40 text-white dark:bg-emerald-800/40 dark:text-emerald-200 font-normal px-5 rounded-xl shadow-sm w-full flex items-center justify-center gap-2 py-3'
                              : 'btn-primary w-full flex items-center justify-center gap-2 py-3'
                        }
                      >
                        {!isKeyRequired
                          ? t.keyNotNeededBtn
                          : status === 'key-signing'
                            ? t.keySigningBtn
                            : keypair
                              ? t.keyReadyBtn
                              : t.setupKeyBtn}
                      </button>
                      <button
                        type="button"
                        onClick={handleFund}
                        disabled={
                          (isKeyRequired && !keypair) ||
                          suiToSpend == null ||
                          status === 'tx-signing' ||
                          status === 'submitting' ||
                          status === 'uploading' ||
                          status === 'success'
                        }
                        className="btn-primary w-full flex items-center justify-center gap-1.5 py-3"
                      >
                        {status === 'uploading'
                          ? t.uploadingShort
                          : status === 'tx-signing' || status === 'submitting'
                            ? t.submittingBtn
                            : status === 'success'
                              ? t.successBtn
                              : t.publishBtn}
                      </button>
                    </>
                  );
                })()}
              </div>
            </div>
          ) : (
            <div className="text-center py-5 warning-box rounded-2xl shadow-inner flex flex-col items-center gap-1.5 justify-center">
              <AlertTriangle size={16} className="text-amber-600 dark:text-amber-500" />
              <p className="text-sm">
                {t.connectWalletPrompt}
              </p>
            </div>
          )}
        </div>
      </div>

      {/* Glassmorphism progress overlay */}
      {status === 'uploading' && (
        <div className="glass-overlay">
          <div className="glass-card space-y-4">
            <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto"></div>
            <h3 className="text-lg font-medium text-slate-800 dark:text-neutral-200 animate-pulse">
              {t.uploadingSurvey}
            </h3>
            <p className="text-sm text-slate-500 dark:text-neutral-400">
              {t.pleaseWait}
            </p>
          </div>
        </div>
      )}
    </main>
  )
}

import { useEffect, useMemo, useState } from 'react'
import { Link } from 'react-router-dom'
import { FileText, ClipboardList, Gift, Globe, ChevronLeft, ChevronRight } from 'lucide-react'
import { useCurrentAccount, useSuiClient } from '@mysten/dapp-kit'
import { parseFullSurveyMarkdown } from '../lib/frontmatter'
import { useLanguage } from '../context/LanguageContext'
import { useT } from '../i18n'

const stepsIcons = [FileText, ClipboardList, Gift]
const PACKAGE_ID = import.meta.env.VITE_PACKAGE_ID ?? ''

interface PublicSurveyItem {
  surveyId: string
  vaultId: string
  title: string
  description: string
  perResponse: number
  maxResponses: number
  claimedCount: number
  deadlineMs: number
  language: string
  allowedSources: number[]
  allowedNftType: string | null
  registeredAtMs: number
}

function normalizeSuiId(id: string): string {
  if (!id) return ''
  let cleaned = id.toLowerCase().trim()
  if (cleaned.startsWith('0x')) {
    cleaned = cleaned.slice(2)
  }
  return cleaned.padStart(64, '0')
}

// 簡單高效的 Unicode 自動語系偵測
function detectLang(text: string): string {
  let zhCount = 0
  let jaCount = 0
  let koCount = 0
  let esCount = 0

  for (let i = 0; i < text.length; i++) {
    const charCode = text.charCodeAt(i)
    
    // 諺文 (韓文)
    if (
      (charCode >= 0xac00 && charCode <= 0xd7af) ||
      (charCode >= 0x1100 && charCode <= 0x11ff) ||
      (charCode >= 0x3130 && charCode <= 0x318f)
    ) {
      koCount++
    }
    // 平假名/片假名 (日文)
    else if (
      (charCode >= 0x3040 && charCode <= 0x309f) ||
      (charCode >= 0x30a0 && charCode <= 0x30ff)
    ) {
      jaCount++
    }
    // CJK 統一漢字 (中日韓，無假名或諺文時傾向中文)
    else if (charCode >= 0x4e00 && charCode <= 0x9fff) {
      zhCount++
    }
    // 西班牙文特有字元 (á, é, í, ó, ú, ü, ñ, ¿, ¡)
    else if (/[áéíóúüñ¿¡ÁÉÍÓÚÜÑ]/.test(text[i])) {
      esCount++
    }
  }

  if (koCount > 0 && koCount >= jaCount && koCount >= zhCount) {
    return 'ko'
  }
  if (jaCount > 0) {
    return 'ja'
  }
  if (zhCount > 0) {
    return 'zh'
  }
  if (esCount > 0) {
    return 'es'
  }
  return 'en'
}

export default function LandingPage() {
  const t = useT('landing')
  const tExplore = useT('explore')
  const account = useCurrentAccount()
  const suiClient = useSuiClient()
  const { lang: uiLang } = useLanguage()

  const [loading, setLoading] = useState(true)
  const [surveys, setSurveys] = useState<PublicSurveyItem[]>([])
  const [claimedVaults, setClaimedVaults] = useState<Set<string>>(new Set())

  const [currentPage, setCurrentPage] = useState(0)
  const [cardsPerPage, setCardsPerPage] = useState(3)

  // 監聽視窗寬度調整每頁卡片數量
  useEffect(() => {
    function handleResize() {
      if (window.innerWidth >= 1024) {
        setCardsPerPage(3)
      } else if (window.innerWidth >= 640) {
        setCardsPerPage(2)
      } else {
        setCardsPerPage(1)
      }
    }
    handleResize()
    window.addEventListener('resize', handleResize)
    return () => window.removeEventListener('resize', handleResize)
  }, [])

  // 1. 載入並解析公開問卷
  useEffect(() => {
    if (!PACKAGE_ID) return
    let cancelled = false
    setLoading(true)

    async function loadExploreData() {
      try {
        const timeLimit = Date.now() - 7 * 86400000
        let cursor: any = null
        let registeredEvents: any[] = []
        let hasNext = true

        // 降序查詢註冊事件，7 天時間窗口截斷
        while (hasNext && !cancelled) {
          const res = await suiClient.queryEvents({
            query: { MoveEventType: `${PACKAGE_ID}::survey_registry::SurveyRegistered` },
            cursor,
            limit: 50,
            order: 'descending',
          })
          let hitDeadline = false
          for (const ev of res.data) {
            const j: any = ev.parsedJson
            if (!j) continue
            const regTime = Number(j.registered_at_ms || 0)
            if (regTime < timeLimit) {
              hitDeadline = true
              break
            }
            registeredEvents.push(j)
          }
          if (hitDeadline || !res.hasNextPage) {
            break
          }
          cursor = res.nextCursor
        }

        if (cancelled || registeredEvents.length === 0) {
          setSurveys([])
          setLoading(false)
          return
        }

        // 批次加載 Survey 與 Vault 物件
        const surveyIds = registeredEvents.map((e) => e.survey_id)
        const vaultIds = registeredEvents.map((e) => e.vault_id)

        const chunk = <T,>(arr: T[], size: number): T[][] =>
          Array.from({ length: Math.ceil(arr.length / size) }, (v, i) =>
            arr.slice(i * size, i * size + size)
          )

        const surveyChunks = chunk(surveyIds, 50)
        const vaultChunks = chunk(vaultIds, 50)

        let surveyObjects: any[] = []
        let vaultObjects: any[] = []

        for (const c of surveyChunks) {
          if (cancelled) return
          const res = await suiClient.multiGetObjects({ ids: c, options: { showContent: true } })
          surveyObjects = [...surveyObjects, ...res]
        }
        for (const c of vaultChunks) {
          if (cancelled) return
          const res = await suiClient.multiGetObjects({ ids: c, options: { showContent: true } })
          vaultObjects = [...vaultObjects, ...res]
        }

        const items: PublicSurveyItem[] = []

        // 解析與過濾
        for (let i = 0; i < registeredEvents.length; i++) {
          const event = registeredEvents[i]
          const sObj = surveyObjects[i]
          const vObj = vaultObjects[i]

          if (!sObj?.data || sObj.error || !vObj?.data || vObj.error) continue

          const sFields = sObj.data.content?.fields
          const vFields = vObj.data.content?.fields
          if (!sFields || !vFields) continue

          // 狀態過濾 (已結束/已刪除)
          if (Number(vFields.status) !== 0) continue

          // 額滿過濾
          const claimedCount = Number(vFields.claimed_count || 0)
          const maxResponses = Number(vFields.max_responses || 0)
          if (claimedCount >= maxResponses) continue

          // 儲存位置過濾：跳過 Walrus 託管問卷，保證極速載入
          const getOptionVec = (opt: any): Uint8Array | null => {
            if (!opt) return null
            if (Array.isArray(opt)) {
              if (opt.length === 0) return null
              const first = opt[0]
              if (Array.isArray(first)) return new Uint8Array(first.map(Number))
              if (typeof first === 'string') {
                return new Uint8Array(first.match(/.{1,2}/g)?.map((byte: string) => parseInt(byte, 16)) || [])
              }
              return new Uint8Array(opt.map(Number))
            }
            const vec = opt.fields?.vec || opt.vec
            if (!Array.isArray(vec) || vec.length === 0) return null
            const first = vec[0]
            if (Array.isArray(first)) return new Uint8Array(first.map(Number))
            if (typeof first === 'string') {
              return new Uint8Array(first.match(/.{1,2}/g)?.map((byte: string) => parseInt(byte, 16)) || [])
            }
            return new Uint8Array(vec.map(Number))
          }

          const surveyBlobIdBytes = getOptionVec(sFields.survey_blob_id)
          if (surveyBlobIdBytes) continue // Walrus 忽略

          // 格式校驗與明文判定 (首 Byte 須為 0x00)
          const rawContent = getOptionVec(sFields.encrypted_content)
          if (!rawContent || rawContent[0] !== 0x00) continue

          // 解析明文 markdown 與 frontmatter
          try {
            const md = new TextDecoder().decode(rawContent.slice(1))
            const parsed = parseFullSurveyMarkdown(md)
            if (!parsed.ok) continue

            const fm = parsed.data
            // 期限過濾
            if (fm.deadlineMs <= Date.now()) continue

            // 語系優先序
            let language = fm.language ? fm.language.toLowerCase() : ''
            if (!language) {
              // 無設定，由內容自動偵測
              const contentToDetect = `${parsed.data.title} ${parsed.data.description}`
              language = detectLang(contentToDetect)
            }

            const allowedNftTypeBytes = getOptionVec(vFields.allowed_nft_type)
            const allowedNftType = allowedNftTypeBytes ? new TextDecoder().decode(allowedNftTypeBytes) : null

            items.push({
              surveyId: event.survey_id,
              vaultId: event.vault_id,
              title: fm.title,
              description: fm.description,
              perResponse: fm.perResponse,
              maxResponses: fm.maxResponses,
              claimedCount,
              deadlineMs: fm.deadlineMs,
              language,
              allowedSources: fm.allowedSources,
              allowedNftType,
              registeredAtMs: Number(event.registered_at_ms || 0),
            })
          } catch (e) {
            console.warn('Failed to parse survey markdown:', event.survey_id, e)
          }
        }

        if (!cancelled) {
          setSurveys(items)
          setLoading(false)
        }
      } catch (err) {
        console.error('Failed to load explore surveys:', err)
        if (!cancelled) {
          setLoading(false)
        }
      }
    }

    void loadExploreData()
    return () => {
      cancelled = true
    }
  }, [suiClient])

  // 2. 當錢包連接時，批次查詢使用者已填過哪些 Vault
  useEffect(() => {
    if (!account?.address || !PACKAGE_ID) {
      setClaimedVaults(new Set())
      return
    }

    let cancelled = false
    async function checkMyClaims() {
      try {
        const myAddrNorm = normalizeSuiId(account!.address)
        const claimedSet = new Set<string>()
        let evCursor: any = null
        let page = 0

        while (!cancelled) {
          const res = await suiClient.queryEvents({
            query: { MoveEventType: `${PACKAGE_ID}::survey_vault::SurveyClaimed` },
            cursor: evCursor,
            limit: 50,
          })
          for (const ev of res.data) {
            const j: any = ev.parsedJson
            if (!j) continue
            if (normalizeSuiId(j.respondent) === myAddrNorm) {
              claimedSet.add(normalizeSuiId(j.vault_id))
            }
          }
          if (!res.hasNextPage || page >= 5) break
          evCursor = res.nextCursor
          page++
        }

        if (!cancelled) {
          setClaimedVaults(claimedSet)
        }
      } catch (e) {
        console.warn('Failed to query user claimed history:', e)
      }
    }

    void checkMyClaims()
    return () => {
      cancelled = true
    }
  }, [account?.address, suiClient])

  // 3. 篩選邏輯
  const filteredSurveys = useMemo(() => {
    const targetLang = uiLang.toLowerCase()
    return surveys.filter((item) => {
      // 填答狀態過濾：已填過則在廣場中過濾隱藏
      if (claimedVaults.has(normalizeSuiId(item.vaultId))) {
        return false
      }
      return item.language === targetLang
    })
  }, [surveys, claimedVaults, uiLang])

  // 4. 限制最多顯示 5 頁的問卷
  const displayedSurveys = useMemo(() => {
    return filteredSurveys.slice(0, 5 * cardsPerPage)
  }, [filteredSurveys, cardsPerPage])

  // 5. 將問卷分頁
  const pages = useMemo(() => {
    const result = []
    for (let i = 0; i < displayedSurveys.length; i += cardsPerPage) {
      result.push(displayedSurveys.slice(i, i + cardsPerPage))
    }
    return result
  }, [displayedSurveys, cardsPerPage])

  // 6. 分頁邊界校正
  useEffect(() => {
    if (currentPage >= pages.length && pages.length > 0) {
      setCurrentPage(pages.length - 1)
    }
  }, [pages.length, currentPage])

  return (
    <div className="min-h-screen bg-white text-slate-800 dark:bg-neutral-950 dark:text-neutral-300 animate-fadeIn transition-colors">
      {/* Hero */}
      <section className="mx-auto max-w-5xl px-6 py-20 text-center">
        <h1 className="text-4xl sm:text-5xl font-normal leading-tight mb-6 text-slate-900 dark:text-white">
          {t.heroTitle}
        </h1>
        <p className="text-lg text-slate-500 dark:text-neutral-400 max-w-2xl mx-auto mb-10 font-normal">
          {t.heroDesc}
        </p>
        <div className="flex flex-col sm:flex-row gap-3 justify-center">
          <Link
            to="/docs"
            className="btn-secondary"
          >
            {t.btnDocs}
          </Link>
          <a
            href="/guide"
            target="_blank"
            rel="noopener noreferrer"
