import { SuiClient } from '@mysten/sui/client'
import { Ed25519Keypair } from '@mysten/sui/keypairs/ed25519'

async function main() {
  const rpcUrl = 'https://fullnode.devnet.sui.io:443'
  const packageId = '0xc65161f158c24f85ba513356962cee7a8e79ac1b78c4b8ecff98a7a315f48f7e'
  const client = new SuiClient({ url: rpcUrl })

  console.log(`Connecting to Sui Devnet at ${rpcUrl}...`)
  console.log(`Package ID: ${packageId}`)

  // Derive sponsor address
  const issuerPriv = '0101010101010101010101010101010101010101010101010101010101010101'
  const keypair = Ed25519Keypair.fromSecretKey(new Uint8Array(Buffer.from(issuerPriv, 'hex')).slice(0, 32))
  const sponsorAddress = keypair.getPublicKey().toSuiAddress()
  console.log(`BFF Sponsor/Issuer Address: ${sponsorAddress}`)

  // Query transaction blocks sent by sponsor address or interacting with the package
  console.log('Querying transactions for package...')
  const txs = await client.queryTransactionBlocks({
    filter: {
      InputObject: packageId,
    },
    options: {
      showInput: true,
      showEffects: true,
      showEvents: true,
    },
    limit: 100,
  })

  console.log(`Found ${txs.data.length} transactions. Analyzing...`)

  const results: Record<string, any[]> = {
    mint_pass: [],
    update_pass_credential: [],
    claim: [],
  }

  for (const tx of txs.data) {
    const status = tx.effects?.status?.status
    if (status !== 'success') continue

    // Find move calls in the transaction
    const transaction = tx.transaction?.data.transaction as any
    if (!transaction || transaction.kind !== 'ProgrammableTransaction') continue

    const commands = transaction.commands || transaction.transactions
    if (!commands || !Array.isArray(commands)) continue

    for (const cmd of commands) {
      const call = cmd.MoveCall || cmd.moveCall
      if (call) {
        if (call.package === packageId) {
          const func = call.function
          if (func === 'mint_pass' || func === 'update_pass_credential' || func === 'claim') {
            const gasUsed = tx.effects?.gasUsed
            if (!gasUsed) continue

            const computation = BigInt(gasUsed.computationCost)
            const storage = BigInt(gasUsed.storageCost)
            const rebate = BigInt(gasUsed.storageRebate)
            const netGas = computation + storage - rebate

            results[func].push({
              digest: tx.digest,
              computation: computation.toString(),
              storage: storage.toString(),
              rebate: rebate.toString(),
              netGas: netGas.toString(),
            })
          }
        }
      }
    }
  }

  console.log('\n--- Query Results ---')
  for (const [func, list] of Object.entries(results)) {
    console.log(`\nFunction: ${func} (found ${list.length} successful transactions)`)
    if (list.length === 0) {
      console.log('  No transaction found.')
      continue
    }

    // Take unique by digest
    const unique = Array.from(new Map(list.map(item => [item.digest, item])).values())
    unique.slice(0, 5).forEach((item, index) => {
      const netSui = Number(item.netGas) / 1e9
      console.log(`  [${index + 1}] Digest: ${item.digest}`)
      console.log(`      Net Gas cost: ${item.netGas} MIST (${netSui} SUI)`)
      console.log(`      computationCost: ${item.computation} MIST`)
      console.log(`      storageCost: ${item.storage} MIST`)
      console.log(`      storageRebate: ${item.rebate} MIST`)
    })
  }
}

main().catch(console.error)

