  const otpData = await otpRes.json() as { code?: string }
  const code = otpData.code
  if (!code) {
    throw new Error('No OTP code received in response. Is NODE_ENV=development set in .env?')
  }
  console.log(`[Test] Received OTP Code: ${code}`)

