  const ticket1 = await verifyRes1.json()
  console.log('[Test] Normal verification successful! Ticket:', ticket1)

  await sleep(500) // 等待 rate limit TTL (360ms) 過期

  // 4. 註銷該 Nullifier (走離線 Admin Sync 模擬)
  console.log(`[Test] Revoking nullifier ${nullifier} via Admin CLI...`)
  execSync(`npx tsx scripts/src/admin_rescue.ts --nullifier ${nullifier} --source 2 --offline-only --reason "E2E Revocation Test"`, { stdio: 'inherit' })

  // 5. 再次請求 OTP 取得新 code (因為剛才 verify 成功後原 code 被 invalidate 了)
  console.log('[Test] Requesting new OTP after revocation...')
  const otpRes2 = await fetch(`${BFF_URL}/auth/email/otp`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
