  console.log(`[Test] Verification response status: ${verifyRes2.status}`)
  const verifyBody2 = await verifyRes2.json()
  console.log('[Test] Verification response body:', verifyBody2)

  if (verifyRes2.status === 403 && verifyBody2.error === 'nullifier_revoked') {
    console.log('[SUCCESS] Successfully blocked revoked nullifier with 403 nullifier_revoked!')
  } else {
    throw new Error('E2E TEST FAILED: Revoked nullifier was NOT blocked correctly!')
  }

  await sleep(500) // 等待 rate limit TTL (360ms) 過期

  // 7. 解除註銷 (還原資料庫)
  console.log(`[Test] Restoring nullifier (unrevoking) ${nullifier}...`)
  execSync(`npx tsx scripts/src/admin_rescue.ts --unrevoke --nullifier ${nullifier} --source 2`, { stdio: 'inherit' })

  // 8. 第三次請求 OTP 取得新 code
  console.log('[Test] Requesting OTP after unrevoking...')
  const otpRes3 = await fetch(`${BFF_URL}/auth/email/otp`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ email: TEST_EMAIL })
  })
  const otpData3 = await otpRes3.json() as { code?: string }
  const code3 = otpData3.code
  console.log(`[Test] Final OTP Code: ${code3}`)

  // 9. 第三次驗證 (應該要恢復成功)
  console.log('[Test] Verifying with restored unrevoked nullifier (should succeed)...')
  const verifyRes3 = await fetch(`${BFF_URL}/auth/email/verify`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ email: TEST_EMAIL, code: code3, owner: TEST_OWNER })
  })

  if (!verifyRes3.ok) {
    throw new Error(`Final verification failed: ${verifyRes3.status} ${await verifyRes3.text()}`)
  }
  const ticket3 = await verifyRes3.json()
  console.log('[SUCCESS] Final verification succeeded! Ticket:', ticket3)
  console.log('[Test] ALL TESTS PASSED SUCCESSFULLY!')
}

